let ideSuggestions = []

function buildIdeSuggestions(val) {
  const lower = val.toLowerCase()
  const results = []

  // Always filter/show commands
  IDE_COMMANDS.forEach(cmd => {
    const pfx = cmd.prefix.toLowerCase().replace(' ','')
    const inp = lower.replace(' ','')
    if (!val || inp.length <= cmd.prefix.length && cmd.prefix.toLowerCase().startsWith(inp)) {
      results.push({ ...cmd, _type: 'cmd' })
    }
  })

  // Account suggestions when @ appears
  if (val.includes('@')) {
    const afterAt = val.split('@').pop().toLowerCase()
    allNodes.filter(n => n.type === 'account').forEach(a => {
      const lbl = (a.metadata?.label || a.content)
      const key = lbl.toLowerCase().replace(/\s+/g,'')
      if (!afterAt || key.includes(afterAt.replace(/\s+/g,''))) {
        results.push({ icon: a.metadata?.icon || '🏦', prefix: '@'+key, tpl: '@'+lbl, desc: 'Cuenta bancaria', color:'#94a3b8', cat:'Cuentas', _type:'account', _key: key })
      }
    })
    // Contact wallets too
    allNodes.filter(n => n.type==='contact' && (n.metadata?.cType==='bank'||n.metadata?.cType==='crypto')).forEach(c => {
      const lbl = (c.metadata?.name || c.content)
      const key = lbl.toLowerCase().replace(/\s+/g,'')
      if (!afterAt || key.includes(afterAt.replace(/\s+/g,''))) {
        results.push({ icon: c.metadata?.cType==='bank'?'🏦':'₿', prefix:'@'+key, tpl:'@'+lbl, desc: c.metadata?.bank_name||c.metadata?.network||'Contacto', color:'#00f0ff', cat:'Contactos/Cuentas', _type:'contact_acct', _key: key })
      }
    })
  }

  // Contact suggestions for member fields and general text
  if (val.length >= 2 && !val.match(/^[+\-#📅]/)) {
    allNodes.filter(n => n.type==='contact').forEach(c => {
      const name = (c.metadata?.name || c.content)
      if (name.toLowerCase().includes(lower)) {
        results.push({ icon: c.metadata?.cType==='bank'?'🏦':c.metadata?.cType==='crypto'?'₿':'👤', prefix: name, tpl: name, desc: c.metadata?.company||c.metadata?.bank_name||c.metadata?.network||'Contacto', color: c.metadata?.color||'#00f0ff', cat:'Contactos', _type:'contact', _id: c.id })
      }
    })
  }

  // Tag autocomplete: detect # mid-input (after at least one char before it)
  const hashMatch = val.match(/#(\w*)$/)
  const isCommandStart = /^#(tarea|persona|proyecto|idea)\s/i.test(val)
  if (hashMatch && !isCommandStart && val.indexOf('#') > 0) {
    const partial = hashMatch[1].toLowerCase()
    const tagFreq = {}
    allNodes.forEach(n => {
      ;(n.metadata?.tags || []).forEach(t => {
        const tag = t.replace(/^#/, '').toLowerCase().trim()
        if (tag) tagFreq[tag] = (tagFreq[tag] || 0) + 1
      })
    })
    Object.entries(tagFreq)
      .filter(([t]) => !partial || t.startsWith(partial))
      .sort((a, b) => b[1] - a[1])
      .slice(0, 6)
      .forEach(([tag, freq]) => {
        const completed = val.replace(/#\w*$/, '#' + tag) + ' '
        results.push({
          icon: '🏷️',
          prefix: '#' + tag,
          tpl: completed,
          desc: `${freq} nodo${freq > 1 ? 's' : ''}`,
          color: '#a855f7',
          cat: 'Etiquetas',
          _type: 'tag',
          _tag: tag,
          _completed: completed
        })
      })
  }

  return results.slice(0, 12)
}

function renderIdeSuggest(val) {
  const box  = document.getElementById('ide-suggest')
  const list = document.getElementById('ide-suggest-list')
  if (!box || !list) return

  ideSuggestions = buildIdeSuggestions(val)
  ideIdx = -1

  if (!ideSuggestions.length || !val) { box.style.display = 'none'; return }

  list.innerHTML = ideSuggestions.map((s, i) => `
    <div class="ide-row" data-idx="${i}" onclick="selectIdeSuggestion(${i})"
      style="display:flex; align-items:center; gap:10px; padding:9px 14px; cursor:pointer; transition:background 0.1s; border-left:3px solid transparent;"
      onmouseover="highlightIde(${i})" onmouseout="">
      <span style="font-size:16px; flex-shrink:0;">${s.icon}</span>
      <div style="flex:1; min-width:0;">
        <div style="font-family:'JetBrains Mono',monospace; font-size:12px; color:${s.color}; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">${esc(s.tpl)}</div>
        <div style="font-size:11px; color:var(--text-muted); margin-top:1px;">${esc(s.desc)}</div>
      </div>
      <span style="font-size:10px; color:var(--text-dim); background:rgba(255,255,255,0.05); padding:2px 6px; border-radius:4px; flex-shrink:0;">${s.cat}</span>
    </div>
  `).join('')

  box.style.display = 'block'
}

function highlightIde(idx) {
  document.querySelectorAll('.ide-row').forEach((r,i) => {
    r.style.background = i===idx ? 'rgba(0,246,255,0.08)' : ''
    r.style.borderLeftColor = i===idx ? 'var(--accent-cyan)' : 'transparent'
  })
  ideIdx = idx
}

window.selectIdeSuggestion = function(idx) {
  const s = ideSuggestions[idx]
  if (!s || !nexusInput) return
  const val = nexusInput.value
  if (s._type === 'account' || s._type === 'contact_acct') {
    nexusInput.value = val.replace(/@[\w]*$/, '@' + s._key) + ' '
  } else if (s._type === 'tag') {
    nexusInput.value = s._completed
  } else if (s._type === 'contact') {
    nexusInput.value = s.tpl
  } else {
    nexusInput.value = s.prefix
  }
  nexusInput.focus()
  const box = document.getElementById('ide-suggest')
  if (box) box.style.display = 'none'
  ideSuggestions = []; ideIdx = -1
  // Re-trigger input to show updated preview
  nexusInput.dispatchEvent(new Event('input'))
}

window.injectAccount = (tag) => {
  if (nexusInput && !nexusInput.value.includes('@')) nexusInput.value = nexusInput.value.trim() + ' ' + tag + ' '
  nexusInput.focus()
  const box = document.getElementById('ide-suggest')
  if (box) box.style.display = 'none'
}

nexusInput?.addEventListener('input', () => {
  const val = nexusInput.value.trim()
  const preview = document.getElementById('parser-preview')

  // IDE suggestions
  renderIdeSuggest(val)

  // Parser preview
  if (preview) {
    if (!val) { preview.style.display = 'none'; return }
    const { type, metadata } = parseNode(val)
    const cfg = {
      income:   { label:`↑ INGRESO $${metadata.amount||'?'}${metadata.account_hint?' @'+metadata.account_hint:''}`, bg:'rgba(74,222,128,0.08)', border:'rgba(74,222,128,0.3)', color:'#4ade80' },
      expense:  { label:`↓ GASTO $${metadata.amount||'?'}${metadata.account_hint?' @'+metadata.account_hint:''}`,   bg:'rgba(248,113,113,0.08)', border:'rgba(248,113,113,0.3)', color:'#f87171' },
      kanban:   { label:'📌 TAREA → Pendiente',         bg:'rgba(96,165,250,0.08)',  border:'rgba(96,165,250,0.3)',  color:'#60a5fa' },
      persona:  { label:'👤 CONTACTO → CRM',             bg:'rgba(251,191,36,0.08)',  border:'rgba(251,191,36,0.3)',  color:'#fbbf24' },
      proyecto: { label:'📁 PROYECTO → Bóveda Neural',   bg:'rgba(168,85,247,0.08)',  border:'rgba(168,85,247,0.3)',  color:'#a855f7' },
      note:     { label:'💡 NOTA LIBRE → Bóveda Neural', bg:'rgba(148,163,184,0.06)', border:'rgba(148,163,184,0.2)', color:'#94a3b8' },
    }
    const c = cfg[type] || cfg.note
    const extras = []
    if (metadata.priority) extras.push(`⚑ ${String(metadata.priority).toUpperCase()}`)
    const detectedDate = metadata.due_date || metadata.date_deadline || metadata.date
    if (detectedDate) extras.push(`📅 ${detectedDate}`)
    const extraStr = extras.length ? `  |  ${extras.join('  ')}` : ''
    preview.textContent = `${c.label}${extraStr}   ↵ Enter para guardar`
    preview.style.cssText = `display:block; position:absolute; bottom:calc(100% + 0px); left:0; right:0; padding:7px 18px; font-size:11px; font-weight:600; font-family:'JetBrains Mono',monospace; border-radius:12px 12px 0 0; border:1px solid ${c.border}; border-bottom:none; background:${c.bg}; color:${c.color}; letter-spacing:0.04em; pointer-events:none; z-index:10;`
  }
})

nexusInput?.addEventListener('keydown', e => {
  const box = document.getElementById('ide-suggest')
  const isOpen = box && box.style.display !== 'none' && ideSuggestions.length > 0

  if (e.key === 'ArrowDown') {
    e.preventDefault()
    if (isOpen) { highlightIde(Math.min(ideIdx+1, ideSuggestions.length-1)) }
    return
  }
  if (e.key === 'ArrowUp') {
    e.preventDefault()
    if (isOpen) { highlightIde(Math.max(ideIdx-1, 0)) }
    return
  }
  if ((e.key === 'Tab' || e.key === 'ArrowRight') && isOpen && ideIdx >= 0) {
    e.preventDefault()
    selectIdeSuggestion(ideIdx)
    return
  }
  if (e.key === 'Escape' && isOpen) {
    e.preventDefault()
    if (box) box.style.display = 'none'; ideSuggestions = []; ideIdx = -1
    return
  }
  if (e.key === 'Enter') {
    if (isOpen && ideIdx >= 0) {
      e.preventDefault()
      selectIdeSuggestion(ideIdx)
      return
    }
    const val = nexusInput.value.trim()
    if (!val) return
    insertNodeRaw(val)
    const wrapper = document.querySelector('.spotlight-wrapper')
    if (wrapper) { wrapper.classList.add('command-success'); setTimeout(() => wrapper.classList.remove('command-success'), 500) }
    nexusInput.value = ''
    if (box) box.style.display = 'none'
    ideSuggestions = []; ideIdx = -1
    const preview = document.getElementById('parser-preview')
    if (preview) preview.style.display = 'none'
  }
})

// Close IDE suggest when clicking outside
document.addEventListener('click', e => {
  if (!e.target.closest('#spotlight-container')) {
    const box = document.getElementById('ide-suggest')
    if (box) box.style.display = 'none'
    ideSuggestions = []; ideIdx = -1
  }
})

// ── Helpers & Rendering ──────────────────
function getFilteredNodes() {
  let nodes = allNodes
  if (activeTypeFilter) nodes = nodes.filter(n => n.type === activeTypeFilter)
  if (!currentFilter) return nodes
  const q = currentFilter.toLowerCase()
  return nodes.filter(n =>
    n.content.toLowerCase().includes(q) ||
    (n.metadata?.tags || []).some(t => t.toLowerCase() === q) ||
    (n.metadata?.label || '').toLowerCase().includes(q) ||
    n.type.toLowerCase().includes(q)
  )
}

window.setTypeFilter = (type) => { activeTypeFilter = activeTypeFilter === type ? null : type; renderAll() }
window.toggleFeedGroup = () => { feedGrouped = !feedGrouped; renderAll() }

// ═══════════════════════════════════════════════════════════
// PANEL DE COMANDOS — Dashboard General
// ═══════════════════════════════════════════════════════════
function renderPanelDashboard() {
  const root = document.getElementById('panel-dashboard-root')
  if (!root) return

  const esc = (s='') => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')
  const fmtM = (n) => '$' + Math.abs(n||0).toLocaleString('es-MX',{maximumFractionDigits:0})

  const today    = new Date()
  const todayStr = today.toISOString().slice(0,10)
  const monthNow = todayStr.slice(0,7)

  // ── Design tokens ─────────────────────────────────────────
  const NX_CARD  = 'background:var(--surface,rgba(255,255,255,0.03));border:1px solid var(--border,rgba(255,255,255,0.08));border-radius:14px;padding:16px;'
  const NX_HEAD  = 'font-size:10px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;'

  // ── A) Global KPIs ────────────────────────────────────────
  const allTxs = allNodes.filter(n => n.type==='income' || n.type==='expense')
  const accounts = allNodes.filter(n => n.type==='account')
  const initBals = accounts.reduce((s,a)=>s+(a.metadata?.balance||0),0)
  const totalInc = allTxs.filter(n=>n.type==='income').reduce((s,n)=>s+(n.metadata?.amount||0),0)
  const totalExp = allTxs.filter(n=>n.type==='expense').reduce((s,n)=>s+(n.metadata?.amount||0),0)
  const netTotal = initBals + totalInc - totalExp
  const netClr   = netTotal >= 0 ? '#2dd4bf' : '#f87171'

  const monthTxs = allTxs.filter(n => (n.metadata?.date||'').startsWith(monthNow))
  const monthInc = monthTxs.filter(n=>n.type==='income').reduce((s,n)=>s+(n.metadata?.amount||0),0)
  const monthExp = monthTxs.filter(n=>n.type==='expense').reduce((s,n)=>s+(n.metadata?.amount||0),0)

  const tareasActivas  = allNodes.filter(n=>n.type==='kanban'&&n.metadata?.status!=='done').length
  const proyectosCount = allNodes.filter(n=>n.type==='proyecto').length

  // Lucide icons — reemplaza el objeto ISVG manual
  const ISVG = {
    net:   lx('DollarSign', 18),
    inc:   lx('TrendingUp',  18),
    exp:   lx('TrendingDown',18),
    tasks: lx('CheckCircle2',18),
    proj:  lx('Briefcase',   18),
    clock: lx('Clock',       14),
    users: lx('Users',       14),
    card:  lx('CreditCard',  14),
    grid:  lx('Layers',      14),
  }

  const kpiData = [
    { icon:'DollarSign', label:'NETO TOTAL',    val:fmtM(netTotal),    color:netClr,    note:netTotal>=0?'flujo positivo':'déficit',    bg: netTotal>=0?'rgba(45,212,191,0.08)':'rgba(248,113,113,0.08)' },
    { icon:'TrendingUp', label:'INGRESOS MES',  val:'+'+fmtM(monthInc),color:'#4ade80', note:monthTxs.filter(n=>n.type==='income').length+' movimientos', bg:'rgba(74,222,128,0.06)' },
    { icon:'TrendingDown',label:'GASTOS MES',   val:'-'+fmtM(monthExp),color:'#f87171', note:monthTxs.filter(n=>n.type==='expense').length+' movimientos', bg:'rgba(248,113,113,0.06)' },
    { icon:'CheckCircle2',label:'TAREAS ACTIVAS',val:tareasActivas,    color:'#60a5fa', note:'en progreso', bg:'rgba(96,165,250,0.06)' },
    { icon:'Briefcase',  label:'PROYECTOS',     val:proyectosCount,    color:'#a78bfa', note:'registrados', bg:'rgba(167,139,250,0.06)' },
  ]

  const kpiStrip = `<div style="display:flex;gap:8px;margin-bottom:16px;overflow-x:auto;padding-bottom:2px;">
    ${kpiData.map(k => `
      <div style="flex:1;min-width:110px;padding:14px 14px 12px;background:${k.bg};border:1px solid ${k.color}22;border-radius:14px;position:relative;overflow:hidden;transition:transform 0.2s,box-shadow 0.2s;cursor:default;"
           onmouseover="this.style.transform='translateY(-2px)';this.style.boxShadow='0 6px 20px rgba(0,0,0,0.25)'"
           onmouseout="this.style.transform='';this.style.boxShadow=''">
        <div style="position:absolute;top:-8px;right:-8px;opacity:0.06;">${lx(k.icon,52,'' ,{strokeWidth:1.2,color:k.color})}</div>
        <div style="color:${k.color};margin-bottom:8px;position:relative;">${lx(k.icon,16,'',{color:k.color,strokeWidth:1.75})}</div>
        <div style="font-size:8.5px;font-weight:800;letter-spacing:.08em;color:var(--text-dim);margin-bottom:5px;text-transform:uppercase;position:relative;">${k.label}</div>
        <div style="font-size:18px;font-weight:900;color:${k.color};font-family:'JetBrains Mono',monospace;line-height:1;position:relative;">${k.val}</div>
        <div style="font-size:9px;color:var(--text-muted);margin-top:4px;position:relative;">${k.note}</div>
      </div>`).join('')}
  </div>`

  // ── A2) Task distribution (Kanban summary) ─────────────────
  const kNodes  = allNodes.filter(n=>n.type==='kanban')
  const kTotal  = kNodes.length
  const kTodo   = kNodes.filter(n=>(n.metadata?.status||'todo')==='todo').length
  const kProg   = kNodes.filter(n=>n.metadata?.status==='in_progress').length
  const kDoneAll= kNodes.filter(n=>n.metadata?.status==='done').length
  const kOver   = kNodes.filter(n=>{const d=n.metadata?.date_deadline||n.metadata?.due_date;return d&&d<todayStr&&n.metadata?.status!=='done'}).length
  const kPctDone= kTotal ? Math.round(kDoneAll/kTotal*100) : 0
  const pctColor= kPctDone>=75?'#4ade80':kPctDone>=40?'#fbbf24':'#94a3b8'

  const taskDistHTML = `<div style="margin-bottom:16px;background:rgba(255,255,255,0.02);border:1px solid rgba(255,255,255,0.07);border-radius:14px;overflow:hidden;">
    <div style="display:flex;align-items:stretch;">
      ${[
        {label:'Pendientes', val:kTodo,   color:'#94a3b8', icon:'Circle'},
        {label:'En progreso',val:kProg,   color:'#fbbf24', icon:'Zap'},
        {label:'Completadas',val:kDoneAll,color:'#4ade80', icon:'CheckCircle2'},
        {label:'Vencidas',   val:kOver,   color:kOver>0?'#f87171':'#475569', icon:'AlertCircle'},
      ].map((k,i)=>`<div style="flex:1;padding:14px 10px;text-align:center;${i>0?'border-left:1px solid rgba(255,255,255,0.05);':''}">
        <div style="display:flex;justify-content:center;margin-bottom:6px;color:${k.color};opacity:${k.val===0?0.35:0.9};">${lx(k.icon,14,'',{color:k.color})}</div>
        <div style="font-size:20px;font-weight:900;color:${k.val===0?'var(--text-dim)':k.color};font-family:'JetBrains Mono',monospace;line-height:1;">${k.val}</div>
        <div style="font-size:8px;font-weight:700;color:var(--text-dim);text-transform:uppercase;margin-top:4px;letter-spacing:.05em;">${k.label}</div>
      </div>`).join('')}
      <div style="padding:14px 18px;border-left:1px solid rgba(255,255,255,0.05);text-align:center;min-width:88px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;">
        <div style="font-size:8px;font-weight:800;color:var(--text-dim);text-transform:uppercase;letter-spacing:.06em;">Progreso</div>
        <div style="font-size:24px;font-weight:900;color:${pctColor};font-family:'JetBrains Mono',monospace;line-height:1;">${kPctDone}<span style="font-size:12px;opacity:.7;">%</span></div>
        <div style="width:56px;height:5px;background:rgba(255,255,255,0.06);border-radius:99px;overflow:hidden;">
          <div style="height:100%;width:${kPctDone}%;background:linear-gradient(90deg,#00f6ff,${pctColor});border-radius:99px;transition:width 0.6s cubic-bezier(0.16,1,0.3,1);"></div>
        </div>
      </div>
    </div>
  </div>`

  // ── B) Próximos pagos fijos — con estado pagado/pendiente ────
  const freqLabelDash = { mensual:'Mensual', bimestral:'Bimestral', trimestral:'Trimestral', semestral:'Semestral', anual:'Anual', bianual:'Cada 2 años', trianual:'Cada 3 años', semanal:'Semanal', quincenal:'Quincenal', diario:'Diario', personalizado:'Personalizado' }
  const bills = allNodes
    .filter(n => n.type==='bill' || n.type==='subscription')
    .map(n => {
      const m = n.metadata || {}
      const freq = m.frequency || 'mensual'
      const nextDate = calcNextDueDate(freq, m.dayOfMonth, m.weekday, m.customDays, m.specificDate)
      const daysLeft = nextDate ? Math.ceil((new Date(nextDate + 'T12:00:00') - today) / 86400000) : 999
      return { n, daysLeft, nextDate, paid: !!m.paid }
    })
    .sort((a, b) => (a.paid ? 1000 + a.daysLeft : a.daysLeft) - (b.paid ? 1000 + b.daysLeft : b.daysLeft))
    .slice(0, 6)

  const billsHTML = bills.length ? bills.map(({ n, daysLeft, nextDate, paid }) => {
    const amt = n.metadata?.amount
    const overdue = !paid && daysLeft < 0
    const clr = paid ? '#4ade80' : overdue ? '#f87171' : daysLeft <= 3 ? '#f87171' : daysLeft <= 7 ? '#fb923c' : '#94a3b8'
    const dayTxt = paid ? 'PAG' : overdue ? `${Math.abs(daysLeft)}d` : daysLeft === 0 ? '¡HOY!' : `${daysLeft}d`
    const subTxt = paid ? '✓ pagado' : overdue ? 'VENCIDO' : n.metadata?.frequency ? freqLabelDash[n.metadata.frequency] || n.metadata.frequency : ''
    return `<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.04);opacity:${paid?0.55:1};">
      <div style="min-width:38px;text-align:center;flex-shrink:0;">
        <div style="font-size:${paid?10:15}px;font-weight:900;color:${clr};font-family:'JetBrains Mono',monospace;line-height:1;">${dayTxt}</div>
        <div style="font-size:8px;color:${clr};font-weight:700;text-transform:uppercase;margin-top:1px;">${subTxt}</div>
      </div>
      <div style="flex:1;min-width:0;">
        <div style="font-size:12px;font-weight:600;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;${paid?'text-decoration:line-through;':''}">${esc(n.metadata?.label||n.content)}</div>
        ${nextDate && !paid ? `<div style="font-size:10px;color:var(--text-dim);">📅 ${nextDate}</div>` : ''}
      </div>
      <button onclick="toggleBillPaid('${n.id}')" style="font-size:10px;padding:2px 8px;border-radius:6px;border:1px solid ${paid?'rgba(74,222,128,0.4)':'rgba(255,255,255,0.15)'};background:${paid?'rgba(74,222,128,0.1)':'transparent'};color:${paid?'#4ade80':'var(--text-muted)'};cursor:pointer;font-weight:700;flex-shrink:0;">${paid?'↩ Reabrir':'✓ Pagar'}</button>
      <div style="font-size:12px;font-weight:800;color:${clr};font-family:'JetBrains Mono',monospace;flex-shrink:0;">${amt!=null?fmtM(amt):'Var'}</div>
    </div>`
  }).join('')
  : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:16px 0;text-align:center;opacity:.7;">Sin pagos recurrentes registrados</div>`

  // ── C) Proyectos activos (con resumen expandible) ──────────
  const proyectos = allNodes.filter(n=>n.type==='proyecto').slice(0,6)
  const projHTML = proyectos.length ? proyectos.map(p => {
    const m = p.metadata||{}
    const label = m.label||p.content
    const budget = +(m.budget||0)
    const slug   = m.project_slug||''
    const tags   = [(m.label||'').toLowerCase(), slug.toLowerCase()].filter(Boolean)
    const cots   = allNodes.filter(n=>n.type==='cotizacion'&&tags.some(t=>(n.metadata?.project_tag||'').toLowerCase()===t))
    const comp   = cots.reduce((s,c)=>s+(+c.metadata?.amount||0),0)
    const pct    = budget>0 ? Math.min(100,Math.round(comp/budget*100)) : 0
    const barClr = pct>90?'#f87171':pct>60?'#fb923c':'#4ade80'
    const miles  = allNodes.filter(n=>n.type==='milestone'&&tags.some(t=>(n.metadata?.project_tag||'').toLowerCase()===t))
    const mDone  = miles.filter(n=>n.metadata?.done).length
    // Task stats for this project
    const projTasks = allNodes.filter(n=>n.type==='kanban'&&tags.some(t=>(n.metadata?.project_tag||'').toLowerCase()===t||(n.metadata?.tags||[]).some(tg=>tg.toLowerCase()==='#'+t)))
    const pTodo = projTasks.filter(n=>(n.metadata?.status||'todo')==='todo').length
    const pProg = projTasks.filter(n=>n.metadata?.status==='in_progress').length
    const pDone = projTasks.filter(n=>n.metadata?.status==='done').length
    // Debt
    const debtTotal = cots.reduce((s,c) => {
      const total = +(c.metadata?.amount||0)
      const paid  = (c.metadata?.abonos||[]).reduce((s2,a)=>s2+(+(a.amount||0)),0)
      return s + Math.max(0, total - paid)
    }, 0)
    // Pagos fijos vinculados al proyecto
    const projBills = allNodes
      .filter(n => (n.type==='bill'||n.type==='subscription') && (n.metadata?.project_tag===slug || (n.metadata?.tags||[]).includes('#'+slug)))
      .map(n => {
        const fm = n.metadata || {}
        const nextDate = calcNextDueDate(fm.frequency||'mensual', fm.dayOfMonth, fm.weekday, fm.customDays, fm.specificDate)
        const dl = nextDate ? Math.ceil((new Date(nextDate+'T12:00:00') - today) / 86400000) : null
        return { n, nextDate, dl, paid: !!fm.paid }
      })
      .sort((a,b) => (a.dl??999)-(b.dl??999))
    const projBillsHtml = projBills.length
      ? projBills.slice(0,3).map(({n,nextDate,dl,paid}) => {
          const clr = paid?'#4ade80':dl!==null&&dl<=0?'#f87171':dl!==null&&dl<=7?'#fb923c':'#94a3b8'
          const dayBadge = paid?'✅':dl===0?'¡HOY!':dl!==null&&dl<0?`${Math.abs(dl)}d VENC`:dl!==null?`${dl}d`:''
          return `<div style="display:flex;align-items:center;gap:6px;padding:3px 0;font-size:10px;">
            <span style="color:${clr};font-weight:800;font-family:'JetBrains Mono',monospace;min-width:42px;">${dayBadge}</span>
            <span style="flex:1;color:var(--text-muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(n.metadata?.label||n.content)}</span>
            ${n.metadata?.amount!=null?`<span style="color:${clr};font-weight:800;font-family:'JetBrains Mono',monospace;">${fmtM(n.metadata.amount)}</span>`:''}
          </div>`
        }).join('')
      : ''
    const pid = p.id
    return `<div style="border-bottom:1px solid rgba(255,255,255,0.04);">
      <div style="display:flex;align-items:center;gap:8px;padding:8px 0;cursor:pointer;" onclick="document.getElementById('pd-expand-${pid}').style.display=document.getElementById('pd-expand-${pid}').style.display==='none'?'':'none'">
        <div style="flex:1;font-size:12px;font-weight:700;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(label)}</div>
        ${budget>0?`<span style="font-size:10px;font-weight:800;font-family:'JetBrains Mono',monospace;color:${barClr};flex-shrink:0;">${pct}%</span>`:''}
        ${miles.length>0?`<span style="font-size:10px;color:var(--text-dim,#475569);flex-shrink:0;">${mDone}/${miles.length}</span>`:''}
        <span style="font-size:10px;color:var(--text-dim);flex-shrink:0;">▾</span>
      </div>
      <div style="height:3px;background:rgba(255,255,255,0.07);border-radius:2px;overflow:hidden;">
        ${budget>0?`<div style="height:100%;width:${pct}%;background:${barClr};border-radius:2px;transition:width .5s;"></div>`:
          `<div style="height:100%;width:100%;background:rgba(255,255,255,0.05);border-radius:2px;"></div>`}
      </div>
      <div id="pd-expand-${pid}" style="display:none;padding:8px 0 10px;border-top:1px solid rgba(255,255,255,0.03);margin-top:6px;">
        <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px;margin-bottom:8px;">
          <div style="text-align:center;background:rgba(148,163,184,0.06);border-radius:6px;padding:6px;">
            <div style="font-size:14px;font-weight:900;color:#94a3b8;font-family:'JetBrains Mono',monospace;">${pTodo}</div>
            <div style="font-size:8px;color:var(--text-dim);font-weight:700;">PENDIENTES</div>
          </div>
          <div style="text-align:center;background:rgba(251,191,36,0.06);border-radius:6px;padding:6px;">
            <div style="font-size:14px;font-weight:900;color:#fbbf24;font-family:'JetBrains Mono',monospace;">${pProg}</div>
            <div style="font-size:8px;color:var(--text-dim);font-weight:700;">EN CURSO</div>
          </div>
          <div style="text-align:center;background:rgba(74,222,128,0.06);border-radius:6px;padding:6px;">
            <div style="font-size:14px;font-weight:900;color:#4ade80;font-family:'JetBrains Mono',monospace;">${pDone}</div>
            <div style="font-size:8px;color:var(--text-dim);font-weight:700;">HECHAS</div>
          </div>
          <div style="text-align:center;background:rgba(248,113,113,0.06);border-radius:6px;padding:6px;">
            <div style="font-size:14px;font-weight:900;color:${debtTotal>0?'#f87171':'#4ade80'};font-family:'JetBrains Mono',monospace;">${fmtM(debtTotal)}</div>
            <div style="font-size:8px;color:var(--text-dim);font-weight:700;">DEUDA</div>
          </div>
        </div>
        ${projBillsHtml ? `<div style="padding:6px 8px;background:rgba(251,146,60,0.04);border:1px solid rgba(251,146,60,0.15);border-radius:8px;margin-bottom:8px;">
          <div style="font-size:8px;font-weight:800;color:#fb923c;letter-spacing:.06em;text-transform:uppercase;margin-bottom:5px;">📅 Pagos vinculados</div>
          ${projBillsHtml}
        </div>` : ''}
        <button onclick="openProjectView('${pid}')" style="width:100%;padding:6px;font-size:11px;font-weight:700;background:rgba(167,139,250,0.08);border:1px solid rgba(167,139,250,0.2);color:#a78bfa;border-radius:6px;cursor:pointer;">Abrir proyecto →</button>
      </div>
    </div>`
  }).join('') : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:16px 0;text-align:center;opacity:.7;">Sin proyectos registrados</div>`

  // ── D) Cuentas ────────────────────────────────────────────
  const accHTML = accounts.length ? accounts.map(a => {
    const inc = allTxs.filter(n=>n.type==='income' &&n.metadata?.account_id===a.id).reduce((s,n)=>s+(n.metadata?.amount||0),0)
    const exp = allTxs.filter(n=>n.type==='expense'&&n.metadata?.account_id===a.id).reduce((s,n)=>s+(n.metadata?.amount||0),0)
    const bal = (a.metadata?.balance||0)+inc-exp
    const clr = a.metadata?.color||'#4ade80'
    const neg = bal<0
    return `<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.04);cursor:pointer;" onclick="switchView('finance');setTimeout(()=>setActiveAccount('${a.id}'),200)">
      <span style="width:8px;height:8px;border-radius:50%;background:${neg?'#f87171':clr};flex-shrink:0;"></span>
      <span style="flex:1;font-size:12px;font-weight:600;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(a.metadata?.label||a.content)}</span>
      <span style="font-size:12px;font-weight:900;font-family:'JetBrains Mono',monospace;color:${neg?'#f87171':clr};flex-shrink:0;">${neg?'-':''}${fmtM(Math.abs(bal))}</span>
    </div>`
  }).join('') : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:16px 0;text-align:center;opacity:.7;">Sin cuentas — crea una en Bio-Finanzas</div>`

  // ── E) Próximos eventos de contactos (cumpleaños / aniversarios) ──────────
  const DAYS_AHEAD = 30
  const upcomingEvents = []
  const todayMD = `${String(today.getMonth()+1).padStart(2,'0')}-${String(today.getDate()).padStart(2,'0')}`
  const personas = allNodes.filter(n => n.type==='persona'||n.type==='contact')
  personas.forEach(c => {
    const m = c.metadata || {}
    const name = m.name || c.content || '?'
    ;[
      { date: m.birthday,    emoji: '🎂', label: 'Cumpleaños de' },
      { date: m.anniversary, emoji: '💑', label: 'Aniversario de' },
    ].forEach(ev => {
      if (!ev.date) return
      const [year, month, day] = ev.date.split('-').map(Number)
      if (!month || !day) return
      // Calculate next occurrence (this year or next)
      let evDate = new Date(today.getFullYear(), month-1, day)
      if (evDate < today) evDate = new Date(today.getFullYear()+1, month-1, day)
      const daysLeft = Math.ceil((evDate - today) / 86400000)
      if (daysLeft <= DAYS_AHEAD) {
        upcomingEvents.push({ daysLeft, emoji: ev.emoji, label: `${ev.label} ${name}`, name, contactId: c.id })
      }
    })
  })
  upcomingEvents.sort((a,b) => a.daysLeft - b.daysLeft)

  const eventsHTML = upcomingEvents.length
    ? upcomingEvents.slice(0,5).map(ev => {
        const clr = ev.daysLeft === 0 ? '#f472b6' : ev.daysLeft <= 3 ? '#fb923c' : ev.daysLeft <= 7 ? '#fbbf24' : '#94a3b8'
        const dayTxt = ev.daysLeft === 0 ? '¡HOY!' : `${ev.daysLeft}d`
        return `<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.04);">
          <div style="min-width:36px;text-align:center;flex-shrink:0;">
            <div style="font-size:15px;font-weight:900;color:${clr};font-family:'JetBrains Mono',monospace;line-height:1;">${dayTxt}</div>
            ${ev.daysLeft > 0 ? `<div style="font-size:8px;color:${clr};font-weight:700;text-transform:uppercase;">días</div>` : ''}
          </div>
          <div style="font-size:18px;flex-shrink:0;">${ev.emoji}</div>
          <div style="flex:1;min-width:0;font-size:12px;font-weight:600;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(ev.label)}</div>
        </div>`
      }).join('')
    : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:16px 0;text-align:center;opacity:.7;">Sin eventos en los próximos 30 días 🎉</div>`

  // ── G) Abonos próximos a vencer (30 días) ────────────────────
  const _cotsPendDash = allNodes.filter(n =>
    n.type === 'cotizacion' && !['rechazada', 'pagada'].includes(n.metadata?.status || ''))
  const _upcomingAbonosDash = _cotsPendDash
    .flatMap(cot => (cot.metadata?.abonos || [])
      .filter(a => a.due_date && !a.paid_at)
      .map(a => ({
        daysLeft: Math.ceil((new Date(a.due_date + 'T12:00:00') - today) / 86400000),
        label:    cot.metadata?.label || cot.content || '?',
        project:  cot.metadata?.project_tag || '',
        amount:   +(a.amount || 0),
        cotId:    cot.id
      })))
    .filter(a => a.daysLeft >= -7 && a.daysLeft <= 30)
    .sort((a, b) => a.daysLeft - b.daysLeft)
    .slice(0, 5)

  const abonosDashHTML = _upcomingAbonosDash.length
    ? _upcomingAbonosDash.map(({ daysLeft, label, project, amount }) => {
        const overdue = daysLeft < 0
        const clr = overdue ? '#f87171' : daysLeft <= 3 ? '#fb923c' : daysLeft <= 7 ? '#fbbf24' : '#94a3b8'
        const dayTxt = overdue ? `${Math.abs(daysLeft)}d` : daysLeft === 0 ? '¡HOY!' : `${daysLeft}d`
        return `<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.04);">
          <div style="min-width:36px;text-align:center;flex-shrink:0;">
            <div style="font-size:15px;font-weight:900;color:${clr};font-family:'JetBrains Mono',monospace;line-height:1;">${dayTxt}</div>
            <div style="font-size:8px;color:${clr};font-weight:700;text-transform:uppercase;">${overdue ? 'VENC' : daysLeft === 0 ? '' : 'días'}</div>
          </div>
          <div style="flex:1;min-width:0;">
            <div style="font-size:12px;font-weight:600;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(label)}</div>
            ${project ? `<div style="font-size:10px;color:var(--text-dim);">#${esc(project)}</div>` : ''}
          </div>
          <div style="font-size:12px;font-weight:800;color:${clr};font-family:'JetBrains Mono',monospace;flex-shrink:0;">${fmtM(amount)}</div>
        </div>`
      }).join('')
    : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:12px 0;text-align:center;opacity:.7;">Sin abonos próximos</div>`

  // ── H) Próximos a liquidar (≥ 70% pagado, saldo > 0) ─────────
  const _nearLiq = _cotsPendDash
    .map(cot => {
      const total = +(cot.metadata?.amount || 0)
      if (total === 0) return null
      const paid  = (cot.metadata?.abonos || []).reduce((s, a) => s + (+(a.amount || 0)), 0)
      const saldo = total - paid
      const pct   = Math.round(paid / total * 100)
      if (saldo <= 0 || pct < 70) return null
      return { label: cot.metadata?.label || cot.content, project: cot.metadata?.project_tag || '', saldo, pct, cotId: cot.id }
    })
    .filter(Boolean)
    .sort((a, b) => b.pct - a.pct)
    .slice(0, 5)

  const nearLiqHTML = _nearLiq.length
    ? _nearLiq.map(({ label, project, saldo, pct }) => {
        const clr = pct >= 90 ? '#4ade80' : '#fbbf24'
        return `<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.04);">
          <div style="min-width:36px;text-align:center;flex-shrink:0;">
            <div style="font-size:14px;font-weight:900;color:${clr};font-family:'JetBrains Mono',monospace;line-height:1;">${pct}%</div>
            <div style="font-size:8px;color:${clr};font-weight:700;text-transform:uppercase;">pagado</div>
          </div>
          <div style="flex:1;min-width:0;">
            <div style="font-size:12px;font-weight:600;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(label)}</div>
            ${project ? `<div style="font-size:10px;color:var(--text-dim);">#${esc(project)}</div>` : ''}
          </div>
          <div style="font-size:12px;font-weight:800;color:#f87171;font-family:'JetBrains Mono',monospace;flex-shrink:0;">${fmtM(saldo)}</div>
        </div>`
      }).join('')
    : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:12px 0;text-align:center;opacity:.7;">Sin cotizaciones cerca de liquidación</div>`

  // ── F) Deudas a proveedores ───────────────────────────────
  const debtMap = {}
  allNodes.filter(n=>n.type==='cotizacion'&&!['rechazada','pagada'].includes(n.metadata?.status||'')).forEach(cot => {
    const pid = cot.metadata?.provider_id; if(!pid) return
    const prov = allNodes.find(n=>n.id===pid); if(!prov) return
    const saldo = Math.max(0, (+cot.metadata?.amount||0) - (cot.metadata?.abonos||[]).reduce((s,a)=>s+(+a.amount||0),0))
    if(saldo<=0) return
    if(!debtMap[pid]) debtMap[pid] = { name: prov.metadata?.name||prov.content||'?', saldo:0 }
    debtMap[pid].saldo += saldo
  })
  const debts = Object.values(debtMap).sort((a,b)=>b.saldo-a.saldo).slice(0,4)
  const debtHTML = debts.length ? debts.map(d => `
    <div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.04);">
      <div style="width:28px;height:28px;border-radius:50%;background:rgba(251,146,60,0.14);color:#fb923c;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:800;flex-shrink:0;">${esc(d.name.charAt(0).toUpperCase())}</div>
      <span style="flex:1;font-size:12px;font-weight:600;color:var(--text-primary,#f0f6fc);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(d.name)}</span>
      <span style="font-size:12px;font-weight:900;font-family:'JetBrains Mono',monospace;color:#f87171;flex-shrink:0;">${fmtM(d.saldo)}</span>
    </div>`).join('')
  : `<div style="font-size:12px;color:var(--text-dim,#475569);padding:16px 0;text-align:center;opacity:.7;">Sin saldos pendientes 🎉</div>`

  // ── Render ────────────────────────────────────────────────
  root.innerHTML = `
    ${kpiStrip}
    ${taskDistHTML}
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
      <div style="${NX_CARD}">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
          ${lx('CalendarClock',14,'',{color:'#fb923c'})}
          <span style="${NX_HEAD}color:#fb923c;">Próximos pagos</span>
          ${bills.length?`<span style="margin-left:auto;font-size:9px;color:#fb923c;font-weight:700;background:rgba(251,146,60,0.12);border-radius:99px;padding:1px 8px;border:1px solid rgba(251,146,60,0.25);">${bills.length}</span>`:''}
        </div>
        ${billsHTML}
      </div>
      <div style="${NX_CARD}">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
          ${lx('Briefcase',14,'',{color:'#a78bfa'})}
          <span style="${NX_HEAD}color:#a78bfa;">Proyectos activos</span>
          ${proyectos.length?`<span style="font-size:9px;color:#a78bfa;font-weight:700;background:rgba(167,139,250,0.12);border-radius:99px;padding:1px 8px;border:1px solid rgba(167,139,250,0.25);">${proyectos.length}</span>`:''}
          <button onclick="switchView('proyectos')" style="margin-left:auto;font-size:10px;color:#a78bfa;background:rgba(167,139,250,0.08);border:1px solid rgba(167,139,250,0.2);border-radius:6px;padding:2px 8px;cursor:pointer;display:flex;align-items:center;gap:4px;">${lx('ArrowUpRight',11,'',{color:'#a78bfa'})} Ver todos</button>
        </div>
        ${projHTML}
      </div>
      <div style="${NX_CARD}">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
          ${lx('Wallet',14,'',{color:'#2dd4bf'})}
          <span style="${NX_HEAD}color:#2dd4bf;">Cuentas</span>
          <button onclick="switchView('finance')" style="margin-left:auto;font-size:10px;color:#2dd4bf;background:rgba(45,212,191,0.08);border:1px solid rgba(45,212,191,0.2);border-radius:6px;padding:2px 8px;cursor:pointer;display:flex;align-items:center;gap:4px;">${lx('ArrowUpRight',11,'',{color:'#2dd4bf'})} Bio-Finanzas</button>
        </div>
        ${accHTML}
      </div>
      <div style="${NX_CARD}">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
          ${lx('Users',14,'',{color:'#f87171'})}
          <span style="${NX_HEAD}color:#f87171;">A quién se debe</span>
          ${debts.length?`<span style="margin-left:auto;font-size:9px;color:#f87171;font-weight:700;background:rgba(248,113,113,0.12);border-radius:99px;padding:1px 8px;border:1px solid rgba(248,113,113,0.25);">${debts.length}</span>`:''}
        </div>
        ${debtHTML}
      </div>
      <div style="${NX_CARD}grid-column:1/-1;">
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:24px;">
          <div>
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
              ${lx('Clock',14,'',{color:'#fb923c'})}
              <span style="${NX_HEAD}color:#fb923c;">Abonos a vencer</span>
              ${_upcomingAbonosDash.length ? `<span style="font-size:9px;color:#fb923c;font-weight:700;background:rgba(251,146,60,0.12);border-radius:99px;padding:1px 8px;border:1px solid rgba(251,146,60,0.25);">${_upcomingAbonosDash.length}</span>` : ''}
              <button onclick="switchView('proyectos')" style="margin-left:auto;font-size:10px;color:#fb923c;background:rgba(251,146,60,0.08);border:1px solid rgba(251,146,60,0.2);border-radius:6px;padding:2px 8px;cursor:pointer;display:flex;align-items:center;gap:4px;">${lx('ArrowUpRight',11,'',{color:'#fb923c'})} Proyectos</button>
            </div>
            ${abonosDashHTML}
          </div>
          <div>
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
              ${lx('TrendingUp',14,'',{color:'#4ade80'})}
              <span style="${NX_HEAD}color:#4ade80;">Próximos a liquidar</span>
              ${_nearLiq.length ? `<span style="font-size:9px;color:#4ade80;font-weight:700;background:rgba(74,222,128,0.12);border-radius:99px;padding:1px 8px;border:1px solid rgba(74,222,128,0.25);">${_nearLiq.length}</span>` : ''}
            </div>
            ${nearLiqHTML}
          </div>
        </div>
      </div>
      <div style="${NX_CARD}grid-column:1/-1;">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#f472b6" stroke-width="2" stroke-linecap="round"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg>
          <span style="${NX_HEAD}color:#f472b6;">Eventos próximos — cumpleaños &amp; aniversarios (30 días)</span>
          ${upcomingEvents.length?`<span style="margin-left:auto;font-size:10px;color:#f472b6;font-weight:700;background:rgba(244,114,182,0.1);border-radius:8px;padding:1px 7px;">${upcomingEvents.length}</span>`:''}
          <button onclick="switchView('contacts')" style="margin-left:${upcomingEvents.length?'4px':'auto'};font-size:10px;color:#f472b6;background:rgba(244,114,182,0.08);border:1px solid rgba(244,114,182,0.2);border-radius:6px;padding:2px 8px;cursor:pointer;">Ver contactos</button>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:0;">
          ${eventsHTML}
        </div>
      </div>
    </div>`
}
window.renderPanelDashboard = renderPanelDashboard

// ── Mapa de renders por vista — lazy render (Phase C) ───────────────────────────
const VIEW_RENDER_MAP = {
  // Feed: incluye semáforo y pulso semanal (solo necesarios en esta vista)
  feed:         (nodes) => { renderPanelDashboard(); renderFeed(nodes); renderFilterBar(); renderSemaforoCuentas(); renderPulsoSemanal() },
  kanban:       (nodes) => renderKanban(nodes),
  notes:        (nodes) => renderNotes(nodes),
  finance:      (nodes) => renderFinance(nodes),
  calendar:     (nodes) => renderCalendar(nodes),
  cronica:      (nodes) => renderCronica(nodes),
  contacts:     ()      => renderContacts(),
  agenda:       ()      => renderAgenda(allNodes),
  proyectos:    ()      => renderProyectos(),
  movimientos:  ()      => renderMovimientos(),
  cotizaciones: ()      => renderCotizaciones(),
  inmuebles:    ()      => renderInmuebles(),
  automations:  ()      => { if (window.nexusAutomations?.render) window.nexusAutomations.render() },
  afp:          ()      => renderAFP(),
  crypto:       ()      => renderCrypto(),
  // Vistas adicionales — evitan que caigan al fallback costoso
  tags:         (nodes) => { if (typeof renderTagsView === 'function') renderTagsView(nodes) },
  herramientas: ()      => {},
}

function renderAll() {
  // safe wrapper — un fallo en una sección no bloquea las demás
  const safe = (fn, ...args) => {
    try { fn(...args) } catch (e) { console.warn('[renderAll]', fn.name || '?', e) }
  }
  const nodes = getFilteredNodes()
  // Siempre: stats globales + alertas de hábitos + índice de búsqueda (solo si allNodes cambió)
  safe(updateStats, nodes)
  safe(checkHabitAlerts)
  if (typeof buildFuseIndex === 'function') safe(buildFuseIndex)
  // Lazy: solo renderiza la vista activa (semáforo/pulso solo en 'feed')
  const viewFn = VIEW_RENDER_MAP[activeView]
  if (viewFn) safe(viewFn, nodes)
  else {
    // Fallback mínimo para vistas desconocidas — solo feed
    safe(renderFeed, nodes); safe(renderFilterBar)
    console.warn('[renderAll] vista no mapeada:', activeView)
  }
  // Herramientas sub-renderers — siempre actualizar aunque no sea la vista activa
  if (typeof renderOtcHistory === 'function') safe(renderOtcHistory)
  if (typeof renderDocHistory === 'function') safe(renderDocHistory)
  // Lucide: reemplaza <i data-lucide="..."> tras cada render
  requestAnimationFrame(refreshIcons)
}

function renderFilterBar() {
  const container = document.getElementById('view-feed') // O donde quieras mostrarlo
  const existing = document.getElementById('active-filter-msg')
  if (existing) existing.remove()
  
  if (currentFilter) {
    const bar = document.createElement('div')
    bar.id = 'active-filter-msg'
    bar.className = 'filter-active-bar'
    bar.innerHTML = `<span>Filtrando por: <b>${currentFilter}</b></span><span onclick="clearFilter()" style="cursor:pointer; margin-left:auto;">✕</span>`
    container.insertBefore(bar, container.querySelector('.feed-container'))
  }
}

window.clearFilter = () => { currentFilter = null; activeTypeFilter = null; renderAll(); }
window.setFilter = (tag) => { currentFilter = tag; renderAll(); }

function updateStats(nodes) {
  const inc = allNodes.filter(n=>n.type==='income').reduce((s,n)=>s+(n.metadata?.amount||0),0)
  const exp = allNodes.filter(n=>n.type==='expense').reduce((s,n)=>s+(n.metadata?.amount||0),0)
  document.getElementById('dominance-balance').textContent = `$${(inc-exp).toLocaleString()}`
  document.getElementById('w-nodes-count').textContent = allNodes.filter(n=>n.type==='kanban').length
}

// TYPE_FILTERS — movido al bloque de constantes (antes del boot IIFE)

function feedItemHtml(n) {
  const tc = TYPE_CONFIG[n.type] || { label:`#${n.type.toUpperCase()}`, color:'var(--accent-cyan)', border:'rgba(0,246,255,0.3)', bg:'rgba(0,246,255,0.04)' }
  const amount = (n.type === 'income' || n.type === 'expense') && n.metadata?.amount
    ? `<span style="font-family:'JetBrains Mono',monospace;font-weight:800;color:${tc.color};flex-shrink:0;">${n.type==='income'?'+':'-'}$${n.metadata.amount.toLocaleString()}</span>` : ''
  const timeStr = n.created_at ? `${new Date(n.created_at).getHours().toString().padStart(2,'0')}:${new Date(n.created_at).getMinutes().toString().padStart(2,'0')}` : '--:--'
  const newPulse = n._optimistic ? ' nexus-new-pulse' : ''
  // Lucide icons para acciones del feed
  const _svgEdit   = lx('Pencil',   11, '', { strokeWidth: 2 })
  const _svgFolder = lx('FolderOpen',11,'', { strokeWidth: 2 })
  const _svgCheck  = lx('Check',    11, '', { strokeWidth: 2.5 })
  const _svgX      = lx('X',        10, '', { strokeWidth: 2.5 })

  // Badge de tipo usando nxBadge
  const typeBadgeFn = NX_TYPE_BADGE[n.type]
  const typeBadge = typeBadgeFn ? typeBadgeFn() : nxBadge(tc.label, { color: tc.color, bg: tc.border.replace('0.4','0.08').replace('0.3','0.08') })

  // Tags del nodo
  const tagsHtml = (n.metadata?.tags||[])
    .filter(t => t.toLowerCase() !== `#${n.type.toLowerCase()}`)
    .map(t => `<span onclick="event.stopPropagation();setFilter('${t}')" style="cursor:pointer;">${nxBadge(t, { color: tc.color, bg: tc.border.replace('0.4','0.06').replace('0.3','0.06'), border: tc.border.replace('0.4','0.15').replace('0.3','0.15'), iconSize:9 })}</span>`)
    .join('')

  return `
    <div class="feed-item node-card${newPulse}" data-node-id="${n.id}" style="border-left:3px solid ${tc.border};background:${tc.bg};" onclick="openCardModal('${n.id}')">
      <span class="feed-time">${timeStr}</span>
      ${typeBadge}
      <div style="flex:1;min-width:0;">
        <div style="font-size:14px;color:#f0f6fc;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(n.metadata?.label || n.content)}</div>
        ${tagsHtml ? `<div style="margin-top:4px;display:flex;gap:4px;flex-wrap:wrap;">${tagsHtml}</div>` : ''}
      </div>
      ${amount}
      ${n.type==='proyecto' ? `
        <span onclick="event.stopPropagation();openProyectoModal('${n.id}')" title="Editar proyecto" style="display:inline-flex;align-items:center;justify-content:center;color:#2dd4bf;cursor:pointer;padding:5px;flex-shrink:0;width:26px;height:26px;border-radius:7px;background:rgba(45,212,191,0.08);border:1px solid rgba(45,212,191,0.18);transition:background 0.15s;" onmouseenter="this.style.background='rgba(45,212,191,0.18)'" onmouseleave="this.style.background='rgba(45,212,191,0.08)'">${_svgEdit}</span>
        <span onclick="event.stopPropagation();openProjectView('${n.id}')" title="Vista de Proyecto" style="display:inline-flex;align-items:center;justify-content:center;color:#60a5fa;cursor:pointer;padding:5px;flex-shrink:0;width:26px;height:26px;border-radius:7px;background:rgba(96,165,250,0.08);border:1px solid rgba(96,165,250,0.18);transition:background 0.15s;" onmouseenter="this.style.background='rgba(96,165,250,0.18)'" onmouseleave="this.style.background='rgba(96,165,250,0.08)'">${_svgFolder}</span>
      ` : ''}
      ${n.type==='cotizacion' ? (() => {
        const st = n.metadata?.status || 'pendiente'
        const stCfg = COT_STATUS[st] || COT_STATUS.pendiente
        const amt = n.metadata?.amount ? `<span style="font-family:'JetBrains Mono',monospace;font-weight:800;color:#fb923c;flex-shrink:0;font-size:12px;">$${(+n.metadata.amount).toLocaleString('es-MX')}</span>` : ''
        const statusBadge = nxBadge(stCfg.label, { color: stCfg.color, bg: stCfg.color + '1a', icon: st==='aceptada'?'CheckCircle2':st==='rechazada'?'XCircle':'Clock' })
        const quickBtns = st !== 'aceptada' ? `<span onclick="event.stopPropagation();changeCotizacionStatus('${n.id}','aceptada')" title="Aceptar" style="display:inline-flex;align-items:center;justify-content:center;color:#4ade80;cursor:pointer;width:26px;height:26px;border-radius:7px;background:rgba(74,222,128,0.08);border:1px solid rgba(74,222,128,0.18);flex-shrink:0;transition:background 0.15s;" onmouseenter="this.style.background='rgba(74,222,128,0.2)'" onmouseleave="this.style.background='rgba(74,222,128,0.08)'">${_svgCheck}</span>` : ''
        const editBtn = `<span onclick="event.stopPropagation();openCotizacionModal('${n.id}')" title="Editar" style="display:inline-flex;align-items:center;justify-content:center;color:#fb923c;cursor:pointer;width:26px;height:26px;border-radius:7px;background:rgba(251,146,60,0.08);border:1px solid rgba(251,146,60,0.18);flex-shrink:0;transition:background 0.15s;" onmouseenter="this.style.background='rgba(251,146,60,0.2)'" onmouseleave="this.style.background='rgba(251,146,60,0.08)'">${_svgEdit}</span>`
        return amt + statusBadge + quickBtns + editBtn
      })() : ''}
      <span onclick="event.stopPropagation();if(confirm('¿Eliminar?')){deleteNode('${n.id}')}" title="Eliminar" style="display:inline-flex;align-items:center;justify-content:center;color:var(--text-dim);cursor:pointer;width:26px;height:26px;border-radius:7px;flex-shrink:0;opacity:0.4;transition:opacity 0.15s,background 0.15s,color 0.15s;" onmouseenter="this.style.opacity=1;this.style.color='#f87171';this.style.background='rgba(248,113,113,0.1)'" onmouseleave="this.style.opacity=0.4;this.style.color='var(--text-dim)';this.style.background='transparent'">${_svgX}</span>
    </div>`
}

function renderFeed(nodes) {
  const root = document.getElementById('feed-root')
  if (!root) return

  // Stats del feed
  const total = allNodes.length
  const counts = {}
  TYPE_FILTERS.forEach(f => { counts[f.type] = allNodes.filter(n=>n.type===f.type).length })

  // Barra de filtros tipo tabla dinámica
  const filterBar = `
    <div style="margin-bottom:16px;">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:10px;">
        <span style="font-size:10px;font-weight:800;color:var(--text-muted);letter-spacing:1px;">FILTRAR</span>
        <button onclick="clearFilter()" style="border:1px solid ${!activeTypeFilter&&!currentFilter?'var(--accent-cyan)':'var(--glass-border)'};background:${!activeTypeFilter&&!currentFilter?'rgba(0,246,255,0.12)':'transparent'};color:${!activeTypeFilter&&!currentFilter?'var(--accent-cyan)':'var(--text-muted)'};border-radius:20px;padding:4px 12px;font-size:10px;font-weight:800;cursor:pointer;">
          TODOS <span style="opacity:0.6;">(${total})</span>
        </button>
        ${TYPE_FILTERS.filter(f=>counts[f.type]>0).map(f=>`
          <button onclick="setTypeFilter('${f.type}')" style="border:1px solid ${activeTypeFilter===f.type?f.color:'var(--glass-border)'};background:${activeTypeFilter===f.type?f.color+'22':'transparent'};color:${activeTypeFilter===f.type?f.color:'var(--text-muted)'};border-radius:20px;padding:4px 12px;font-size:10px;font-weight:800;cursor:pointer;transition:all 0.15s;">
            ${f.label} <span style="opacity:0.6;">(${counts[f.type]})</span>
          </button>`).join('')}
        <button onclick="toggleFeedGroup()" style="margin-left:auto;border:1px solid ${feedGrouped?'var(--accent-cyan)':'var(--glass-border)'};background:${feedGrouped?'rgba(0,246,255,0.1)':'transparent'};color:${feedGrouped?'var(--accent-cyan)':'var(--text-muted)'};border-radius:20px;padding:4px 12px;font-size:10px;font-weight:800;cursor:pointer;display:inline-flex;align-items:center;gap:5px;transition:all 0.15s;" title="Agrupar por tipo">
          ${lx(feedGrouped?'Layers':'List', 11)} ${feedGrouped?'Agrupado':'Agrupar'}
        </button>
      </div>
      ${currentFilter?`<div style="display:flex;align-items:center;gap:8px;background:rgba(0,246,255,0.06);border:1px solid rgba(0,246,255,0.2);border-radius:10px;padding:8px 14px;font-size:12px;color:var(--accent-cyan);">
        ${lx('Search',13)} <span>Buscando: <b>${currentFilter}</b></span>
        <button onclick="clearFilter()" style="margin-left:auto;display:inline-flex;align-items:center;gap:4px;color:var(--text-muted);background:transparent;border:none;cursor:pointer;font-size:11px;padding:2px 6px;border-radius:5px;transition:color 0.15s;" onmouseenter="this.style.color='#f87171'" onmouseleave="this.style.color='var(--text-muted)'">${lx('X',10)} Limpiar</button>
      </div>`:''}
    </div>`

  if (nodes.length === 0) {
    root.innerHTML = filterBar + nxEmptyState({
      img: '/empty/no-search.svg',
      title: 'Sin resultados',
      sub: 'Prueba otro filtro o escribe algo en el panel de comandos',
      cta: `<button onclick="clearSearch?.()" style="margin-top:4px;padding:8px 18px;border-radius:8px;background:rgba(0,240,255,0.1);border:1px solid rgba(0,240,255,0.25);color:var(--accent-cyan);font-size:12px;font-weight:600;cursor:pointer;">${lx('RefreshCw',13)} Limpiar filtros</button>`
    })
    return
  }

  let content = ''
  if (feedGrouped) {
    // Agrupar por tipo
    const groups = {}
    nodes.forEach(n => { if (!groups[n.type]) groups[n.type] = []; groups[n.type].push(n) })
    content = Object.entries(groups).map(([type, items]) => {
      const f = TYPE_FILTERS.find(f=>f.type===type)
      return `
        <div style="margin-bottom:24px;">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid var(--glass-border);">
            <span style="font-size:10px;font-weight:800;color:${f?.color||'var(--accent-cyan)'};letter-spacing:1.5px;">${f?.label||type.toUpperCase()}</span>
            <span style="font-size:10px;color:var(--text-dim);background:var(--glass-border);border-radius:10px;padding:1px 8px;">${items.length}</span>
          </div>
          ${items.map(feedItemHtml).join('')}
        </div>`
    }).join('')
  } else {
    // Agrupar por FECHA: Hoy / Ayer / Esta semana / Este mes / Antes
    const now   = new Date()
    const todayStr     = now.toDateString()
    const yesterdayStr = new Date(now - 86400000).toDateString()
    const thisWeekStart  = new Date(now); thisWeekStart.setDate(now.getDate() - now.getDay())
    const thisMonthStart = new Date(now.getFullYear(), now.getMonth(), 1)
    function _feedDateGroup(n) {
      const d = new Date(n.created_at || n.timestamp || 0)
      const ds = d.toDateString()
      if (ds === todayStr)     return 'Hoy'
      if (ds === yesterdayStr) return 'Ayer'
      if (d >= thisWeekStart)  return 'Esta semana'
      if (d >= thisMonthStart) return 'Este mes'
      return 'Antes'
    }
    const ORDER = ['Hoy','Ayer','Esta semana','Este mes','Antes']
    const grps = {}
    nodes.forEach(n => { const g = _feedDateGroup(n); (grps[g] ??= []).push(n) })
    content = ORDER.filter(g => grps[g]?.length).map(g =>
      `<div class="feed-date-header">${g} <span style="color:var(--text-dim);font-size:10px;font-weight:600;">(${grps[g].length})</span></div>${grps[g].map(feedItemHtml).join('')}`
    ).join('')
  }

  root.innerHTML = filterBar + content

  // Scroll to top when a new optimistic node appears
  if (nodes.some(n => n._optimistic)) {
    const feedSection = document.getElementById('view-feed')
    if (feedSection?.classList.contains('active')) root.scrollTop = 0
  }
}

window.deleteNode = async (id) => {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  if (node.type === 'proyecto') {
    openDeleteProjectModal(id)
    return
  }
  if (!confirm('¿Eliminar este elemento?')) return
  if (localStorage.getItem('nexus_admin_bypass') === 'true') {
    allNodes = allNodes.filter(n => n.id !== id)
  } else {
    await supabase.from('nodes').delete().eq('id', id)
    allNodes = allNodes.filter(n => n.id !== id)
  }
  renderAll()
}

let _deletingProjectId = null

window.openDeleteProjectModal = (id) => {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  _deletingProjectId = id
  const slug = node.metadata?.project_slug || (node.metadata?.label || node.content).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]/g,'')
  const projectName = node.metadata?.label || node.content || 'Proyecto'

  // Count linked nodes
  const linked = allNodes.filter(n => n.id !== id && (
    n.metadata?.project_tag === slug ||
    (n.metadata?.tags || []).includes('#' + slug)
  ))
  const counts = { kanban: 0, expense: 0, income: 0, note: 0, cotizacion: 0, other: 0 }
  linked.forEach(n => {
    if (counts[n.type] !== undefined) counts[n.type]++
    else counts.other++
  })
  const parts = []
  if (counts.kanban)    parts.push(`<strong>${counts.kanban}</strong> tarea${counts.kanban>1?'s':''}`)
  if (counts.expense)   parts.push(`<strong>${counts.expense}</strong> gasto${counts.expense>1?'s':''}`)
  if (counts.income)    parts.push(`<strong>${counts.income}</strong> ingreso${counts.income>1?'s':''}`)
  if (counts.cotizacion)parts.push(`<strong>${counts.cotizacion}</strong> cotización${counts.cotizacion>1?'es':''}`)
  if (counts.note)      parts.push(`<strong>${counts.note}</strong> nota${counts.note>1?'s':''}`)
  if (counts.other)     parts.push(`<strong>${counts.other}</strong> elemento${counts.other>1?'s':''}`)

  const impactHtml = parts.length
    ? `<div style="background:rgba(251,146,60,0.08);border:1px solid rgba(251,146,60,0.2);border-radius:8px;padding:10px 14px;margin:10px 0;font-size:12px;color:var(--text-muted);">
        Tiene ${parts.join(', ')} vinculados.
       </div>`
    : `<div style="font-size:12px;color:var(--text-dim);margin:8px 0;">No hay elementos vinculados a este proyecto.</div>`

  document.getElementById('pdm-body').innerHTML = `
    <span>¿Qué deseas hacer con el proyecto <strong style="color:var(--text-main);">${esc(projectName)}</strong>?</span>
    ${impactHtml}
  `
  document.getElementById('project-delete-modal').classList.remove('hidden')
}

window.closeProjectDeleteModal = () => {
  document.getElementById('project-delete-modal').classList.add('hidden')
  _deletingProjectId = null
}

window.executeProjectDelete = async (mode) => {
  const id = _deletingProjectId
  if (!id) return
  const node = allNodes.find(n => n.id === id)
  if (!node) { closeProjectDeleteModal(); return }
  const slug = node.metadata?.project_slug || (node.metadata?.label || node.content).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]/g,'')
  const isDemo = localStorage.getItem('nexus_admin_bypass') === 'true'
  const linked = allNodes.filter(n => n.id !== id && (
    n.metadata?.project_tag === slug ||
    (n.metadata?.tags || []).includes('#' + slug)
  ))

  if (mode === 'archive') {
    // Archive — set archived flag, keep data
    node.metadata = { ...(node.metadata || {}), archived: true }
    if (!isDemo) await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
    showToast('📦 Proyecto archivado.')
  } else if (mode === 'project-only') {
    // Delete only the project node
    if (!isDemo) await supabase.from('nodes').delete().eq('id', id)
    allNodes = allNodes.filter(n => n.id !== id)
    showToast('🗂 Proyecto eliminado. Los elementos vinculados permanecen.')
  } else if (mode === 'all') {
    // Delete project + all linked nodes
    const idsToDelete = [id, ...linked.map(n => n.id)]
    if (!isDemo) {
      for (const did of idsToDelete) {
        await supabase.from('nodes').delete().eq('id', did)
      }
    }
    allNodes = allNodes.filter(n => !idsToDelete.includes(n.id))
    showToast(`🗑 Proyecto y ${linked.length} elemento${linked.length!==1?'s':''} eliminados.`)
  }
  closeProjectDeleteModal()
  renderAll()
}

window.changeNodeType = async (id, newType) => {
  const node = allNodes.find(n => n.id === id)
  if (node) {
    node.type = newType
    if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
      await supabase.from('nodes').update({ type: newType }).eq('id', id)
    }
    renderAll()
  }
}

// ── Full-page note editor builder ─────────────────────────────────────────────
function _buildNoteEditorHTML(id) {
  const node = allNodes.find(n => n.id === id)
  if (!node) return '<p style="color:var(--text-dim);">Nota no encontrada</p>'
  const m = node.metadata || {}
  const title = m.label || node.content.replace(/<[^>]+>/g,' ').trim()
  const color = m.color || ''
  const colorStyle = NOTE_COLORS[color] || ''
  const isPinned = m.pinned
  const tags = (m.tags || [])
  const hasReminder = !!m.reminder

  return `
  <div style="max-width:900px;margin:0 auto;animation:fadeIn .25s;">
    <!-- Back button -->
    <button onclick="closeNoteEditor()" style="display:inline-flex;align-items:center;gap:6px;background:none;border:none;color:var(--accent-cyan);cursor:pointer;font-size:13px;font-weight:700;padding:8px 0;margin-bottom:16px;letter-spacing:.03em;">
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>
      Volver a Bóveda Neural
    </button>

    <!-- Header card -->
    <div style="${colorStyle};background:${colorStyle ? '' : 'rgba(255,255,255,0.02)'};border:1px solid var(--glass-border);border-radius:16px;padding:24px 28px;margin-bottom:20px;">
      <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:16px;">
        <div style="display:flex;align-items:center;gap:10px;flex:1;">
          <span style="font-size:24px;">📝</span>
          <input type="text" id="nfp-title" value="${esc(title)}" placeholder="Título de la nota"
            style="flex:1;background:none;border:none;color:var(--text-main);font-size:20px;font-weight:800;outline:none;font-family:inherit;letter-spacing:-.02em;" />
        </div>
        <div style="display:flex;align-items:center;gap:6px;">
          <button onclick="toggleNotePin_fp('${id}')" class="btn-ghost" style="font-size:12px;padding:5px 10px;" title="${isPinned ? 'Desfijar' : 'Fijar'}">
            ${isPinned ? '📌 Fijada' : '📌 Fijar'}
          </button>
          <button onclick="archiveNote_fp('${id}')" class="btn-ghost" style="font-size:12px;padding:5px 10px;" title="Archivar">📦 Archivar</button>
        </div>
      </div>

      <!-- Tags -->
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
        <label style="font-size:11px;color:var(--text-dim);font-weight:700;letter-spacing:.05em;">ETIQUETAS</label>
        <input type="text" id="nfp-tags" value="${esc(tags.join(' '))}" placeholder="#idea #proyecto #importante"
          style="flex:1;background:rgba(255,255,255,0.03);border:1px solid var(--glass-border);border-radius:8px;padding:5px 10px;color:var(--text-primary);font-size:12px;outline:none;" />
      </div>

      <!-- Color -->
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
        <label style="font-size:11px;color:var(--text-dim);font-weight:700;letter-spacing:.05em;">COLOR</label>
        <div style="display:flex;gap:4px;">
          ${Object.keys(NOTE_COLORS).filter(c => c).map(c => `
            <div onclick="setNoteColor_fp('${id}','${c}')" style="${NOTE_COLORS[c]} width:20px;height:20px;border-radius:50%;border:2px solid ${color===c?'white':'transparent'};cursor:pointer;display:inline-block;box-sizing:border-box;transition:border-color .15s;"></div>
          `).join('')}
          <div onclick="setNoteColor_fp('${id}','')" style="width:20px;height:20px;border-radius:50%;border:2px solid ${color===''?'white':'rgba(255,255,255,0.2)'};cursor:pointer;display:inline-block;background:transparent;"></div>
        </div>
      </div>

      <!-- Reminder -->
      <div style="display:flex;align-items:center;gap:8px;">
        <label style="font-size:11px;color:var(--text-dim);font-weight:700;letter-spacing:.05em;">🔔 RECORDATORIO</label>
        <input type="date" id="nfp-reminder-date" value="${m.reminder ? m.reminder.split('T')[0] : ''}"
          style="background:rgba(255,255,255,0.03);border:1px solid var(--glass-border);border-radius:8px;padding:5px 10px;color:var(--text-primary);font-size:12px;outline:none;" />
        <input type="time" id="nfp-reminder-time" value="${m.reminder ? (m.reminder.split('T')[1]||'').slice(0,5) : '09:00'}"
          style="background:rgba(255,255,255,0.03);border:1px solid var(--glass-border);border-radius:8px;padding:5px 10px;color:var(--text-primary);font-size:12px;outline:none;width:100px;" />
        ${hasReminder ? `<button onclick="document.getElementById('nfp-reminder-date').value='';document.getElementById('nfp-reminder-time').value='09:00'" class="btn-ghost" style="font-size:10px;padding:3px 8px;">✕ Quitar</button>` : ''}
      </div>
    </div>

    <!-- Editor area -->
    <div style="background:rgba(255,255,255,0.02);border:1px solid var(--glass-border);border-radius:16px;overflow:hidden;margin-bottom:20px;display:flex;flex-direction:column;min-height:400px;">
      <div id="nfp-toolbar"></div>
      <textarea id="nfp-body" style="display:none;">${node.content || ''}</textarea>
    </div>

    <!-- Attachments -->
    <div style="background:rgba(255,255,255,0.02);border:1px solid var(--glass-border);border-radius:16px;padding:20px 24px;margin-bottom:20px;">
      <label style="font-size:11px;color:var(--text-dim);font-weight:700;letter-spacing:.08em;text-transform:uppercase;display:block;margin-bottom:10px;">📎 Adjuntos</label>
      <div id="nfp-attachments" style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px;"></div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;">
        <label style="cursor:pointer;background:rgba(255,255,255,0.05);border:1px dashed var(--glass-border);border-radius:10px;padding:8px 14px;font-size:12px;color:var(--text-muted);display:inline-block;">
          📎 Imagen / PDF
          <input type="file" accept="image/*,.pdf,application/pdf" style="display:none;" onchange="attachImageFromFile(this, 'nfp')" />
        </label>
        <button onclick="addAttachmentUrl('nfp')" style="background:rgba(255,255,255,0.05);border:1px dashed var(--glass-border);border-radius:10px;padding:8px 14px;font-size:12px;color:var(--text-muted);cursor:pointer;">🔗 Agregar link</button>
      </div>
    </div>

    <!-- Actions bar -->
    <div style="display:flex;align-items:center;gap:10px;justify-content:space-between;flex-wrap:wrap;padding:16px 0;">
      <div style="display:flex;gap:8px;">
        <button onclick="exportNote_fp('print')" class="btn-ghost" style="font-size:12px;padding:7px 14px;display:flex;align-items:center;gap:5px;">🖨️ Imprimir</button>
        <button onclick="exportNote_fp('markdown')" class="btn-ghost" style="font-size:12px;padding:7px 14px;display:flex;align-items:center;gap:5px;">📋 Copiar MD</button>
      </div>
      <div style="display:flex;gap:8px;">
        <button onclick="deleteNote_fp('${id}')" class="btn-danger" style="font-size:12px;padding:7px 18px;">🗑 Eliminar</button>
        <button onclick="saveNote_fp('${id}')" class="btn-primary" style="font-size:13px;padding:9px 28px;font-weight:800;">💾 Guardar</button>
      </div>
    </div>
  </div>`
}

// ── Full-page note actions ──────────────────────────────────────────────────
window.openNoteFullPage = function(id) {
  _noteProfileId = id
  _notesMode = 'editor'
  editingNoteId = id
  renderNotes(allNodes)
}

window.closeNoteEditor = function() {
  // Clean up nfp-body editor
  if (_richEditors['nfp-body']) {
    const ed = _richEditors['nfp-body']
    if (ed._slashMenu) ed._slashMenu.remove()
    if (ed._selBar) ed._selBar.remove()
    delete _richEditors['nfp-body']
  }
  _notesMode = 'grid'
  _noteProfileId = null
  editingNoteId = null
  renderNotes(allNodes)
  document.getElementById('notes-root')?.scrollIntoView({ behavior:'smooth', block:'start' })
}

window.saveNote_fp = async function(id) {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  const title = (document.getElementById('nfp-title')?.value || '').trim()
  const richEditor = _richEditors['nfp-body']
  const body = richEditor ? richEditor.innerHTML : (document.getElementById('nfp-body')?.value || '').trim()
  const tagsRaw = document.getElementById('nfp-tags')?.value || ''
  const tags = tagsRaw.split(/\s+/).filter(t => t.startsWith('#'))
  const rdVal = document.getElementById('nfp-reminder-date')?.value || ''
  const rtVal = document.getElementById('nfp-reminder-time')?.value || '09:00'
  const reminder = rdVal ? `${rdVal}T${rtVal}` : null

  node.content = body
  node.metadata = { ...(node.metadata||{}), label: title, tags }
  if (reminder) node.metadata.reminder = reminder
  else delete node.metadata.reminder

  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ content: body, metadata: node.metadata }).eq('id', id)
  }
  showToast('✅ Nota guardada')
  // Re-render the editor with updated data
  renderNotes(allNodes)
}

window.deleteNote_fp = async function(id) {
  if (!confirm('¿Eliminar esta nota? Esta acción es irreversible.')) return
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').delete().eq('id', id)
  }
  allNodes = allNodes.filter(n => n.id !== id)
  showToast('🗑 Nota eliminada')
  closeNoteEditor()
  renderAll()
}

window.archiveNote_fp = async function(id) {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), archived: true }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  showToast('📦 Nota archivada')
  closeNoteEditor()
  renderAll()
}

window.toggleNotePin_fp = async function(id) {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), pinned: !node.metadata?.pinned }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  showToast(node.metadata.pinned ? '📌 Nota fijada' : '📌 Nota desfijada')
  renderNotes(allNodes)
}

window.setNoteColor_fp = async function(id, color) {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), color }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  renderNotes(allNodes)
}

window.exportNote_fp = function(mode) {
  const node = allNodes.find(n => n.id === _noteProfileId)
  if (!node) return
  const title = document.getElementById('nfp-title')?.value || node.metadata?.label || node.content
  const richEditor = _richEditors['nfp-body']
  const body = richEditor ? richEditor.innerHTML : (document.getElementById('nfp-body')?.value || '')

  if (mode === 'print') {
    const w = window.open('', '_blank')
    w.document.write(`<!DOCTYPE html><html><head><title>${esc(title)}</title>
      <style>
        *, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }
        body { font-family:'Georgia','Times New Roman',serif; max-width:680px; margin:48px auto; color:#111; line-height:1.8; font-size:15px; background:#fff; }
        .doc-title { font-size:26px; font-weight:700; margin-bottom:4px; color:#000; }
        .doc-meta { font-size:12px; color:#888; margin-bottom:32px; padding-bottom:16px; border-bottom:1px solid #e5e5e5; }
        .doc-body h1 { font-size:2em; font-weight:700; margin:.6em 0 .2em; line-height:1.2; }
        .doc-body h2 { font-size:1.45em; font-weight:700; margin:.5em 0 .2em; line-height:1.3; }
        .doc-body h3 { font-size:1.15em; font-weight:700; margin:.4em 0 .15em; line-height:1.4; }
        .doc-body p  { margin:.3em 0; min-height:1.4em; }
        .doc-body blockquote { border-left:3px solid #888; padding-left:16px; margin:.6em 0; color:#555; font-style:italic; }
        .doc-body ul, .doc-body ol { padding-left:22px; margin:.4em 0; }
        .doc-body li { margin:.15em 0; }
        .doc-body hr { border:none; border-top:1px solid #ddd; margin:1.4em 0; }
        .doc-body a  { color:#0066cc; text-decoration:underline; }
        .doc-body code { font-family:'Courier New',monospace; font-size:0.88em; background:#f5f5f5; padding:1px 5px; border-radius:3px; }
        @media print { body { margin:24px; } }
      </style>
    </head><body>
      <div class="doc-title">${esc(title)}</div>
      <div class="doc-meta">Nexus OS · ${new Date().toLocaleDateString('es-MX',{year:'numeric',month:'long',day:'numeric'})}</div>
      <div class="doc-body">${body}</div>
    </body></html>`)
    w.document.close()
    w.focus()
    setTimeout(() => w.print(), 500)
  } else if (mode === 'markdown') {
    const md = `# ${title}\n\n${body.replace(/<[^>]+>/g,'')}`
    navigator.clipboard.writeText(md).then(() => showToast('✅ Copiado como Markdown')).catch(() => showToast('✅ Copiado'))
  }
}

function renderNotes(nodes) {
  const root = document.getElementById('notes-root')
  if (!root) return

  // ── Full-page editor mode ──────────────────────────────
  if (_notesMode === 'editor' && _noteProfileId) {
    root.style.display = 'block'
    root.className = ''
    root.innerHTML = _buildNoteEditorHTML(_noteProfileId)
    // Initialize rich editor after DOM is ready
    setTimeout(() => {
      const node = allNodes.find(n => n.id === _noteProfileId)
      if (!node) return
      // Destroy old nfp-body editor if exists
      if (_richEditors['nfp-body']) {
        const old = _richEditors['nfp-body']
        if (old._slashMenu) old._slashMenu.remove()
        if (old._selBar) old._selBar.remove()
        old.parentElement?.remove()
        delete _richEditors['nfp-body']
      }
      buildNoteBlockEditor('nfp-body', 'nfp-toolbar')
      syncRichEditor('nfp-body')
      // Render attachments
      renderAttachments(node.metadata?.images || [], 'nfp')
    }, 50)
    // Hide archived section when in editor mode
    const archSec = document.getElementById('notes-archived-section')
    if (archSec) archSec.style.display = 'none'
    return
  }

  // ── Grid mode (default) ────────────────────────────────
  root.style.display = ''
  root.className = 'notes-grid'

  const notes = nodes
    .filter(n => {
      if (n.type !== 'note') return false
      if (n.metadata?.project_tag) return false
      if (n.metadata?.archived) return false
      return true
    })
    .sort((a, b) => (b.metadata?.pinned ? 1 : 0) - (a.metadata?.pinned ? 1 : 0))

  if (notes.length === 0) {
    root.innerHTML = nxEmptyState({
      img: '/empty/no-notes.svg',
      title: 'Bóveda Neural vacía',
      sub: 'Escribe tu primer pensamiento en el panel de comandos o usa el atajo rápido',
      cta: `<button onclick="document.getElementById('cmd-input')?.focus()" style="margin-top:4px;padding:8px 18px;border-radius:8px;background:rgba(0,240,255,0.1);border:1px solid rgba(0,240,255,0.25);color:var(--accent-cyan);font-size:12px;font-weight:600;cursor:pointer;">${lx('Plus',13)} Nueva nota</button>`
    })
    if (_showArchivedNotes) _renderArchivedNotes()
    return
  }

  root.innerHTML = notes.map(n => {
    const color = n.metadata?.color || ''
    const colorStyle = NOTE_COLORS[color] || ''
    const isPinned = n.metadata?.pinned
    const hasReminder = !!n.metadata?.reminder
    const ntc = TYPE_CONFIG[n.type] || { color:'var(--accent-cyan)', label:`#${n.type.toUpperCase()}` }
    const _svgPin = `<svg width="11" height="11" viewBox="0 0 24 24" fill="${isPinned?'currentColor':'none'}" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="17" x2="12" y2="22"/><path d="M5 17h14v-1.76a2 2 0 0 0-1.11-1.79l-1.78-.9A2 2 0 0 1 15 10.76V6h1a2 2 0 0 0 0-4H8a2 2 0 0 0 0 4h1v4.76a2 2 0 0 1-1.11 1.79l-1.78.9A2 2 0 0 0 5 15.24V17z"/></svg>`
    const isSelected = _selectedNoteIds.has(n.id)
    const selectCb = _noteSelectionMode ? `
      <span class="note-select-cb" onclick="event.stopPropagation();toggleNoteSelect('${n.id}')"
        style="position:absolute;top:8px;right:8px;width:18px;height:18px;border-radius:50%;border:2px solid var(--accent-cyan);background:${isSelected?'var(--accent-cyan)':'transparent'};display:flex;align-items:center;justify-content:center;cursor:pointer;transition:all 0.15s;z-index:2;">
        ${isSelected?'<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#000" stroke-width="3"><polyline points="20 6 9 17 4 12"/></svg>':''}
      </span>` : ''
    const reminderBadge = hasReminder ? `<span style="display:inline-flex;align-items:center;gap:3px;font-size:9px;color:#fb923c;background:rgba(251,146,60,0.1);padding:1px 6px;border-radius:4px;"><svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg>${n.metadata.reminder.replace('T',' ').slice(0,16)}</span>` : ''
    return `
    <div class="note-keep" data-nid="${n.id}" style="${colorStyle};position:relative;${isSelected?'outline:2px solid var(--accent-cyan);':''}"
         onclick="${_noteSelectionMode?`toggleNoteSelect('${n.id}')`:`openNoteEdit('${n.id}')`}"
         title="${_noteSelectionMode?'Clic para seleccionar':'Clic para editar'}">
      ${selectCb}
      <div class="note-keep-inner">
        <div style="display:flex; justify-content:space-between; align-items:center; flex-shrink:0;">
          <span style="display:inline-flex;align-items:center;gap:3px;font-size:9px;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:${ntc.color};background:${ntc.color}18;padding:2px 7px;border-radius:4px;"><span style="width:4px;height:4px;border-radius:50%;background:${ntc.color};flex-shrink:0;"></span>${ntc.label}</span>
          ${_noteSelectionMode ? '' : `<span title="${isPinned ? 'Desfijar' : 'Fijar'}"
                onclick="event.stopPropagation(); togglePin('${n.id}')"
                style="display:inline-flex;align-items:center;justify-content:center;cursor:pointer;color:${isPinned?'#fb923c':'var(--text-dim)'};opacity:${isPinned?'1':'0.35'};width:22px;height:22px;border-radius:5px;${isPinned?'background:rgba(251,146,60,0.1);':''}">${_svgPin}</span>`}
        </div>
        <div class="note-keep-title">${esc(n.metadata?.label || n.content.replace(/<[^>]+>/g,' ').trim())}</div>
        <div class="note-keep-body">${esc(n.content.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim())}</div>
        ${reminderBadge ? `<div style="margin-top:4px;">${reminderBadge}</div>` : ''}
        <div style="display:flex; gap:4px; flex-wrap:wrap; flex-shrink:0;">
          ${(n.metadata?.tags || []).map(t => `<span class="tag-pill" onclick="event.stopPropagation(); setFilter('${t}')" style="background:var(--accent-cyan-dim); color:var(--accent-cyan); font-size:9px; padding:1px 5px; border-radius:4px; cursor:pointer;">${t}</span>`).join('')}
        </div>
        ${_noteSelectionMode ? '' : `<div class="note-color-bar" onclick="event.stopPropagation()">
          ${Object.keys(NOTE_COLORS).filter(c=>c).map(c=>`
            <div title="${c}" onclick="setNoteColor('${n.id}','${c}')" style="${NOTE_COLORS[c]} width:14px; height:14px; border-radius:50%; border:2px solid ${color===c?'white':'transparent'}; cursor:pointer; display:inline-block; box-sizing:border-box;"></div>
          `).join('')}
          <div title="Sin color" onclick="setNoteColor('${n.id}','')" style="width:14px; height:14px; border-radius:50%; border:2px solid ${color===''?'white':'rgba(255,255,255,0.2)'}; cursor:pointer; display:inline-block; background:transparent;"></div>
        </div>`}
      </div>
    </div>
  `}).join('')
  // Re-render archived if visible
  if (_showArchivedNotes) _renderArchivedNotes()
}

window.togglePin = async (id) => {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), pinned: !node.metadata?.pinned }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  renderAll()
}

window.setNoteColor = async (id, color) => {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), color }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  renderAll()
}

// ── Rich text editor builder ─────────────────────────────────────────────────
const _richEditors = {}

// ── Gutenberg-style block editor for notes ────────────────────────────────────
function buildNoteBlockEditor(textareaId, toolbarContainerId) {
  const textarea = document.getElementById(textareaId)
  if (!textarea || _richEditors[textareaId]) return
  const toolbarEl = document.getElementById(toolbarContainerId)
  if (!toolbarEl) return

  // ── Inject document styles once ──────────────────────────
  if (!document.getElementById('nexus-block-editor-style')) {
    const style = document.createElement('style')
    style.id = 'nexus-block-editor-style'
    style.textContent = `
      .nbe-wrap { border:1px solid var(--glass-border); border-top:none; border-radius:0 0 10px 10px; background:rgba(255,255,255,0.02); overflow-y:auto; flex:1; min-height:260px; display:flex; flex-direction:column; }
      .nbe { flex:1; outline:none; padding:28px 40px; font-family:'Georgia','Times New Roman',serif; font-size:15px; line-height:1.85; color:var(--text-primary); caret-color:var(--accent-cyan); min-height:220px; }
      .nbe:empty::before { content:attr(data-placeholder); color:rgba(255,255,255,0.18); pointer-events:none; font-style:italic; }
      .nbe h1 { font-size:2em; font-weight:700; margin:.5em 0 .15em; line-height:1.2; color:var(--text-main); font-family:inherit; }
      .nbe h2 { font-size:1.5em; font-weight:700; margin:.4em 0 .15em; line-height:1.3; color:var(--text-main); font-family:inherit; }
      .nbe h3 { font-size:1.15em; font-weight:700; margin:.3em 0 .1em; line-height:1.4; color:var(--text-main); font-family:inherit; }
      .nbe p  { margin:.15em 0; min-height:1.85em; }
      .nbe blockquote { border-left:3px solid var(--accent-cyan); padding:6px 0 6px 16px; margin:.5em 0; color:var(--text-muted); font-style:italic; }
      .nbe ul, .nbe ol { padding-left:22px; margin:.3em 0; }
      .nbe li { margin:.1em 0; }
      .nbe hr { border:none; border-top:1px solid rgba(255,255,255,0.1); margin:1.2em 0; }
      .nbe a  { color:var(--accent-cyan); text-decoration:underline; }
      .nbe code { font-family:'JetBrains Mono',monospace; font-size:0.88em; background:rgba(255,255,255,0.08); padding:1px 5px; border-radius:4px; }
      .nbe-toolbar { display:flex; align-items:center; gap:2px; flex-wrap:wrap; padding:5px 8px; background:rgba(255,255,255,0.03); border:1px solid var(--glass-border); border-bottom:1px solid rgba(255,255,255,0.04); border-radius:8px 8px 0 0; }
      .nbe-btn { min-width:26px; height:26px; padding:0 5px; border-radius:5px; background:rgba(255,255,255,0.05); border:1px solid rgba(255,255,255,0.09); color:var(--text-muted); cursor:pointer; font-size:11px; font-family:inherit; display:inline-flex; align-items:center; justify-content:center; gap:2px; white-space:nowrap; transition:background .15s; }
      .nbe-btn:hover { background:rgba(0,246,255,0.1); color:var(--accent-cyan); border-color:rgba(0,246,255,0.25); }
      .nbe-btn.active { background:rgba(0,246,255,0.15); color:var(--accent-cyan); border-color:rgba(0,246,255,0.3); }
      .nbe-sep { width:1px; height:18px; background:rgba(255,255,255,0.1); margin:0 3px; flex-shrink:0; }
      .nbe-slash-menu { display:none; position:fixed; z-index:9999; background:#1a1e2e; border:1px solid rgba(0,246,255,0.25); border-radius:10px; padding:6px; min-width:230px; box-shadow:0 10px 40px rgba(0,0,0,0.6); }
      .nbe-slash-item { display:flex; align-items:center; gap:10px; padding:7px 10px; border-radius:7px; cursor:pointer; transition:background .12s; }
      .nbe-slash-item:hover, .nbe-slash-item.selected { background:rgba(0,246,255,0.09); }
      .nbe-slash-icon { width:30px; height:30px; border-radius:7px; background:rgba(255,255,255,0.06); border:1px solid rgba(255,255,255,0.1); display:grid; place-items:center; font-size:11px; font-weight:700; color:var(--text-muted); flex-shrink:0; }
      .nbe-sel-toolbar { display:none; position:fixed; z-index:9999; background:#1a1e2e; border:1px solid rgba(0,246,255,0.2); border-radius:8px; padding:4px 5px; gap:2px; box-shadow:0 4px 20px rgba(0,0,0,0.5); align-items:center; }
      .nbe-sel-btn { width:24px; height:24px; border-radius:4px; background:rgba(255,255,255,0.05); border:none; color:var(--text-muted); cursor:pointer; font-size:11px; font-family:inherit; display:grid; place-items:center; }
      .nbe-sel-btn:hover { background:rgba(0,246,255,0.12); color:var(--accent-cyan); }
    `
    document.head.appendChild(style)
  }

  // ── Toolbar ───────────────────────────────────────────────
  toolbarEl.className = 'nbe-toolbar'
  toolbarEl.innerHTML = ''

  // Block type selector removed (H1/H2/H3 incompatible with Tailwind Preflight)
  // Users prefer the font-size selector (XS/Sm/Md/Lg/XL/2X/3X) which works reliably

  const sep0 = document.createElement('div'); sep0.className = 'nbe-sep'; toolbarEl.appendChild(sep0)

  // ── Font size select ─────────────────────────────────────
  const FONT_SIZES = [
    { val:'1', label:'XS' },
    { val:'2', label:'Sm' },
    { val:'3', label:'Md' },
    { val:'4', label:'Lg' },
    { val:'5', label:'XL' },
    { val:'6', label:'2X' },
    { val:'7', label:'3X' },
  ]
  const sizeSel = document.createElement('select')
  sizeSel.className = 'nbe-btn'
  sizeSel.title = 'Tamaño de texto'
  sizeSel.style.cssText = 'padding:0 5px;font-size:11px;cursor:pointer;height:26px;min-width:auto;width:auto;border-radius:5px;'
  FONT_SIZES.forEach(o => {
    const opt = document.createElement('option')
    opt.value = o.val; opt.textContent = o.label
    if (o.val === '3') opt.selected = true
    sizeSel.appendChild(opt)
  })
  sizeSel.addEventListener('change', () => {
    editor.focus()
    document.execCommand('styleWithCSS', false, false)
    document.execCommand('fontSize', false, sizeSel.value)
  })
  toolbarEl.appendChild(sizeSel)

  const sepSz = document.createElement('div'); sepSz.className = 'nbe-sep'; toolbarEl.appendChild(sepSz)

  // ── Text color picker ────────────────────────────────────
  const colorPicker = document.createElement('input')
  colorPicker.type = 'color'
  colorPicker.value = '#00f0ff'
  colorPicker.title = 'Color de texto'
  colorPicker.style.cssText = 'width:26px;height:26px;padding:1px;border-radius:5px;border:1px solid rgba(255,255,255,0.09);background:rgba(255,255,255,0.05);cursor:pointer;'
  colorPicker.addEventListener('input', () => {
    editor.focus()
    document.execCommand('foreColor', false, colorPicker.value)
  })
  // Wrap in button-like div
  const colorWrap = document.createElement('div')
  colorWrap.title = 'Color de texto'
  colorWrap.style.cssText = 'display:inline-flex;align-items:center;justify-content:center;width:26px;height:26px;position:relative;cursor:pointer;'
  colorWrap.innerHTML = `<span style="font-size:11px;position:absolute;bottom:0;left:50%;transform:translateX(-50%);line-height:1;pointer-events:none;">A</span>`
  colorWrap.appendChild(colorPicker)
  colorPicker.style.cssText = 'width:26px;height:26px;opacity:0;position:absolute;inset:0;cursor:pointer;'
  const colorDisp = document.createElement('div')
  colorDisp.style.cssText = 'width:26px;height:26px;border-radius:5px;border:1px solid rgba(255,255,255,0.09);background:rgba(255,255,255,0.05);display:flex;align-items:center;justify-content:center;cursor:pointer;font-size:11px;font-weight:700;color:#fff;position:relative;overflow:hidden;'
  colorDisp.title = 'Color de texto'
  colorDisp.innerHTML = `<span style="font-size:11px;font-weight:900;color:${colorPicker.value}">A</span>`
  colorPicker.addEventListener('input', () => {
    colorDisp.querySelector('span').style.color = colorPicker.value
  })
  colorPicker.addEventListener('change', () => {
    editor.focus()
    document.execCommand('foreColor', false, colorPicker.value)
    colorDisp.querySelector('span').style.color = colorPicker.value
  })
  colorDisp.appendChild(colorPicker)
  toolbarEl.appendChild(colorDisp)

  // ── Highlight/background color picker ────────────────────
  const hlPicker = document.createElement('input')
  hlPicker.type = 'color'
  hlPicker.value = '#fbbf24'
  hlPicker.title = 'Resaltar texto'
  const hlDisp = document.createElement('div')
  hlDisp.title = 'Resaltar texto'
  hlDisp.style.cssText = 'width:26px;height:26px;border-radius:5px;border:1px solid rgba(255,255,255,0.09);background:rgba(255,255,255,0.05);display:flex;align-items:center;justify-content:center;cursor:pointer;font-size:11px;font-weight:700;position:relative;overflow:hidden;'
  hlDisp.innerHTML = `<span style="font-size:11px;font-weight:900;background:${hlPicker.value};padding:0 2px;border-radius:2px;">M</span>`
  hlPicker.style.cssText = 'width:26px;height:26px;opacity:0;position:absolute;inset:0;cursor:pointer;'
  hlPicker.addEventListener('change', () => {
    editor.focus()
    document.execCommand('hiliteColor', false, hlPicker.value)
    hlDisp.querySelector('span').style.background = hlPicker.value
  })
  hlDisp.appendChild(hlPicker)
  toolbarEl.appendChild(hlDisp)

  const sepColor = document.createElement('div'); sepColor.className = 'nbe-sep'; toolbarEl.appendChild(sepColor)

  const INLINE = [
    { cmd:'bold',              html:'<b>B</b>',        title:'Negrita (Ctrl+B)' },
    { cmd:'italic',            html:'<i>I</i>',        title:'Cursiva (Ctrl+I)' },
    { cmd:'underline',         html:'<u>U</u>',        title:'Subrayado (Ctrl+U)' },
    { cmd:'strikeThrough',     html:'<s>S</s>',        title:'Tachado' },
    { sep: true },
    { cmd:'insertUnorderedList', html:'• ≡',           title:'Lista de viñetas' },
    { cmd:'insertOrderedList',   html:'1. ≡',          title:'Lista numerada' },
    { sep: true },
    { cmd:'insertHorizontalRule', html:'— —',          title:'Separador horizontal' },
    { sep: true },
    { cmd:'createLink',        html:'🔗',              title:'Hipervínculo', prompt:'URL del enlace:' },
    { sep: true },
    { cmd:'removeFormat',      html:'🧹',              title:'Limpiar formato de selección' },
  ]
  INLINE.forEach(t => {
    if (t.sep) { const s = document.createElement('div'); s.className = 'nbe-sep'; toolbarEl.appendChild(s); return }
    const btn = document.createElement('button')
    btn.type = 'button'; btn.className = 'nbe-btn'; btn.title = t.title; btn.innerHTML = t.html
    btn.addEventListener('mousedown', e => {
      e.preventDefault(); editor.focus()
      if (t.prompt) { const v = prompt(t.prompt); if (v) document.execCommand(t.cmd, false, v) }
      else document.execCommand(t.cmd, false, null)
    })
    toolbarEl.appendChild(btn)
  })

  function syncBlockTypeSelect() { /* no-op — block selector removed */ }

  // ── Editor container ──────────────────────────────────────
  const wrap = document.createElement('div'); wrap.className = 'nbe-wrap'
  const editor = document.createElement('div')
  editor.className = 'nbe'; editor.contentEditable = 'true'
  editor.setAttribute('data-placeholder', 'Escribe algo... o usa / para insertar un bloque')
  editor.innerHTML = textarea.value || ''
  wrap.appendChild(editor)

  textarea.style.display = 'none'
  textarea.parentNode.insertBefore(toolbarEl, textarea)
  textarea.parentNode.insertBefore(wrap, textarea.nextSibling)
  _richEditors[textareaId] = editor

  // ── Slash command menu ────────────────────────────────────
  const slashMenu = document.createElement('div'); slashMenu.className = 'nbe-slash-menu'
  const SLASH_ITEMS = [
    { type:'p',           icon:'¶',   label:'Párrafo',         desc:'Texto normal' },
    { type:'blockquote',  icon:'"',   label:'Cita',            desc:'Texto destacado en bloque' },
    { type:'ul',          icon:'•',   label:'Lista viñetas',   desc:'Lista con puntos' },
    { type:'ol',          icon:'1.',  label:'Lista numerada',  desc:'Lista con números' },
    { type:'hr',          icon:'—',   label:'Separador',       desc:'Línea horizontal divisoria' },
  ]
  let slashActive = false
  SLASH_ITEMS.forEach((item, i) => {
    const row = document.createElement('div'); row.className = 'nbe-slash-item'; row.dataset.idx = i
    row.innerHTML = `<div class="nbe-slash-icon">${item.icon}</div><div><div style="font-size:13px;color:var(--text-main);font-weight:600;">${item.label}</div><div style="font-size:11px;color:var(--text-dim);">${item.desc}</div></div>`
    row.addEventListener('mousedown', e => {
      e.preventDefault()
      applySlashType(item.type)
    })
    slashMenu.appendChild(row)
  })
  document.body.appendChild(slashMenu)

  function showSlashMenu() {
    const sel = window.getSelection()
    if (!sel?.rangeCount) return
    const rect = sel.getRangeAt(0).getBoundingClientRect()
    slashMenu.style.display = 'block'
    const menuH = 280
    const spaceBelow = window.innerHeight - rect.bottom - 10
    slashMenu.style.top = spaceBelow > menuH ? (rect.bottom + 4) + 'px' : (rect.top - menuH - 4) + 'px'
    slashMenu.style.left = Math.min(rect.left, window.innerWidth - 250) + 'px'
    slashActive = true
  }
  function hideSlashMenu() { slashMenu.style.display = 'none'; slashActive = false }

  function applySlashType(type) {
    hideSlashMenu()
    editor.focus()
    // Remove the '/' that triggered the menu
    const sel = window.getSelection()
    if (sel?.rangeCount) {
      const range = sel.getRangeAt(0)
      const node = range.startContainer
      if (node.nodeType === Node.TEXT_NODE && node.textContent.startsWith('/')) {
        node.textContent = node.textContent.slice(1)
        range.setStart(node, 0); range.collapse(true)
        sel.removeAllRanges(); sel.addRange(range)
      }
    }
    if (type === 'ul') document.execCommand('insertUnorderedList', false, null)
    else if (type === 'ol') document.execCommand('insertOrderedList', false, null)
    else if (type === 'hr') document.execCommand('insertHorizontalRule', false, null)
    else document.execCommand('formatBlock', false, `<${type}>`)
    textarea.value = editor.innerHTML
    syncBlockTypeSelect()
  }

  // ── Floating selection toolbar ────────────────────────────
  const selBar = document.createElement('div'); selBar.className = 'nbe-sel-toolbar'
  const SEL_BTNS = [
    { cmd:'bold',      html:'<b>B</b>' },
    { cmd:'italic',    html:'<i>I</i>' },
    { cmd:'underline', html:'<u>U</u>' },
    { cmd:'strikeThrough', html:'<s>S</s>' },
    { sep:true },
    { cmd:'createLink', html:'🔗', prompt:'URL:' },
    { cmd:'unlink',     html:'<span style="font-size:10px;">✕🔗</span>', title:'Quitar enlace' },
  ]
  SEL_BTNS.forEach(t => {
    if (t.sep) { const s = document.createElement('div'); s.className='nbe-sep'; selBar.appendChild(s); return }
    const btn = document.createElement('button'); btn.type='button'; btn.className='nbe-sel-btn'; btn.innerHTML=t.html; if(t.title) btn.title=t.title
    btn.addEventListener('mousedown', e => {
      e.preventDefault()
      if (t.prompt) { const v = prompt(t.prompt); if (v) document.execCommand(t.cmd, false, v) }
      else document.execCommand(t.cmd, false, null)
    })
    selBar.appendChild(btn)
  })
  document.body.appendChild(selBar)

  let _selTimer
  function updateSelBar() {
    clearTimeout(_selTimer)
    _selTimer = setTimeout(() => {
      const sel = window.getSelection()
      if (sel && !sel.isCollapsed && sel.toString().trim().length && editor.contains(sel.anchorNode)) {
        const rect = sel.getRangeAt(0).getBoundingClientRect()
        selBar.style.display = 'flex'
        selBar.style.left = rect.left + 'px'
        selBar.style.top  = (rect.top - 42) + 'px'
      } else {
        selBar.style.display = 'none'
      }
    }, 60)
  }

  editor.addEventListener('mouseup', updateSelBar)
  editor.addEventListener('keyup',   updateSelBar)

  document.addEventListener('selectionchange', () => {
    const sel = window.getSelection()
    if (!sel || sel.isCollapsed || !editor.contains(sel.anchorNode)) {
      clearTimeout(_selTimer); _selTimer = setTimeout(() => { selBar.style.display = 'none' }, 200)
    }
  })

  // ── Input & keyboard handlers ─────────────────────────────
  editor.addEventListener('input', () => {
    textarea.value = editor.innerHTML
    syncBlockTypeSelect()
    // Slash detection
    const sel = window.getSelection()
    if (!sel?.rangeCount) return
    const node = sel.getRangeAt(0).startContainer
    if (node.nodeType === Node.TEXT_NODE && node.textContent === '/') showSlashMenu()
    else if (slashActive && !node.textContent?.startsWith('/')) hideSlashMenu()
  })

  editor.addEventListener('keydown', e => {
    if (e.key === 'Escape' && slashActive) { hideSlashMenu(); e.preventDefault(); return }
    textarea.value = editor.innerHTML
    syncBlockTypeSelect()
  })

  editor.addEventListener('focus', () => syncBlockTypeSelect())
  editor.addEventListener('blur',  () => { textarea.value = editor.innerHTML; hideSlashMenu(); selBar.style.display = 'none' })

  // ── Paste as plain text by default ──────────────────────
  editor.addEventListener('paste', e => {
    e.preventDefault()
    const text = (e.clipboardData || window.clipboardData).getData('text/plain')
    // Insert plain text at cursor position
    const sel = window.getSelection()
    if (sel?.rangeCount) {
      const range = sel.getRangeAt(0)
      range.deleteContents()
      // Split text by newlines and insert as paragraphs
      const lines = text.split(/\r?\n/)
      const frag = document.createDocumentFragment()
      lines.forEach((line, i) => {
        frag.appendChild(document.createTextNode(line))
        if (i < lines.length - 1) frag.appendChild(document.createElement('br'))
      })
      range.insertNode(frag)
      // Move cursor to end of inserted content
      range.collapse(false)
      sel.removeAllRanges()
      sel.addRange(range)
    }
    textarea.value = editor.innerHTML
  })

  // Store refs for cleanup
  editor._slashMenu = slashMenu
  editor._selBar = selBar
}

function buildRichEditor(textareaId, toolbarContainerId) {
  const textarea = document.getElementById(textareaId)
  if (!textarea || _richEditors[textareaId]) return
  // Create toolbar
  const toolbar = document.getElementById(toolbarContainerId)
  if (!toolbar) return
  const TOOLS = [
    { cmd:'bold',        icon:'<b>B</b>',    title:'Negrita (Ctrl+B)' },
    { cmd:'italic',      icon:'<i>I</i>',    title:'Cursiva (Ctrl+I)' },
    { cmd:'underline',   icon:'<u>U</u>',    title:'Subrayado (Ctrl+U)' },
    { cmd:'strikeThrough',icon:'<s>S</s>',   title:'Tachado' },
    { sep: true },
    { cmd:'insertUnorderedList', icon:'≡',   title:'Lista con viñetas' },
    { cmd:'insertOrderedList',   icon:'⊟',   title:'Lista numerada' },
    { sep: true },
    { cmd:'foreColor',   icon:'A',   title:'Color de texto', type:'color' },
    { cmd:'hiliteColor', icon:'✱',   title:'Resaltar', type:'color', color:'#fbbf24' },
    { sep: true },
    { cmd:'createLink',  icon:'🔗',  title:'Hipervínculo', type:'prompt', prompt:'URL del enlace:' },
    { cmd:'insertImage', icon:'📷',  title:'Imagen (URL)', type:'prompt', prompt:'URL de la imagen:' },
  ]
  toolbar.style.cssText = 'display:flex;align-items:center;gap:4px;flex-wrap:wrap;padding:6px 8px;background:rgba(255,255,255,0.03);border:1px solid var(--glass-border);border-radius:8px 8px 0 0;border-bottom:none;'
  TOOLS.forEach(t => {
    if (t.sep) {
      const sep = document.createElement('div')
      sep.style.cssText = 'width:1px;height:18px;background:rgba(255,255,255,0.1);margin:0 2px;'
      toolbar.appendChild(sep)
      return
    }
    if (t.type === 'color') {
      const wrap = document.createElement('div')
      wrap.style.cssText = 'position:relative;display:inline-flex;align-items:center;'
      const lbl = document.createElement('label')
      lbl.title = t.title
      lbl.style.cssText = 'width:26px;height:26px;border-radius:5px;background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);cursor:pointer;display:grid;place-items:center;font-size:12px;font-family:inherit;'
      lbl.innerHTML = t.icon
      const inp = document.createElement('input')
      inp.type = 'color'
      inp.value = t.color || '#ffffff'
      inp.style.cssText = 'position:absolute;opacity:0;width:100%;height:100%;cursor:pointer;'
      inp.addEventListener('input', () => { editor.focus(); document.execCommand(t.cmd, false, inp.value) })
      lbl.appendChild(inp)
      wrap.appendChild(lbl)
      toolbar.appendChild(wrap)
    } else {
      const btn = document.createElement('button')
      btn.type = 'button'
      btn.title = t.title
      btn.innerHTML = t.icon
      btn.style.cssText = 'width:26px;height:26px;border-radius:5px;background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);color:var(--text-muted);cursor:pointer;font-size:12px;font-family:inherit;display:grid;place-items:center;'
      btn.addEventListener('mousedown', (e) => {
        e.preventDefault()
        editor.focus()
        if (t.type === 'prompt') {
          const val = prompt(t.prompt)
          if (val) document.execCommand(t.cmd, false, val)
        } else {
          document.execCommand(t.cmd, false, null)
        }
      })
      toolbar.appendChild(btn)
    }
  })
  // Create contenteditable editor
  const editor = document.createElement('div')
  editor.contentEditable = 'true'
  editor.style.cssText = textarea.style.cssText || ''
  editor.style.cssText += ';min-height:120px;outline:none;padding:10px 12px;background:var(--bg-panel);border:1px solid var(--glass-border);border-radius:0 0 8px 8px;color:var(--text-primary);font-size:14px;line-height:1.6;overflow-y:auto;'
  editor.innerHTML = textarea.value || ''
  // Sync editor → textarea on every input
  editor.addEventListener('input', () => { textarea.value = editor.innerHTML })
  editor.addEventListener('blur', () => { textarea.value = editor.innerHTML })
  // Insert editor after textarea, hide textarea
  textarea.style.display = 'none'
  textarea.parentNode.insertBefore(toolbar, textarea)
  textarea.parentNode.insertBefore(editor, textarea.nextSibling)
  _richEditors[textareaId] = editor
}

function syncRichEditor(textareaId) {
  const editor = _richEditors[textareaId]
  const textarea = document.getElementById(textareaId)
  if (editor && textarea) editor.innerHTML = textarea.value || ''
}

window.openNoteEdit = (id) => {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  if (node.type === 'kanban') { openCardModal(id); return }
  if (node.type === 'income' || node.type === 'expense' || node.type === 'bill' || node.type === 'subscription') { openFinanceDetail(id); return }
  if (node.type === 'cotizacion') { openCotizacionDetail(id); return }
  // Open full-page editor instead of modal
  openNoteFullPage(id)
}

window.closeNoteModal = () => {
  // Always remove fullscreen before hiding to avoid broken state on reopen
  const modalBox = document.querySelector('#note-edit-modal .modal-box')
  if (modalBox) modalBox.classList.remove('fullscreen')
  const fsBtn = document.getElementById('note-toggle-size')
  if (fsBtn) fsBtn.textContent = '⤢'
  document.getElementById('note-edit-modal').classList.add('hidden')
  const panel = document.getElementById('transform-panel')
  if (panel) panel.style.display = 'none'
  pendingTransformType = null
  editingNoteId = null
}

// Toggle note editor between normal and fullscreen modes
function toggleNoteSize() {
  const modalBox = document.querySelector('#note-edit-modal .modal-box')
  if (!modalBox) return
  const isFs = modalBox.classList.toggle('fullscreen')
  const btn = document.getElementById('note-toggle-size')
  if (btn) btn.textContent = isFs ? '⤡' : '⤢'
  if (!isFs) {
    modalBox.style.display = ''
    modalBox.style.flexDirection = ''
  }
}
window.toggleNoteSize = toggleNoteSize;

// ── Note: clear reminder ──────────────────────────────────────────────────────
window.clearNoteReminder = () => {
  const rdEl = document.getElementById('ne-reminder-date')
  const rtEl = document.getElementById('ne-reminder-time')
  const rcBtn = document.getElementById('ne-reminder-clear')
  if (rdEl) rdEl.value = ''
  if (rtEl) rtEl.value = '09:00'
  if (rcBtn) rcBtn.style.display = 'none'
}

// ── Note: archive ─────────────────────────────────────────────────────────────
window.archiveNote = async () => {
  const id = editingNoteId
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), archived: true }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  closeNoteModal()
  showToast('📦 Nota archivada.')
  renderAll()
}

// ── Note: unarchive ───────────────────────────────────────────────────────────
window.unarchiveNote = async (id) => {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...(node.metadata || {}), archived: false }
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  showToast('📤 Nota restaurada.')
  renderAll()
}

// ── Note: export (print / markdown) ──────────────────────────────────────────
window.exportNote = (mode) => {
  const node = allNodes.find(n => n.id === editingNoteId)
  if (!node) return
  const title = document.getElementById('ne-title')?.value || node.metadata?.label || node.content
  const body  = document.getElementById('ne-body')?.value  || node.content

  if (mode === 'print') {
    // Get the rich HTML from the block editor if available, else fall back to textarea
    const editorEl = _richEditors['ne-body']
    const richHtml = editorEl ? editorEl.innerHTML : body.replace(/\n/g, '<br>')
    const w = window.open('', '_blank')
    w.document.write(`<!DOCTYPE html><html><head><title>${esc(title)}</title>
      <style>
        *, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }
        body { font-family:'Georgia','Times New Roman',serif; max-width:680px; margin:48px auto; color:#111; line-height:1.8; font-size:15px; background:#fff; }
        .doc-title { font-size:26px; font-weight:700; margin-bottom:4px; color:#000; }
        .doc-meta { font-size:12px; color:#888; margin-bottom:32px; padding-bottom:16px; border-bottom:1px solid #e5e5e5; }
        .doc-body h1 { font-size:2em; font-weight:700; margin:.6em 0 .2em; line-height:1.2; }
        .doc-body h2 { font-size:1.45em; font-weight:700; margin:.5em 0 .2em; line-height:1.3; }
        .doc-body h3 { font-size:1.15em; font-weight:700; margin:.4em 0 .15em; line-height:1.4; }
        .doc-body p  { margin:.3em 0; min-height:1.4em; }
        .doc-body blockquote { border-left:3px solid #888; padding-left:16px; margin:.6em 0; color:#555; font-style:italic; }
        .doc-body ul, .doc-body ol { padding-left:22px; margin:.4em 0; }
        .doc-body li { margin:.15em 0; }
        .doc-body hr { border:none; border-top:1px solid #ddd; margin:1.4em 0; }
        .doc-body a  { color:#0066cc; text-decoration:underline; }
        .doc-body code { font-family:'Courier New',monospace; font-size:0.88em; background:#f5f5f5; padding:1px 5px; border-radius:3px; }
        .doc-body b, .doc-body strong { font-weight:700; }
        .doc-body i, .doc-body em { font-style:italic; }
        @media print { body { margin:24px; } }
      </style>
    </head><body>
      <div class="doc-title">${esc(title)}</div>
      <div class="doc-meta">Nexus OS · ${new Date().toLocaleDateString('es-MX',{year:'numeric',month:'long',day:'numeric'})}</div>
      <div class="doc-body">${richHtml}</div>
    </body></html>`)
    w.document.close()
    w.focus()
    setTimeout(() => w.print(), 500)
  } else if (mode === 'markdown') {
    const md = `# ${title}\n\n${body}`
    navigator.clipboard.writeText(md).then(() => {
      showToast('✅ Copiado como Markdown')
    }).catch(() => {
      // fallback
      const ta = document.createElement('textarea')
      ta.value = md
      document.body.appendChild(ta)
      ta.select()
      document.execCommand('copy')
      document.body.removeChild(ta)
      showToast('✅ Copiado como Markdown')
    })
  }
}

// ── Note multi-select state ───────────────────────────────────────────────────
let _noteSelectionMode = false
let _selectedNoteIds = new Set()
let _showArchivedNotes = false

window.toggleNoteSelectionMode = () => {
  _noteSelectionMode = !_noteSelectionMode
  _selectedNoteIds.clear()
  const bar = document.getElementById('notes-selection-bar')
  const btn = document.getElementById('notes-select-toggle')
  if (_noteSelectionMode) {
    if (bar) bar.style.display = 'flex'
    if (btn) { btn.style.background = 'rgba(99,102,241,0.2)'; btn.style.color = 'var(--accent-cyan)' }
  } else {
    if (bar) bar.style.display = 'none'
    if (btn) { btn.style.background = ''; btn.style.color = '' }
  }
  renderAll()
}

window.toggleArchivedNotes = () => {
  _showArchivedNotes = !_showArchivedNotes
  const sec = document.getElementById('notes-archived-section')
  const btn = document.getElementById('notes-archive-toggle')
  if (sec) sec.style.display = _showArchivedNotes ? 'block' : 'none'
  if (btn) { btn.style.background = _showArchivedNotes ? 'rgba(99,102,241,0.15)' : ''; btn.style.color = _showArchivedNotes ? 'var(--accent-cyan)' : '' }
  if (_showArchivedNotes) _renderArchivedNotes()
}

function _renderArchivedNotes() {
  const root = document.getElementById('notes-archived-root')
  if (!root) return
  const archived = allNodes.filter(n => n.type === 'note' && n.metadata?.archived)
  if (!archived.length) { root.innerHTML = '<p style="font-size:12px;color:var(--text-dim);padding:12px 0;">No hay notas archivadas.</p>'; return }
  root.innerHTML = archived.map(n => {
    const color = n.metadata?.color || ''
    const colorStyle = NOTE_COLORS[color] || ''
    return `
    <div class="note-keep" style="${colorStyle};opacity:0.65;" title="Nota archivada">
      <div class="note-keep-inner">
        <div class="note-keep-title" style="margin-bottom:6px;">${esc(n.metadata?.label || n.content.replace(/<[^>]+>/g,' ').trim())}</div>
        <div class="note-keep-body">${esc(n.content.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim())}</div>
        <div style="display:flex;gap:6px;margin-top:8px;">
          <button onclick="unarchiveNote('${n.id}')" class="btn-ghost" style="font-size:10px;padding:3px 8px;">📤 Restaurar</button>
          <button onclick="openNoteEdit('${n.id}')" class="btn-ghost" style="font-size:10px;padding:3px 8px;">✏️ Editar</button>
        </div>
      </div>
    </div>`
  }).join('')
}

window.toggleNoteSelect = (id) => {
  if (!_noteSelectionMode) return
  if (_selectedNoteIds.has(id)) _selectedNoteIds.delete(id)
  else _selectedNoteIds.add(id)
  // Update count badge
  const countEl = document.getElementById('notes-selection-count')
  if (countEl) countEl.textContent = `${_selectedNoteIds.size} seleccionada${_selectedNoteIds.size!==1?'s':''}`
  // Refresh cards UI without full re-render
  document.querySelectorAll('.note-keep[data-nid]').forEach(el => {
    const nid = el.getAttribute('data-nid')
    const cb = el.querySelector('.note-select-cb')
    const isSelected = _selectedNoteIds.has(nid)
    if (cb) cb.style.opacity = isSelected ? '1' : ''
    el.style.outline = isSelected ? '2px solid var(--accent-cyan)' : ''
  })
}

window.actionSelectedNotes = async (action) => {
  if (!_selectedNoteIds.size) { showToast('Selecciona al menos una nota.'); return }
  const ids = [..._selectedNoteIds]
  const isDemo = localStorage.getItem('nexus_admin_bypass') === 'true'

  if (action === 'delete') {
    if (!confirm(`¿Eliminar ${ids.length} nota${ids.length>1?'s':''}? Esta acción es irreversible.`)) return
    for (const id of ids) {
      if (!isDemo) await supabase.from('nodes').delete().eq('id', id)
      allNodes = allNodes.filter(n => n.id !== id)
    }
    showToast(`🗑 ${ids.length} nota${ids.length>1?'s':''} eliminada${ids.length>1?'s':''}.`)
  } else if (action === 'archive') {
    for (const id of ids) {
      const node = allNodes.find(n => n.id === id)
      if (!node) continue
      node.metadata = { ...(node.metadata || {}), archived: true }
      if (!isDemo) await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
    }
    showToast(`📦 ${ids.length} nota${ids.length>1?'s':''} archivada${ids.length>1?'s':''}.`)
  } else if (action === 'color') {
    const colors = Object.keys(NOTE_COLORS).filter(c => c)
    const color = colors[Math.floor(Math.random() * colors.length)]
    for (const id of ids) {
      const node = allNodes.find(n => n.id === id)
      if (!node) continue
      node.metadata = { ...(node.metadata || {}), color }
      if (!isDemo) await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
    }
    showToast(`🎨 Color aplicado a ${ids.length} nota${ids.length>1?'s':''}.`)
  }
  _selectedNoteIds.clear()
  _noteSelectionMode = false
  const bar = document.getElementById('notes-selection-bar')
  const btn = document.getElementById('notes-select-toggle')
  if (bar) bar.style.display = 'none'
  if (btn) { btn.style.background = ''; btn.style.color = '' }
  renderAll()
}


document.getElementById('ne-save')?.addEventListener('click', async () => {
  const node = allNodes.find(n => n.id === editingNoteId)
  if (!node) return
  const title = document.getElementById('ne-title').value.trim()
  // Use rich editor HTML if available, otherwise fall back to textarea
  const richEditor = _richEditors['ne-body']
  const body = richEditor ? richEditor.innerHTML : (document.getElementById('ne-body')?.value || '').trim()
  const tagsRaw = document.getElementById('ne-tags')?.value || ''
  const tags = tagsRaw.split(/\s+/).filter(t => t.startsWith('#'))
  // Reminder
  const rdVal = document.getElementById('ne-reminder-date')?.value || ''
  const rtVal = document.getElementById('ne-reminder-time')?.value || '09:00'
  const reminder = rdVal ? `${rdVal}T${rtVal}` : null
  node.content = body
  node.metadata = { ...(node.metadata||{}), label: title, tags }
  if (reminder) node.metadata.reminder = reminder
  else delete node.metadata.reminder
  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ content: body, metadata: node.metadata }).eq('id', editingNoteId)
  }
  closeNoteModal()
  renderAll()
})

document.getElementById('ne-delete')?.addEventListener('click', async () => {
  const node = allNodes.find(n => n.id === editingNoteId)
  if (!node) return
  if (node.type === 'proyecto') {
    closeNoteModal()
    openDeleteProjectModal(node.id)
    return
  }
  if (!confirm('¿Eliminar esta nota?')) return
  if (localStorage.getItem('nexus_admin_bypass') === 'true') {
    allNodes = allNodes.filter(n => n.id !== editingNoteId)
  } else {
    await supabase.from('nodes').delete().eq('id', editingNoteId)
    allNodes = allNodes.filter(n => n.id !== editingNoteId)
  }
  closeNoteModal()
  renderAll()
})

window.showTransformPanel = (targetType) => {
  pendingTransformType = targetType
  const panel = document.getElementById('transform-panel')
  const amtInput = document.getElementById('tp-amount')
  const dateInput = document.getElementById('tp-date')
  if (!panel) return
  panel.style.display = 'flex'
  amtInput.style.display = (targetType === 'income' || targetType === 'expense') ? 'block' : 'none'
  dateInput.style.display = (targetType === 'calendar') ? 'block' : 'none'
  if (targetType === 'calendar') dateInput.value = new Date().toISOString().split('T')[0]
  if (targetType === 'kanban' || targetType === 'contact') confirmTransform()
}

window.confirmTransform = async () => {
  const id = editingNoteId
  const targetType = pendingTransformType
  const node = allNodes.find(n => n.id === id)
  if (!node || !targetType) return

  if (targetType === 'kanban') {
    node.type = 'kanban'
    node.metadata = { ...node.metadata, label: node.metadata?.label || node.content, status: 'todo' }
  } else if (targetType === 'income') {
    const amt = parseFloat(document.getElementById('tp-amount')?.value || '0')
    node.type = 'income'
    node.metadata = { ...node.metadata, amount: amt, label: node.metadata?.label || node.content }
  } else if (targetType === 'expense') {
    const amt = parseFloat(document.getElementById('tp-amount')?.value || '0')
    node.type = 'expense'
    node.metadata = { ...node.metadata, amount: amt, label: node.metadata?.label || node.content }
  } else if (targetType === 'calendar') {
    const date = document.getElementById('tp-date')?.value || new Date().toISOString().split('T')[0]
    node.type = 'kanban'
    node.metadata = { ...node.metadata, label: node.metadata?.label || node.content, due_date: date, status: 'todo' }
  } else if (targetType === 'contact') {
    const name = node.metadata?.label || node.metadata?.name || node.content
    node.type = 'contact'
    node.metadata = { ...node.metadata, cType: 'persona', name, label: name, color: node.metadata?.color || '#fdba74' }
  }

  if (localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ type: node.type, metadata: node.metadata }).eq('id', id)
  }
  pendingTransformType = null
  closeNoteModal()
  renderAll()
}

// ─────────────────────────────────────────
// Bio-Finanzas
// ─────────────────────────────────────────
function renderFinance(nodes) {
  const root = document.getElementById('finance-root')
  if (!root) return

  const accounts = nodes.filter(n => n.type === 'account')
  // Unified FinancialEngine
  const txs = getTransactions(nodes, activeAccount)
  const _initBalForCalc = (activeAccount !== 'all')
    ? (accounts.find(a => a.id === activeAccount)?.metadata?.balance || 0)
    : 0
  const { income, expense } = calcBalance(txs, _initBalForCalc)

  const accountTabsHtml = `
    <div class="fin-tabs" style="display:flex; gap:10px; flex-wrap:wrap; margin-bottom:20px;">
      <button class="fin-tab ${activeAccount==='all'?'fin-tab-active':''}" onclick="setActiveAccount('all')">Todas las Cuentas</button>
      ${accounts.map(a=>`
        <div style="display:inline-flex; align-items:center; gap:0; background:${activeAccount===a.id?'rgba(0,246,255,0.15)':'rgba(255,255,255,0.04)'}; border:1px solid ${activeAccount===a.id?'var(--accent-cyan)':'var(--glass-border)'}; border-radius:10px; overflow:hidden;">
          <button class="fin-tab" style="border:none; background:transparent; border-radius:0; padding:8px 12px;" onclick="setActiveAccount('${a.id}')">
            <span style="width:8px;height:8px;border-radius:50%;background:${esc(a.metadata?.color||'#4ade80')};display:inline-block;margin-right:6px;"></span>
            ${esc(a.metadata?.label||a.content)}
          </button>
          <button onclick="openAccountModal('${a.id}')" style="background:transparent; border:none; border-left:1px solid var(--glass-border); padding:8px 10px; cursor:pointer; color:var(--text-muted); font-size:13px;" title="Editar cuenta" onmouseover="this.style.color='var(--accent-cyan)'" onmouseout="this.style.color='var(--text-muted)'">✏️</button>
        </div>
      `).join('')}
      <button class="fin-tab" onclick="openAccountModal()" style="border-style:dashed;">+ Cuenta</button>
    </div>
  `

  const net = income - expense
  const activeAcc   = accounts.find(a => a.id === activeAccount)
  const initBalance = activeAccount !== 'all' ? (activeAcc?.metadata?.balance || 0) : 0
  const accBalance  = activeAccount !== 'all' ? initBalance + income - expense : net

  // ── Reactive finance-hero ──────────────────────────────────────
  const heroLabel = document.getElementById('dominance-label')
  const heroBalance = document.getElementById('dominance-balance')
  if (heroLabel && heroBalance) {
    if (activeAccount === 'all') {
      heroLabel.textContent = 'Balance Neto Consolidado'
      heroBalance.textContent = `$${net.toLocaleString('es-MX', {minimumFractionDigits:2, maximumFractionDigits:2})}`
    } else {
      const accName = activeAcc?.metadata?.label || activeAcc?.content || 'Cuenta'
      heroLabel.textContent = `Balance • ${accName}`
      heroBalance.textContent = `$${accBalance.toLocaleString('es-MX', {minimumFractionDigits:2, maximumFractionDigits:2})}`
    }
  }

  // ── DASHBOARD "TODAS LAS CUENTAS" ─────────────────────────────
  let statsHtml = ''
  if (activeAccount === 'all') {
    // Fila de tarjetas por cuenta (una por cada cuenta registrada)
    const allTxs = nodes.filter(n => n.type==='income'||n.type==='expense'||n.type==='loan')
    const accountCards = accounts.length > 0
      ? accounts.map(a => {
          const aInc  = allTxs.filter(n=>n.type==='income'  && n.metadata?.account_id===a.id).reduce((s,n)=>s+(n.metadata?.amount||0),0)
          const aExp  = allTxs.filter(n=>n.type==='expense' && n.metadata?.account_id===a.id).reduce((s,n)=>s+(n.metadata?.amount||0),0)
          const aInit = a.metadata?.balance || 0
          const aBal  = aInit + aInc - aExp
          const aClr  = a.metadata?.color || '#4ade80'
          const aBg   = aBal >= 0 ? `${aClr}12` : 'rgba(248,113,113,0.08)'
          const aBdr  = aBal >= 0 ? `${aClr}30` : 'rgba(248,113,113,0.25)'
          const aBalClr = aBal >= 0 ? aClr : '#f87171'
          return `<div onclick="setActiveAccount('${a.id}')" style="cursor:pointer;background:${aBg};border:1px solid ${aBdr};border-radius:14px;padding:16px 18px;transition:transform 0.15s;" onmouseover="this.style.transform='translateY(-2px)'" onmouseout="this.style.transform=''">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
              <span style="width:10px;height:10px;border-radius:50%;background:${aClr};flex-shrink:0;"></span>
              <span style="font-size:11px;font-weight:800;color:${aClr};letter-spacing:0.5px;">${esc(a.metadata?.label||a.content)}</span>
            </div>
            <div style="font-size:20px;font-weight:800;color:${aBalClr};font-family:'JetBrains Mono',monospace;margin-bottom:6px;">${aBal>=0?'+':''}\$${aBal.toLocaleString()}</div>
            <div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text-dim);">
              <span>↑ $${aInc.toLocaleString()}</span>
              <span>↓ $${aExp.toLocaleString()}</span>
            </div>
          </div>`
        }).join('')
      : `<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);padding:20px;font-size:12px;">Sin cuentas. Crea una con <b>+ Cuenta</b></div>`

    // Top 3 categorías de gasto (por tags)
    const tagTotals = {}
    allTxs.filter(n=>n.type==='expense').forEach(n => {
      ;(n.metadata?.tags||[]).forEach(t => {
        if (!tagTotals[t]) tagTotals[t] = 0
        tagTotals[t] += n.metadata?.amount || 0
      })
    })
    const topTags = Object.entries(tagTotals).sort((a,b)=>b[1]-a[1]).slice(0,3)
    const topTagsHtml = topTags.length > 0
      ? topTags.map(([tag, amt]) => `<div style="display:flex;justify-content:space-between;align-items:center;padding:5px 0;border-bottom:1px solid rgba(255,255,255,0.04);">
          <span style="font-size:11px;color:var(--text-muted);">${tag}</span>
          <span style="font-size:11px;font-weight:700;color:#f87171;font-family:'JetBrains Mono',monospace;">-$${amt.toLocaleString()}</span>
        </div>`).join('')
      : '<div style="font-size:11px;color:var(--text-dim);">Sin datos de categorías</div>'

    const consolidatedInc = allTxs.filter(n=>n.type==='income').reduce((s,n)=>s+(n.metadata?.amount||0),0)
    const consolidatedExp = allTxs.filter(n=>n.type==='expense').reduce((s,n)=>s+(n.metadata?.amount||0),0)
    const consolidatedNet = consolidatedInc - consolidatedExp
    const cNetClr = consolidatedNet >= 0 ? '#00f6ff' : '#fb923c'

    // ── SVG icons para Bio-Finanzas ───────────────────────────
    const FI = {
      inc:  `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg>`,
      exp:  `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><polyline points="23 18 13.5 8.5 8.5 13.5 1 6"/><polyline points="17 18 23 18 23 12"/></svg>`,
      net:  `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>`,
      card: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="2" y1="10" x2="22" y2="10"/></svg>`,
      tag:  `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M20.59 13.41l-7.17 7.17a2 2 0 01-2.83 0L2 12V2h10l8.59 8.59a2 2 0 010 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/></svg>`,
      list: `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>`,
      move: `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="1" y="3" width="7" height="7"/><rect x="1" y="14" width="7" height="7"/><line x1="21" y1="6" x2="9" y2="6"/><line x1="21" y1="17" x2="9" y2="17"/></svg>`,
    }
    const NX_KPI = (color) => `background:${color}0d;border:1px solid ${color}28;border-radius:14px;padding:16px;`
    const NX_LBL = (color) => `font-size:9px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;color:${color};margin-bottom:6px;display:flex;align-items:center;gap:6px;`
    const NX_VAL = (color) => `font-size:20px;font-weight:900;color:${color};font-family:'JetBrains Mono',monospace;line-height:1.1;`

    statsHtml = `
    <div style="margin-bottom:24px;">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="2"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="2" y1="10" x2="22" y2="10"/></svg>
        <span style="font-size:10px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;color:var(--text-muted);">Balance por cuenta</span>
        <span style="font-size:10px;color:var(--text-dim);margin-left:4px;">— clic para ver detalle</span>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:12px;margin-bottom:20px;">
        ${accountCards}
      </div>
      <div style="display:flex;gap:0;background:rgba(255,255,255,0.02);border:1px solid rgba(255,255,255,0.07);border-radius:14px;overflow:hidden;">
        <div style="flex:1;padding:16px 14px;border-right:1px solid rgba(255,255,255,0.06);">
          <div style="${NX_LBL('#4ade80')}"><span style="color:#4ade80;">${FI.inc}</span>Total ingresos</div>
          <div id="fin-kpi-income" style="${NX_VAL('#4ade80')}">+$${consolidatedInc.toLocaleString()}</div>
          <div style="font-size:10px;color:var(--text-dim);margin-top:4px;">${allTxs.filter(n=>n.type==='income').length} transacciones</div>
        </div>
        <div style="flex:1;padding:16px 14px;border-right:1px solid rgba(255,255,255,0.06);">
          <div style="${NX_LBL('#f87171')}"><span style="color:#f87171;">${FI.exp}</span>Total gastos</div>
          <div id="fin-kpi-expense" style="${NX_VAL('#f87171')}">-$${consolidatedExp.toLocaleString()}</div>
          <div style="font-size:10px;color:var(--text-dim);margin-top:4px;">${allTxs.filter(n=>n.type==='expense').length} transacciones</div>
        </div>
        <div style="flex:1;padding:16px 14px;">
          <div style="${NX_LBL(consolidatedNet>=0?'#2dd4bf':'#fb923c')}"><span style="color:${consolidatedNet>=0?'#2dd4bf':'#fb923c'};">${FI.net}</span>Neto consolidado</div>
          <div id="fin-kpi-net" style="${NX_VAL(consolidatedNet>=0?'#2dd4bf':'#fb923c')}">${consolidatedNet>=0?'+':''}\$${consolidatedNet.toLocaleString()}</div>
          <div style="font-size:10px;color:var(--text-dim);margin-top:4px;">${consolidatedNet>=0?'Flujo positivo':'Déficit acumulado'}</div>
        </div>
      </div>
      ${topTags.length > 0 ? `<div style="margin-top:14px;background:rgba(255,255,255,0.02);border:1px solid rgba(255,255,255,0.07);border-radius:12px;padding:14px 16px;">
        <div style="display:flex;align-items:center;gap:6px;font-size:10px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;color:var(--text-muted);margin-bottom:10px;">
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="2" stroke-linecap="round"><path d="M20.59 13.41l-7.17 7.17a2 2 0 01-2.83 0L2 12V2h10l8.59 8.59a2 2 0 010 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/></svg>
          Top categorías de gasto
        </div>
        ${topTagsHtml}
      </div>` : ''}
    </div>`

  } else {
    // ── DASHBOARD CUENTA ESPECÍFICA ────────────────────────────────
    const aClr = activeAcc?.metadata?.color || '#60a5fa'
    const txCount = txs.length
    const avgExp  = txs.filter(n=>n.type==='expense').length > 0
      ? expense / txs.filter(n=>n.type==='expense').length : 0
    const maxTx   = [...txs].sort((a,b)=>(b.metadata?.amount||0)-(a.metadata?.amount||0))[0]
    const balClr  = accBalance >= 0 ? aClr : '#f87171'
    const balBg   = accBalance >= 0 ? `${aClr}0d` : 'rgba(248,113,113,0.06)'
    const balBdr  = accBalance >= 0 ? `${aClr}30` : 'rgba(248,113,113,0.25)'

    const FI2 = {
      inc:  `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#4ade80" stroke-width="1.5" stroke-linecap="round"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg>`,
      exp:  `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#f87171" stroke-width="1.5" stroke-linecap="round"><polyline points="23 18 13.5 8.5 8.5 13.5 1 6"/><polyline points="17 18 23 18 23 12"/></svg>`,
      card: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="${balClr}" stroke-width="1.5" stroke-linecap="round"><rect x="2" y="5" width="20" height="14" rx="2"/><line x1="2" y1="10" x2="22" y2="10"/></svg>`,
      move: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#a78bfa" stroke-width="1.5" stroke-linecap="round"><rect x="1" y="3" width="7" height="7"/><rect x="1" y="14" width="7" height="7"/><line x1="21" y1="6" x2="9" y2="6"/><line x1="21" y1="17" x2="9" y2="17"/></svg>`,
    }
    const NX_LBL2 = (c) => `font-size:9px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;color:${c};margin-bottom:6px;display:flex;align-items:center;gap:6px;`
    const NX_VAL2 = (c) => `font-size:20px;font-weight:900;color:${c};font-family:'JetBrains Mono',monospace;line-height:1.1;`

    statsHtml = `
    <div style="display:flex;gap:0;background:rgba(255,255,255,0.02);border:1px solid rgba(255,255,255,0.07);border-radius:14px;overflow:hidden;margin-bottom:24px;">
      <div style="flex:1.2;padding:18px 16px;border-right:1px solid rgba(255,255,255,0.06);">
        <div style="${NX_LBL2(balClr)}">${FI2.card} Saldo actual</div>
        <div id="fin-kpi-net" style="${NX_VAL2(balClr)}">${accBalance>=0?'+':''}\$${accBalance.toLocaleString()}</div>
        <div style="font-size:10px;color:var(--text-dim);margin-top:4px;">Inicial: $${initBalance.toLocaleString()}</div>
      </div>
      <div style="flex:1;padding:18px 16px;border-right:1px solid rgba(255,255,255,0.06);">
        <div style="${NX_LBL2('#4ade80')}">${FI2.inc} Ingresos</div>
        <div id="fin-kpi-income" style="${NX_VAL2('#4ade80')}">+$${income.toLocaleString()}</div>
        <div style="font-size:10px;color:var(--text-dim);margin-top:4px;">${txs.filter(n=>n.type==='income').length} mov.</div>
      </div>
      <div style="flex:1;padding:18px 16px;border-right:1px solid rgba(255,255,255,0.06);">
        <div style="${NX_LBL2('#f87171')}">${FI2.exp} Gastos</div>
        <div id="fin-kpi-expense" style="${NX_VAL2('#f87171')}">-$${expense.toLocaleString()}</div>
        <div style="font-size:10px;color:var(--text-dim);margin-top:4px;">Prom: $${Math.round(avgExp).toLocaleString()}</div>
      </div>
      <div style="flex:1;padding:18px 16px;">
        <div style="${NX_LBL2('#a78bfa')}">${FI2.move} Movimientos</div>
        <div style="${NX_VAL2('#a78bfa')}">${txCount}</div>
        ${maxTx ? `<div style="font-size:10px;color:var(--text-dim);margin-top:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="Mayor: ${esc(maxTx.metadata?.label||maxTx.content)}">Mayor: $${(maxTx.metadata?.amount||0).toLocaleString()}</div>` : ''}
      </div>
    </div>`
  }

  // ── TRANSACTIONS TABLE ──────────────────────────────────────────────────────
  // Running balance — unified FinancialEngine
  const initBal = activeAccount !== 'all' ? (accounts.find(a=>a.id===activeAccount)?.metadata?.balance || 0) : 0
  const txsWithBalance = buildRunningBalance(txs, initBal)

  // Phase 1 · Quick filter (solo movimientos de cuenta)
  const _filterPills = [
    { key:'all',     label:'Todos',    icon:'⚡' },
    { key:'income',  label:'Ingresos', icon:'💰' },
    { key:'expense', label:'Gastos',   icon:'💸' },
  ]
  const _pillsHtml = _filterPills.map(p => {
    const active = finTxFilter === p.key
    return `<button onclick="setFinTxFilter('${p.key}')" style="font-size:11px;font-weight:700;padding:5px 13px;border-radius:20px;border:1px solid ${active?'var(--accent-cyan)':'rgba(255,255,255,0.1)'};background:${active?'rgba(0,246,255,0.15)':'rgba(255,255,255,0.04)'};color:${active?'var(--accent-cyan)':'var(--text-muted)'};cursor:pointer;transition:all 0.15s;">${p.icon} ${p.label}</button>`
  }).join('')

  // Apply filter
  const _filteredTxs = finTxFilter === 'income'  ? txsWithBalance.filter(t => t.type === 'income')
                     : finTxFilter === 'expense' ? txsWithBalance.filter(t => t.type === 'expense')
                     : txsWithBalance

  const txTableHtml = `
  <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;flex-wrap:wrap;gap:8px;">
    <div style="display:flex;align-items:center;gap:8px;">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="2" stroke-linecap="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>
      <span style="font-size:10px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;color:var(--text-muted);">Movimientos (${_filteredTxs.length})</span>
    </div>
    <div style="display:flex;gap:8px;flex-wrap:wrap;">
      <button onclick="window.printFinanceReport()" style="font-size:11px;background:rgba(96,165,250,0.1);border:1px solid rgba(96,165,250,0.3);color:#60a5fa;border-radius:7px;padding:5px 12px;cursor:pointer;font-weight:600;">🖨 Imprimir</button>
      <button onclick="openTransactionModal()" style="font-size:11px;background:rgba(0,246,255,0.1);border:1px solid rgba(0,246,255,0.3);color:var(--accent-cyan);border-radius:7px;padding:5px 12px;cursor:pointer;font-weight:600;">+ Movimiento</button>
    </div>
  </div>
  <div style="display:flex;gap:6px;margin-bottom:14px;flex-wrap:wrap;">${_pillsHtml}</div>
  <div style="overflow-x:auto;">
    <table id="finance-tx-table" style="width:100%;border-collapse:collapse;font-size:12px;">
      <thead>
        <tr style="background:rgba(255,255,255,0.04);">
          <th style="text-align:center;padding:8px 6px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);width:28px;"></th>
          <th style="text-align:left;padding:8px 10px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Fecha</th>
          <th style="text-align:left;padding:8px 10px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Concepto</th>
          <th style="text-align:left;padding:8px 10px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Cuenta</th>
          <th style="text-align:right;padding:8px 10px;color:#4ade80;font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Entrada</th>
          <th style="text-align:right;padding:8px 10px;color:#f87171;font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Salida</th>
          <th style="text-align:right;padding:8px 10px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Saldo</th>
          <th style="text-align:center;padding:8px 10px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);">Comprobante</th>
          <th style="text-align:center;padding:8px 10px;color:var(--text-muted);font-weight:700;border-bottom:1px solid rgba(255,255,255,0.08);"></th>
        </tr>
      </thead>
      <tbody>
      ${_filteredTxs.length === 0
        ? `<tr><td colspan="9" style="text-align:center;padding:32px;color:var(--text-dim);">Sin movimientos. Registra un ingreso o gasto.</td></tr>`
        : _filteredTxs.map(tx => {
            const m = tx.metadata || {}
            const isIncome = tx.type === 'income'
            const isExpense = tx.type === 'expense'
            const amt = m.amount || 0
            const rawDate = m.date || m.fecha || tx.created_at || ''
            const date = rawDate ? (() => { try { return new Date(rawDate.includes('T') ? rawDate : rawDate + 'T12:00:00').toLocaleDateString('es-MX',{day:'2-digit',month:'short',year:'2-digit'}) } catch(e){ return rawDate.slice(0,10) } })() : '—'
            const concept = m.description || m.label || tx.content || '—'
            const accountName = accounts.find(a=>a.id===m.account_id)?.metadata?.label || m.account_id || '—'
            const bal = tx._runningBalance
            const balClr = bal >= 0 ? '#4ade80' : '#f87171'
            const comprobante = m.comprobante_url || m.receipt_url || ''
            const tags = (m.tags||[]).join(' ')
            // Phase 1 · Semaphore badge
            const semaphore = isIncome ? '🟢' : isExpense ? '🔴' : '🟡'
            return `<tr style="border-bottom:1px solid rgba(255,255,255,0.04);transition:background 0.1s;" onmouseover="this.style.background='rgba(255,255,255,0.03)'" onmouseout="this.style.background=''">
              <td style="padding:8px 6px;text-align:center;font-size:13px;">${semaphore}</td>
              <td style="padding:8px 10px;color:var(--text-muted);white-space:nowrap;">${date}</td>
              <td style="padding:8px 10px;color:var(--text-primary);max-width:200px;">
                <div style="font-weight:600;">${esc(concept)}</div>
                ${tags ? `<div style="font-size:10px;color:var(--text-dim);margin-top:2px;">${esc(tags)}</div>` : ''}
              </td>
              <td style="padding:8px 10px;color:var(--text-muted);font-size:11px;white-space:nowrap;">${esc(accountName)}</td>
              <td style="padding:8px 10px;text-align:right;color:#4ade80;font-weight:700;font-family:'JetBrains Mono',monospace;">${isIncome ? '+$' + amt.toLocaleString('es-MX',{minimumFractionDigits:2}) : ''}</td>
              <td style="padding:8px 10px;text-align:right;color:#f87171;font-weight:700;font-family:'JetBrains Mono',monospace;">${isExpense ? '-$' + amt.toLocaleString('es-MX',{minimumFractionDigits:2}) : ''}</td>
              <td style="padding:8px 10px;text-align:right;color:${balClr};font-weight:700;font-family:'JetBrains Mono',monospace;">${activeAccount !== 'all' ? (bal>=0?'+':'')+' $'+bal.toLocaleString('es-MX',{minimumFractionDigits:2}) : ''}</td>
              <td style="padding:8px 10px;text-align:center;">
                ${comprobante ? `<a href="${esc(comprobante)}" target="_blank" style="color:var(--accent-cyan);font-size:12px;text-decoration:none;" onmouseover="this.style.textDecoration='underline'" onmouseout="this.style.textDecoration='none'" title="Ver comprobante">🔗 Ver</a>` : '<span style="color:var(--text-dim);font-size:11px;">—</span>'}
              </td>
              <td style="padding:8px 10px;text-align:center;">
                <button onclick="openFinanceDetail('${tx.id}')" style="background:none;border:none;color:var(--text-dim);cursor:pointer;font-size:12px;" title="Editar" onmouseover="this.style.color='var(--accent-cyan)'" onmouseout="this.style.color='var(--text-dim)'">✏️</button>
              </td>
            </tr>`
          }).join('')}
      </tbody>
    </table>
  </div>
  `

  // ── Phase 2 · Charts — always visible, more prominent ─────────
  const chartsBtn = `<button class="fin-action-btn" id="fin-charts-toggle" onclick="toggleFinanceCharts()" style="background:${finChartsVisible?'rgba(0,246,255,0.15)':'rgba(255,255,255,0.05)'};color:${finChartsVisible?'var(--accent-cyan)':'var(--text-muted)'};">📊 ${finChartsVisible?'Ocultar':'Ver'} gráficos</button>`
  const actionsHtmlFull = `
    <div style="display:flex; gap:10px; margin-bottom:24px; flex-wrap:wrap;">
      <button class="fin-action-btn" onclick="openTransferModal()">⇄ Transferir</button>
      <button class="fin-action-btn" onclick="openLoanModal()">💸 Préstamo</button>
      <button class="fin-action-btn" onclick="exportFinanceCSV()">⬇ CSV</button>
      <button class="fin-action-btn" onclick="exportFinancePDF()">🖨 PDF</button>
      <button class="fin-action-btn" onclick="exportResumenMensualPDF()" style="background:rgba(74,222,128,0.1);color:#4ade80;border-color:rgba(74,222,128,0.3);">📑 Resumen Mensual PDF</button>
      ${chartsBtn}
    </div>
  `

  // Charts panel — 3 canvases, shown above transactions
  const chartsHtml = `
    <div id="finance-charts-panel" style="display:${finChartsVisible?'grid':'none'};grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:16px;margin-bottom:28px;">
      <div style="background:var(--bg-panel);border:1px solid var(--glass-border);border-radius:16px;padding:18px;">
        <div style="font-size:10px;font-weight:800;color:var(--text-muted);letter-spacing:1px;margin-bottom:14px;">INGRESOS VS GASTOS · ÚLTIMOS 6 MESES</div>
        <canvas id="chart-bar" style="max-height:220px;"></canvas>
      </div>
      <div style="background:var(--bg-panel);border:1px solid var(--glass-border);border-radius:16px;padding:18px;">
        <div style="font-size:10px;font-weight:800;color:var(--text-muted);letter-spacing:1px;margin-bottom:14px;">DISTRIBUCIÓN DE GASTOS</div>
        <canvas id="chart-donut" style="max-height:220px;"></canvas>
      </div>
      <div style="background:var(--bg-panel);border:1px solid var(--glass-border);border-radius:16px;padding:18px;">
        <div style="font-size:10px;font-weight:800;color:var(--text-muted);letter-spacing:1px;margin-bottom:14px;">PATRIMONIO NETO · HISTORIAL</div>
        <canvas id="chart-line" style="max-height:220px;"></canvas>
      </div>
    </div>
  `

  // ── ASSEMBLY: Information Pyramid (Top→Bottom) ─────────────────
  // 1. Account tabs
  // 2. Per-account / consolidated KPI cards
  // 3. Action buttons
  // 4. Charts (Phase 2)
  // 5. Transaction log with filters + semaphore
  root.innerHTML = accountTabsHtml + statsHtml + actionsHtmlFull + chartsHtml +
    `<div style="background:var(--bg-panel);border:1px solid var(--glass-border);border-radius:16px;padding:24px;">${txTableHtml}</div>`

  // Animate KPI numbers
  animateStatEl('fin-kpi-income',  income)
  animateStatEl('fin-kpi-expense', expense)
  animateStatEl('fin-kpi-net',     net)

  // Render charts — always render when visible
  if (finChartsVisible) {
    const chartNodes = activeAccount === 'all' ? nodes : nodes.filter(n => n.metadata?.account_id === activeAccount || n.type === 'account')
    setTimeout(() => renderFinanceCharts(chartNodes), 0)
  }
}

window.setActiveAccount = (id) => {
  activeAccount = id
  renderAll()
}

window.setFinTxFilter = (f) => {
  finTxFilter = f
  renderAll()
}

window.openTransactionModal = () => {
  const inp = document.getElementById('nexus-input')
  if (inp) { inp.focus(); inp.placeholder = '+$1000 Salario   ó   -$200 Renta' }
}

window.printFinanceReport = () => {
  const table = document.getElementById('finance-tx-table')
  if (!table) { showMsg('⚠ Sin datos para imprimir'); return }
  const accLabel = activeAccount === 'all' ? 'Todas las cuentas' :
    (allNodes.find(n=>n.id===activeAccount)?.metadata?.label || activeAccount)
  const date = new Date().toLocaleDateString('es-MX', {year:'numeric',month:'long',day:'numeric'})
  const win = window.open('', '_blank', 'width=900,height=700')
  win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8">
    <title>Reporte Financiero — ${accLabel}</title>
    <style>
      body { font-family: Arial, sans-serif; font-size: 13px; color: #111; padding: 32px; }
      h1 { font-size: 20px; margin-bottom: 4px; }
      .meta { color: #666; font-size: 12px; margin-bottom: 24px; }
      table { width: 100%; border-collapse: collapse; }
      th { background: #f0f0f0; padding: 8px 10px; text-align: left; font-weight: 700; border-bottom: 2px solid #ccc; }
      td { padding: 7px 10px; border-bottom: 1px solid #eee; }
      .income { color: #16a34a; font-weight: 700; }
      .expense { color: #dc2626; font-weight: 700; }
      .balance { font-weight: 700; }
      @media print { body { padding: 16px; } button { display: none; } }
    </style>
  </head><body>
    <h1>📊 Reporte Financiero</h1>
    <div class="meta">Cuenta: <strong>${accLabel}</strong> — Generado: ${date} — Nexus OS</div>
    ${table.outerHTML}
    <div style="margin-top:24px;font-size:11px;color:#999;">Generado con Nexus OS · nexus-os-chi.vercel.app</div>
    <script>window.onload=()=>window.print()<\\/script>
  </body></html>`)
  win.document.close()
}

window.exportFinanceCSV = () => {
  const txs = allNodes.filter(n => n.type==='income' || n.type==='expense')
  const accounts = allNodes.filter(n => n.type==='account')
  const rows = txs.map(n => {
    const acc = accounts.find(a => a.id === n.metadata?.account_id)
    return [
      new Date(n.created_at).toLocaleDateString('es-MX'),
      n.type === 'income' ? 'Ingreso' : 'Gasto',
      JSON.stringify(n.metadata?.label || n.content),
      n.metadata?.amount || 0,
      acc ? (acc.metadata?.label || acc.content) : 'General'
    ].join(',')
  })
  const csv = '\ufeff' + ['Fecha,Tipo,Descripción,Monto,Cuenta', ...rows].join('\n')
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' })
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob)
  a.download = `nexus-finanzas-${new Date().toISOString().split('T')[0]}.csv`
  a.click()
}

// Export finance view as PDF (account‑specific)
window.exportFinancePDF = function exportFinancePDF() {
  // Mostrar modal de filtros antes de imprimir
  const accounts = allNodes.filter(n => n.type === 'account')
  const modal = document.getElementById('print-filter-modal')
  if (!modal) return
  // Llenar selector de cuentas
  const acSel = document.getElementById('pf-account')
  if (acSel) {
    acSel.innerHTML = '<option value="all">Todas las cuentas</option>' +
      accounts.map(a=>`<option value="${a.id}">${esc(a.metadata?.label||a.content)}</option>`).join('')
    if (activeAccount !== 'all') acSel.value = activeAccount
  }
  // Fechas por defecto: primer día del mes actual → hoy
  const today = new Date().toISOString().split('T')[0]
  const firstOfMonth = today.slice(0,7) + '-01'
  const pfFrom = document.getElementById('pf-from')
  const pfTo   = document.getElementById('pf-to')
  if (pfFrom && !pfFrom.value) pfFrom.value = firstOfMonth
  if (pfTo   && !pfTo.value)   pfTo.value   = today
  modal.classList.remove('hidden')
}

window.doPrint = function doPrint() {
  const pfAccount = document.getElementById('pf-account')?.value || 'all'
  const pfType    = document.getElementById('pf-type')?.value    || 'all'
  const pfFrom    = document.getElementById('pf-from')?.value    || ''
  const pfTo      = document.getElementById('pf-to')?.value      || ''
  document.getElementById('print-filter-modal')?.classList.add('hidden')

  // Filtrar nodos para imprimir
  let printNodes = allNodes.filter(n => n.type === 'income' || n.type === 'expense')
  if (pfAccount !== 'all') printNodes = printNodes.filter(n => n.metadata?.account_id === pfAccount)
  if (pfType !== 'all')    printNodes = printNodes.filter(n => n.type === pfType)
  if (pfFrom) printNodes = printNodes.filter(n => (n.metadata?.fecha||n.created_at?.split('T')[0]||'') >= pfFrom)
  if (pfTo)   printNodes = printNodes.filter(n => (n.metadata?.fecha||n.created_at?.split('T')[0]||'') <= pfTo)

  const accounts = allNodes.filter(n => n.type === 'account')
  const accLabel = pfAccount === 'all' ? 'Todas las cuentas' : (accounts.find(a=>a.id===pfAccount)?.metadata?.label || pfAccount)
  const income  = printNodes.filter(n=>n.type==='income').reduce((s,n)=>s+(n.metadata?.amount||0),0)
  const expense = printNodes.filter(n=>n.type==='expense').reduce((s,n)=>s+(n.metadata?.amount||0),0)

  // Inyectar contenido en #print-zone y hacer window.print()
  let printZone = document.getElementById('print-zone')
  if (!printZone) { printZone = document.createElement('div'); printZone.id = 'print-zone'; document.body.appendChild(printZone) }
  printZone.innerHTML = `
    <div style="font-family:'JetBrains Mono',monospace; padding:32px; max-width:900px; margin:0 auto;">
      <h1 style="font-size:20px; margin-bottom:4px;">Nexus OS — Estado de Cuenta</h1>
      <p style="color:#666; font-size:12px; margin-bottom:4px;">Cuenta: ${accLabel} | Período: ${pfFrom||'inicio'} → ${pfTo||'hoy'}</p>
      <p style="color:#666; font-size:12px; margin-bottom:24px;">Generado: ${new Date().toLocaleString('es-MX')}</p>
      <table style="width:100%; border-collapse:collapse; font-size:12px; margin-bottom:24px;">
        <thead>
          <tr style="border-bottom:2px solid #333;">
            <th style="text-align:left; padding:8px 4px;">Fecha</th>
            <th style="text-align:left; padding:8px 4px;">Descripción</th>
            <th style="text-align:left; padding:8px 4px;">Cuenta</th>
            <th style="text-align:right; padding:8px 4px;">Entrada</th>
            <th style="text-align:right; padding:8px 4px;">Salida</th>
          </tr>
        </thead>
        <tbody>
          ${printNodes.map(n=>{
            const acc = accounts.find(a=>a.id===n.metadata?.account_id)
            const fecha = n.metadata?.fecha || n.created_at?.split('T')[0] || ''
            return `<tr style="border-bottom:1px solid #eee;">
              <td style="padding:6px 4px;">${fecha}</td>
              <td style="padding:6px 4px;">${esc(n.metadata?.label||n.content)}</td>
              <td style="padding:6px 4px;">${esc(acc?.metadata?.label||acc?.content||'-')}</td>
              <td style="text-align:right; padding:6px 4px; color:${n.type==='income'?'green':''};">${n.type==='income'?'$'+n.metadata?.amount?.toLocaleString():''}</td>
              <td style="text-align:right; padding:6px 4px; color:${n.type==='expense'?'red':''};">${n.type==='expense'?'$'+n.metadata?.amount?.toLocaleString():''}</td>
            </tr>`
          }).join('')}
        </tbody>
        <tfoot>
          <tr style="border-top:2px solid #333; font-weight:bold;">
            <td colspan="3" style="padding:10px 4px;">TOTALES (${printNodes.length} movimientos)</td>
            <td style="text-align:right; padding:10px 4px; color:green;">$${income.toLocaleString()}</td>
            <td style="text-align:right; padding:10px 4px; color:red;">$${expense.toLocaleString()}</td>
          </tr>
          <tr style="font-weight:bold; background:#f9f9f9;">
            <td colspan="4" style="padding:10px 4px;">SALDO NETO</td>
            <td style="text-align:right; padding:10px 4px; color:${income-expense>=0?'green':'red'};">${income-expense>=0?'+':''}\$${(income-expense).toLocaleString()}</td>
          </tr>
        </tfoot>
      </table>
    </div>`

  // Añadir CSS de impresión temporal
  const style = document.createElement('style')
  style.id = 'print-override'
  style.textContent = `@media print { body > *:not(#print-zone) { display:none !important; } #print-zone { display:block !important; } }`
  document.head.appendChild(style)
  setTimeout(() => {
    window.print()
    setTimeout(() => { style.remove(); printZone.innerHTML = '' }, 800)
  }, 200)
}

