window.agendaSearchMovimientos = function(safeId, query) {
  const resultsEl = document.getElementById(`ag-link-res-${safeId}`)
  if (!resultsEl) return
  const q    = (query || '').toLowerCase().trim()
  const movs = allNodes
    .filter(n => ['expense', 'income', 'payment'].includes(n.type))
    .filter(n => !q || (n.content || '').toLowerCase().includes(q) || String(n.metadata?.amount || '').includes(q))
    .slice(0, 10)
  if (movs.length === 0) {
    resultsEl.innerHTML = `<div style="color:var(--text-muted);font-size:11px;padding:8px 4px;">Sin resultados</div>`
    return
  }
  resultsEl.innerHTML = movs.map(n => {
    const amt = n.metadata?.amount ? fmt$(n.metadata.amount) : ''
    const dt  = (n.metadata?.date || n.created_at || '').slice(0, 10)
    return `<div onclick="agendaConfirmLink('${n.id}','${safeId}')"
      style="display:flex;justify-content:space-between;align-items:center;padding:7px 10px;border-radius:8px;cursor:pointer;background:rgba(255,255,255,0.04);"
      onmouseover="this.style.background='rgba(96,165,250,0.12)'" onmouseout="this.style.background='rgba(255,255,255,0.04)'">
      <span style="font-size:12px;color:#fff;">${esc(n.content || '(sin descripción)')}</span>
      <div style="display:flex;gap:8px;align-items:center;flex-shrink:0;">
        ${amt ? `<span style="font-size:12px;font-family:'JetBrains Mono',monospace;color:#4ade80;">${amt}</span>` : ''}
        <span style="font-size:10px;color:var(--text-muted);">${dt}</span>
      </div>
    </div>`
  }).join('')
}

window.agendaConfirmLink = async function(movId, safeId) {
  const { start, end } = _agendaPeriodRange()
  const obs    = _agendaBuildObligations(allNodes, start, end)
  const ob     = obs.find(o => o.id.replace(/[^a-zA-Z0-9_-]/g, '_') === safeId)
  if (!ob) return
  const realId = ob.nodeId || ob.id
  const node   = allNodes.find(n => n.id === realId)
  if (!node) return
  const upd = { ...node.metadata, linked_movimiento_id: movId }
  const { error } = await supabase.from('nodes').update({ metadata: upd }).eq('id', realId)
  if (error) { console.error('[agendaConfirmLink]', error); return }
  const i = allNodes.findIndex(n => n.id === realId)
  if (i >= 0) allNodes[i] = { ...allNodes[i], metadata: upd }
  renderAgenda(allNodes)
}

function fmt$(n) {
  if (typeof n !== 'number') return '$0'
  return '$' + n.toLocaleString('es-MX', { minimumFractionDigits: 0, maximumFractionDigits: 2 })
}

// ── FRECUENCIA — chips y selector de día de semana ───────────────────────────
window.agFreqSelect = (chip) => {
  document.querySelectorAll('#ag-freq-chips .freq-chip').forEach(c => {
    c.style.background = 'transparent'
    c.style.borderColor = 'rgba(255,255,255,0.1)'
    c.style.color = 'var(--text-muted)'
    c.classList.remove('active')
  })
  chip.style.background  = 'rgba(96,165,250,0.15)'
  chip.style.borderColor = 'rgba(96,165,250,0.4)'
  chip.style.color       = '#60a5fa'
  chip.classList.add('active')
  const freq = chip.dataset.freq
  document.getElementById('ag-frequency').value = freq
  // Sub-campos condicionales
  const showMonthDay  = ['mensual','bimestral','trimestral','semestral','anual'].includes(freq)
  document.getElementById('ag-freq-day-month').style.display  = showMonthDay   ? '' : 'none'
  document.getElementById('ag-freq-weekday').style.display    = freq === 'semanal'      ? '' : 'none'
  document.getElementById('ag-freq-quincenal').style.display  = freq === 'quincenal'    ? '' : 'none'
  document.getElementById('ag-freq-custom').style.display     = freq === 'personalizado'? '' : 'none'
}

window.agWeekdaySelect = (btn) => {
  document.querySelectorAll('#ag-weekday-btns .weekday-btn').forEach(b => {
    b.style.background  = 'transparent'
    b.style.borderColor = 'rgba(255,255,255,0.1)'
    b.style.color       = 'var(--text-muted)'
    b.classList.remove('active')
  })
  btn.style.background  = 'rgba(96,165,250,0.15)'
  btn.style.borderColor = 'rgba(96,165,250,0.4)'
  btn.style.color       = '#60a5fa'
  btn.classList.add('active')
  document.getElementById('ag-weekday').value = btn.dataset.day
}

// ── Calcula próximo vencimiento para CUALQUIER frecuencia ────────────────────
function calcNextDueDate(frequency, dayOfMonth, weekday, customDays, specificDate) {
  const today = new Date(); today.setHours(0,0,0,0)
  if (frequency === 'diario') {
    const d = new Date(today); d.setDate(d.getDate() + 1)
    return d.toISOString().split('T')[0]
  }
  if (frequency === 'semanal') {
    const target = parseInt(weekday ?? 1)
    const d = new Date(today)
    let diff = target - d.getDay()
    if (diff <= 0) diff += 7
    d.setDate(d.getDate() + diff)
    return d.toISOString().split('T')[0]
  }
  if (frequency === 'quincenal') {
    const d = new Date(today)
    const day = d.getDate()
    if (day < 15) { d.setDate(15) }
    else { d.setMonth(d.getMonth() + 1); d.setDate(1) }
    return d.toISOString().split('T')[0]
  }
  if (frequency === 'personalizado' && customDays > 0) {
    const d = new Date(today); d.setDate(d.getDate() + customDays)
    return d.toISOString().split('T')[0]
  }
  // Anual, bianual, trianual — con fecha específica (mes + día exacto)
  if (['anual','bianual','trianual'].includes(frequency)) {
    const yearStep = frequency === 'bianual' ? 2 : frequency === 'trianual' ? 3 : 1
    if (specificDate) {
      const ref = new Date(specificDate + 'T12:00:00')
      // Advance from reference date by yearStep until future
      let next = new Date(ref.getFullYear(), ref.getMonth(), ref.getDate())
      while (next <= today) next.setFullYear(next.getFullYear() + yearStep)
      return next.toISOString().split('T')[0]
    }
    // Fallback: only dayOfMonth known (backward compat)
    const dom = dayOfMonth || 1
    const d = new Date(today.getFullYear(), today.getMonth(), dom)
    while (d <= today) d.setMonth(d.getMonth() + yearStep * 12)
    return d.toISOString().split('T')[0]
  }
  // mensual, bimestral, trimestral, semestral
  const freqMonths = { mensual:1, bimestral:2, trimestral:3, semestral:6 }
  const months = freqMonths[frequency] || 1
  const dom = dayOfMonth || 1
  const d = new Date(today.getFullYear(), today.getMonth(), dom)
  while (d <= today) d.setMonth(d.getMonth() + months)
  return d.toISOString().split('T')[0]
}

// ── Helper para inicializar chips al abrir el modal ──────────────────────────
function _agInitFreqChips(freq = 'mensual') {
  document.querySelectorAll('#ag-freq-chips .freq-chip').forEach(c => {
    const active = c.dataset.freq === freq
    c.style.background  = active ? 'rgba(96,165,250,0.15)' : 'transparent'
    c.style.borderColor = active ? 'rgba(96,165,250,0.4)'  : 'rgba(255,255,255,0.1)'
    c.style.color       = active ? '#60a5fa'               : 'var(--text-muted)'
    if (active) c.classList.add('active'); else c.classList.remove('active')
  })
  document.getElementById('ag-frequency').value = freq
  const showMonthDay    = ['mensual','bimestral','trimestral','semestral'].includes(freq)
  const showSpecificDate = ['anual','bianual','trianual'].includes(freq)
  document.getElementById('ag-freq-day-month').style.display    = showMonthDay     ? '' : 'none'
  const sdEl = document.getElementById('ag-freq-specific-date')
  if (sdEl) sdEl.style.display                                   = showSpecificDate ? '' : 'none'
  document.getElementById('ag-freq-weekday').style.display      = freq === 'semanal'       ? '' : 'none'
  document.getElementById('ag-freq-quincenal').style.display    = freq === 'quincenal'     ? '' : 'none'
  document.getElementById('ag-freq-custom').style.display       = freq === 'personalizado' ? '' : 'none'
}

// ── Helper para inicializar cuenta destino en cascada ────────────────────────
function _agInitContactAccounts(contactId, savedAccountIdx = null) {
  const accountWrap = document.getElementById('ag-bill-account-wrap')
  const accountSel  = document.getElementById('ag-bill-account')
  const infoEl      = document.getElementById('ag-bill-contact-info')
  if (!contactId) {
    if (accountWrap) accountWrap.style.display = 'none'
    if (infoEl) infoEl.style.display = 'none'
    return
  }
  const contact = allNodes.find(n => n.id === contactId)
  if (!contact) { if (accountWrap) accountWrap.style.display = 'none'; return }
  const m = contact.metadata || {}
  // Info básica
  const parts = []
  if (m.bank_name || m.bank) parts.push(`🏦 ${m.bank_name || m.bank}`)
  if (m.clabe)   parts.push(`CLABE: ${m.clabe}`)
  if (m.account) parts.push(`Cta: ${m.account}`)
  if (m.phone)   parts.push(`📞 ${m.phone}`)
  if (infoEl) { infoEl.innerHTML = parts.join(' &nbsp;·&nbsp; ') || ''; infoEl.style.display = parts.length ? '' : 'none' }
  // Cuentas registradas del contacto
  const accounts = m.contact_accounts || []
  if (accounts.length > 0 && accountSel && accountWrap) {
    accountSel.innerHTML = '<option value="">— Elige la cuenta destino —</option>' +
      accounts.map((acc, i) => {
        const last4 = acc.clabe ? `····${acc.clabe.slice(-4)}` : acc.account ? `····${String(acc.account).slice(-4)}` : ''
        const label = [acc.bank || acc.bank_name, acc.type, last4].filter(Boolean).join(' ')
        const sel   = savedAccountIdx !== null && parseInt(savedAccountIdx) === i ? 'selected' : ''
        return `<option value="${i}" ${sel}>${esc(label || `Cuenta ${i+1}`)}</option>`
      }).join('')
    accountWrap.style.display = ''
  } else if (accountWrap) {
    accountWrap.style.display = 'none'
  }
}

// ── AGENDA MODAL ──────────────────────────────────────────────────────────────
window.openAgendaModal = (type, prefillProjectTag = '') => {
  agendaItemType = type
  editingAgendaId = null
  window._agendaPrefillProject = prefillProjectTag
  agendaColor = type === 'card' ? '#60a5fa' : type === 'subscription' ? '#a78bfa' : '#fb923c'
  const titles = { card:'Nueva Tarjeta de Crédito', subscription:'Nueva Suscripción / Servicio', bill:'Nuevo Pago Fijo' }
  document.getElementById('agenda-modal-title').textContent = titles[type] || 'Nuevo Ítem'
  document.getElementById('ag-name').value = ''
  // Toggle field groups
  document.getElementById('ag-fields-card').style.display      = type === 'card' ? '' : 'none'
  document.getElementById('ag-fields-recurring').style.display = type !== 'card' ? '' : 'none'
  document.getElementById('ag-category-wrap').style.display    = type === 'subscription' ? '' : 'none'
  document.getElementById('ag-bill-fields').style.display      = type === 'bill' ? '' : 'none'
  if (type !== 'card') {
    document.getElementById('ag-amount').value = ''
    document.getElementById('ag-day').value    = ''
    document.getElementById('ag-custom-days') && (document.getElementById('ag-custom-days').value = '')
    document.getElementById('ag-specific-date') && (document.getElementById('ag-specific-date').value = '')
    _agInitFreqChips('mensual')
    // Reset weekday chips to Lunes
    document.querySelectorAll('#ag-weekday-btns .weekday-btn').forEach(b => {
      const active = b.dataset.day === '1'
      b.style.background = active ? 'rgba(96,165,250,0.15)' : 'transparent'
      b.style.borderColor = active ? 'rgba(96,165,250,0.4)' : 'rgba(255,255,255,0.1)'
      b.style.color = active ? '#60a5fa' : 'var(--text-muted)'
    })
    document.getElementById('ag-weekday') && (document.getElementById('ag-weekday').value = '1')
  } else {
    document.getElementById('ag-last4').value       = ''
    document.getElementById('ag-limit').value       = ''
    document.getElementById('ag-cut-day').value     = ''
    document.getElementById('ag-pay-day').value     = ''
    document.getElementById('ag-bank').value        = ''
    document.getElementById('ag-holder').value      = ''
    document.getElementById('ag-card-number').value = ''
    document.getElementById('ag-clabe').value       = ''
    document.getElementById('ag-account-num').value = ''
    document.getElementById('ag-branch').value      = ''
  }
  // Populate contact dropdown for bills
  if (type === 'bill') {
    const sel = document.getElementById('ag-bill-contact')
    const infoEl = document.getElementById('ag-bill-contact-info')
    if (sel) {
      const contacts = getContacts()
      sel.innerHTML = '<option value="">— Sin contacto —</option>' +
        contacts.map(c => {
          const name = c.metadata?.name || c.content
          return `<option value="${c.id}">${esc(name)}</option>`
        }).join('')
      if (infoEl) infoEl.style.display = 'none'
      document.getElementById('ag-bill-account-wrap') && (document.getElementById('ag-bill-account-wrap').style.display = 'none')
      sel.onchange = () => _agInitContactAccounts(sel.value)
    }
  }
  // Reset color swatches
  document.querySelectorAll('#agenda-modal .ev-color-swatch').forEach(s => s.classList.remove('active'))
  document.querySelector(`#agenda-modal .ev-color-swatch[data-color="${agendaColor}"]`)?.classList.add('active')
  document.getElementById('agenda-modal').classList.remove('hidden')
  setTimeout(() => document.getElementById('ag-name')?.focus(), 60)
}
window.closeAgendaModal = () => document.getElementById('agenda-modal')?.classList.add('hidden')
window.toggleAgendaAccount = (accId, checkbox) => {
  // If currently "all selected" (empty set), initialize with all ids checked minus the one being unchecked
  if (agendaPlanAccounts.size === 0) {
    const allAcc = allNodes.filter(n => n.type === 'account').map(n => n.id)
    allAcc.forEach(id => agendaPlanAccounts.add(id))
  }
  if (checkbox.checked) agendaPlanAccounts.add(accId)
  else agendaPlanAccounts.delete(accId)
  // If all selected again → reset to "all" state
  const allAcc = allNodes.filter(n => n.type === 'account').map(n => n.id)
  if (allAcc.every(id => agendaPlanAccounts.has(id))) agendaPlanAccounts.clear()
  renderAgenda(allNodes)
}
window.selectAgendaColor = (btn) => {
  document.querySelectorAll('#agenda-modal .ev-color-swatch').forEach(s => s.classList.remove('active'))
  btn.classList.add('active'); agendaColor = btn.dataset.color
}
window.saveAgendaItem = async () => {
  const name = document.getElementById('ag-name')?.value.trim()
  if (!name) { showToast('⚠️ El nombre es obligatorio'); return }
  let meta = { label: name, color: agendaColor }
  if (agendaItemType === 'card') {
    meta = { ...meta,
      bank:       document.getElementById('ag-bank')?.value.trim() || '',
      cardType:   document.getElementById('ag-card-type')?.value || 'crédito',
      holder:     document.getElementById('ag-holder')?.value.trim() || '',
      lastFour:   document.getElementById('ag-last4')?.value.trim() || '',
      cardNumber: document.getElementById('ag-card-number')?.value.replace(/\s/g,'') || '',
      clabe:      document.getElementById('ag-clabe')?.value.trim() || '',
      accountNum: document.getElementById('ag-account-num')?.value.trim() || '',
      branch:     document.getElementById('ag-branch')?.value.trim() || '',
      limit:      parseFloat(document.getElementById('ag-limit')?.value) || 0,
      cutDay:     parseInt(document.getElementById('ag-cut-day')?.value) || null,
      payDay:     parseInt(document.getElementById('ag-pay-day')?.value) || null,
      currency:   document.getElementById('ag-card-currency')?.value || 'MXN'
    }
  } else {
    const rawAmt      = document.getElementById('ag-amount')?.value?.trim()
    const frequency   = document.getElementById('ag-frequency')?.value || 'mensual'
    const dayOfMonth  = parseInt(document.getElementById('ag-day')?.value) || null
    const weekday     = document.getElementById('ag-weekday')?.value || '1'
    const customDays  = parseInt(document.getElementById('ag-custom-days')?.value) || null
    const specificDate = ['anual','bianual','trianual'].includes(frequency)
      ? (document.getElementById('ag-specific-date')?.value || null)
      : null
    meta = { ...meta,
      amount:       rawAmt !== '' ? (parseFloat(rawAmt) || 0) : null,
      currency:     document.getElementById('ag-currency')?.value || 'MXN',
      dayOfMonth,
      weekday:      frequency === 'semanal' ? weekday : null,
      customDays:   frequency === 'personalizado' ? customDays : null,
      specificDate: specificDate || null,
      frequency,
      category:     document.getElementById('ag-category')?.value || '',
      paid: false
    }
    if (agendaItemType === 'bill') {
      const contactId = document.getElementById('ag-bill-contact')?.value || ''
      const accountIdx = document.getElementById('ag-bill-account')?.value ?? ''
      meta.contactId   = contactId
      meta.method      = document.getElementById('ag-bill-method')?.value || 'transferencia'
      meta.contractNum = document.getElementById('ag-contract-num')?.value?.trim() || ''
      meta.payRef      = document.getElementById('ag-pay-ref')?.value?.trim()      || ''
      meta.billNotes   = document.getElementById('ag-bill-notes')?.value?.trim()   || ''
      // Guardar qué cuenta destino se seleccionó
      if (accountIdx !== '' && contactId) {
        const contact  = allNodes.find(n => n.id === contactId)
        const accounts = contact?.metadata?.contact_accounts || []
        meta.targetAccount = accounts[parseInt(accountIdx)] || null
        meta.targetAccountIdx = accountIdx
      } else {
        meta.targetAccount = null
        meta.targetAccountIdx = ''
      }
      meta.dueDate = calcNextDueDate(frequency, dayOfMonth, weekday, customDays)
    }
    // Pre-fill project tag if opened from project dashboard
    if (window._agendaPrefillProject) {
      meta.project_tag = window._agendaPrefillProject
      if (!meta.tags) meta.tags = []
      if (!meta.tags.includes('#'+window._agendaPrefillProject)) meta.tags.push('#'+window._agendaPrefillProject)
    }
  }
  closeAgendaModal()
  window._agendaPrefillProject = ''
  if (editingAgendaId) {
    // Edit mode — update existing node
    const node = allNodes.find(n => n.id === editingAgendaId)
    if (node) {
      node.content  = name
      node.metadata = { ...node.metadata, ...meta }
      if (localStorage.getItem('nexus_admin_bypass') !== 'true' && currentUser)
        await supabase.from('nodes').update({ content: name, metadata: node.metadata }).eq('id', editingAgendaId)
      renderAll()
      showToast('✅ Actualizado')
    }
    editingAgendaId = null
  } else {
    await insertDirectNode(agendaItemType, name, meta)
  }
}
window.editAgendaItem = (nodeId) => {
  const node = allNodes.find(n => n.id === nodeId)
  if (!node) return
  const m = node.metadata || {}
  agendaItemType  = node.type
  editingAgendaId = nodeId
  agendaColor     = m.color || (node.type === 'card' ? '#60a5fa' : node.type === 'subscription' ? '#a78bfa' : '#fb923c')
  const titles = { card:'Editar Tarjeta', subscription:'Editar Suscripción', bill:'Editar Pago Fijo' }
  document.getElementById('agenda-modal-title').textContent = titles[node.type] || 'Editar'
  document.getElementById('ag-name').value = m.label || node.content || ''
  document.getElementById('ag-fields-card').style.display      = node.type === 'card' ? '' : 'none'
  document.getElementById('ag-fields-recurring').style.display = node.type !== 'card' ? '' : 'none'
  document.getElementById('ag-category-wrap').style.display    = node.type === 'subscription' ? '' : 'none'
  document.getElementById('ag-bill-fields').style.display      = node.type === 'bill' ? '' : 'none'
  if (node.type !== 'card') {
    document.getElementById('ag-amount').value = m.amount != null ? m.amount : ''
    document.getElementById('ag-day').value    = m.dayOfMonth || ''
    if (document.getElementById('ag-specific-date')) document.getElementById('ag-specific-date').value = m.specificDate || ''
    if (document.getElementById('ag-currency')) document.getElementById('ag-currency').value = m.currency || 'MXN'
    if (document.getElementById('ag-category') && node.type === 'subscription') document.getElementById('ag-category').value = m.category || ''
    // Restaurar chips de frecuencia (también muestra/oculta ag-freq-specific-date)
    _agInitFreqChips(m.frequency || 'mensual')
    // Restaurar día de semana
    if (m.frequency === 'semanal' && m.weekday) {
      document.getElementById('ag-weekday') && (document.getElementById('ag-weekday').value = m.weekday)
      document.querySelectorAll('#ag-weekday-btns .weekday-btn').forEach(b => {
        const active = b.dataset.day === String(m.weekday)
        b.style.background  = active ? 'rgba(96,165,250,0.15)' : 'transparent'
        b.style.borderColor = active ? 'rgba(96,165,250,0.4)'  : 'rgba(255,255,255,0.1)'
        b.style.color       = active ? '#60a5fa'               : 'var(--text-muted)'
      })
    }
    // Restaurar cada X días
    if (m.frequency === 'personalizado' && m.customDays) {
      document.getElementById('ag-custom-days') && (document.getElementById('ag-custom-days').value = m.customDays)
    }
    if (node.type === 'bill') {
      if (document.getElementById('ag-bill-method')) document.getElementById('ag-bill-method').value = m.method || 'transferencia'
      if (document.getElementById('ag-contract-num')) document.getElementById('ag-contract-num').value = m.contractNum || ''
      if (document.getElementById('ag-pay-ref'))      document.getElementById('ag-pay-ref').value      = m.payRef      || ''
      if (document.getElementById('ag-bill-notes'))   document.getElementById('ag-bill-notes').value   = m.billNotes   || ''
      // Populate & set contact + cascade de cuentas
      const sel = document.getElementById('ag-bill-contact')
      if (sel) {
        const contacts = getContacts()
        sel.innerHTML = '<option value="">— Sin contacto —</option>' + contacts.map(c => {
          const name = c.metadata?.name || c.content
          return `<option value="${c.id}" ${m.contactId===c.id?'selected':''}>${esc(name)}</option>`
        }).join('')
        sel.onchange = () => _agInitContactAccounts(sel.value)
        if (m.contactId) _agInitContactAccounts(m.contactId, m.targetAccountIdx ?? null)
      }
    }
  }
  document.querySelectorAll('#agenda-modal .ev-color-swatch').forEach(s => s.classList.remove('active'))
  document.querySelector(`#agenda-modal .ev-color-swatch[data-color="${agendaColor}"]`)?.classList.add('active')
  document.getElementById('agenda-modal').classList.remove('hidden')
  setTimeout(() => document.getElementById('ag-name')?.focus(), 60)
}

window.deleteAgendaItem = async (nodeId) => {
  if (!confirm('¿Eliminar este ítem?')) return
  allNodes = allNodes.filter(n => n.id !== nodeId)
  renderAll()
  if (localStorage.getItem('nexus_admin_bypass') !== 'true' && currentUser)
    await supabase.from('nodes').delete().eq('id', nodeId)
}
window.toggleBillPaid = async (nodeId) => {
  const node = allNodes.find(n => n.id === nodeId); if (!node) return
  node.metadata = { ...node.metadata, paid: !node.metadata?.paid }
  renderAll()
  if (localStorage.getItem('nexus_admin_bypass') !== 'true' && currentUser)
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', nodeId)
}

// ═══════════════════════════════════════════════════════════
// ABONOS — Pagos parciales a proveedores
// ═══════════════════════════════════════════════════════════
let _abonoProviderId   = null
let _abonoProjectSlug  = null
let _abonoRefreshId    = null   // project id to refresh after save
let _abonoCotId        = null   // cotización id to update when abono is saved
let _abonoComprobantes = []     // [{type:'url'|'image', url, label?}]

window.openAbonoModal = (provId, provName, projSlug, projectId, cotId = null) => {
  _abonoProviderId   = provId
  _abonoProjectSlug  = projSlug
  _abonoRefreshId    = projectId
  _abonoCotId        = cotId || null
  _abonoComprobantes = []
  const infoEl = document.getElementById('abono-proveedor-info')
  if (infoEl) infoEl.textContent = `💸 Abono a: ${provName}`
  document.getElementById('abono-amount').value = ''
  document.getElementById('abono-date').value   = new Date().toISOString().split('T')[0]
  document.getElementById('abono-method').value = 'transferencia'
  document.getElementById('abono-notes').value  = ''
  const urlInp = document.getElementById('abono-comp-url-input')
  if (urlInp) urlInp.value = ''
  abonoRenderComprobantes()
  document.getElementById('abono-modal').classList.remove('hidden')
  setTimeout(() => document.getElementById('abono-amount')?.focus(), 60)
}
window.closeAbonoModal = () => document.getElementById('abono-modal')?.classList.add('hidden')

window.saveAbono = async () => {
  const amount = parseFloat(document.getElementById('abono-amount').value)
  if (!amount || amount <= 0) { showToast('⚠️ Ingresa un monto válido'); return }
  const date   = document.getElementById('abono-date').value || new Date().toISOString().split('T')[0]
  const method = document.getElementById('abono-method').value
  const notes  = document.getElementById('abono-notes').value.trim()
  const label  = notes || `Abono ${method}`
  const comprobantes = [..._abonoComprobantes]
  const receiptUrl = comprobantes.find(c => c.type === 'url')?.url || undefined
  const meta = {
    label, amount, date,
    method,
    contact_id:   _abonoProviderId,
    project_tag:  _abonoProjectSlug,
    es_abono:     true,
    notes:        notes || undefined,
    comprobantes: comprobantes.length ? comprobantes : undefined,
    receipt_url:  receiptUrl,
  }
  closeAbonoModal()
  const bypass = localStorage.getItem('nexus_admin_bypass') === 'true'
  let newExpenseId = null
  if (bypass) {
    const tmp = { id: Math.random().toString(36).substr(2,9), type:'expense', content:label, metadata:meta, created_at: new Date().toISOString() }
    allNodes.unshift(tmp)
    newExpenseId = tmp.id
  } else {
    const { data } = await supabase.from('nodes').insert({ owner_id:currentUser.id, type:'expense', content:label, metadata:meta }).select()
    if (data?.[0]) { allNodes.unshift(data[0]); newExpenseId = data[0].id }
  }
  await autoLinkToProject(newExpenseId || allNodes[0]?.id, _abonoProjectSlug)

  // ── Actualizar cotización vinculada con el nuevo abono ──────────────────
  if (_abonoCotId) {
    const cotNode = allNodes.find(n => n.id === _abonoCotId)
    if (cotNode) {
      const cotMeta = { ...(cotNode.metadata || {}) }
      const abonoEntry = {
        id:           crypto.randomUUID ? crypto.randomUUID() : Date.now().toString(),
        date, amount, method,
        notes:        notes || null,
        comprobantes: comprobantes.length ? comprobantes : undefined,
        receipt_url:  receiptUrl || null,
        expense_id:   newExpenseId,
      }
      cotMeta.abonos = [...(cotMeta.abonos || []), abonoEntry]
      // Auto-actualizar status
      const cotTotal = +(cotMeta.amount || 0)
      const cotPaid  = cotMeta.abonos.reduce((s, a) => s + +(a.amount || 0), 0)
      if (cotTotal > 0 && cotPaid >= cotTotal) cotMeta.status = 'pagada'
      else if (cotPaid > 0) cotMeta.status = 'parcial'
      cotNode.metadata = cotMeta
      if (!bypass && currentUser) {
        supabase.from('nodes').update({ metadata: cotMeta }).eq('id', _abonoCotId).then(() => {})
      }
    }
  }
  // ──────────────────────────────────────────────────────────────────────

  showToast(`✅ Abono de $${amount.toLocaleString('es-MX')} registrado`)
  if (_abonoRefreshId) openProjectDashboard(_abonoRefreshId)
}

// ── Comprobantes helpers — abono-modal ───────────────────────────────────────
window.abonoRenderComprobantes = () => {
  const listEl = document.getElementById('abono-comprobantes-list')
  if (!listEl) return
  listEl.innerHTML = _abonoComprobantes.length === 0 ? '' : _abonoComprobantes.map((c, i) =>
    `<div style="display:flex;align-items:center;gap:6px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.06);border-radius:6px;padding:5px 8px;">
      ${c.type === 'image'
        ? `<img src="${esc(c.url)}" onclick="viewImage('${c.url.replace(/'/g,'&#39;')}')" style="height:28px;width:28px;object-fit:cover;border-radius:4px;cursor:pointer;flex-shrink:0;" title="Ver imagen" />`
        : `<span style="flex-shrink:0;font-size:12px;">🔗</span>`}
      <span style="flex:1;font-size:11px;color:#60a5fa;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${esc(c.label||c.url)}">${c.type==='url'?`<a href="${esc(c.url)}" target="_blank" style="color:inherit;text-decoration:none;">${esc(c.label||c.url)}</a>`:esc(c.label||'imagen')}</span>
      <button onclick="abonoRemoveComp(${i})" style="background:none;border:none;color:#f87171;cursor:pointer;font-size:13px;line-height:1;padding:0 3px;flex-shrink:0;">✕</button>
    </div>`
  ).join('')
}

window.abonoAddCompUrl = () => {
  const inp = document.getElementById('abono-comp-url-input')
  const url = inp?.value.trim()
  if (!url) { showToast('⚠️ Ingresa una URL primero'); return }
  _abonoComprobantes.push({ type: 'url', url, label: decodeURIComponent(url.split('/').pop() || url).slice(0, 60) })
  if (inp) inp.value = ''
  abonoRenderComprobantes()
}

window.abonoRemoveComp = (i) => {
  _abonoComprobantes.splice(i, 1)
  abonoRenderComprobantes()
}

window.abonoAddCompFile = (inp) => {
  const file = inp?.files?.[0]
  if (!file) return
  compressImage(file, b64 => {
    _abonoComprobantes.push({ type: 'image', url: b64, label: file.name })
    abonoRenderComprobantes()
    inp.value = ''
  })
}
