// HERRAMIENTAS — TAB SYSTEM
// ═══════════════════════════════════════════════════════════════════
window.switchHerrTab = function(tab) {
  document.querySelectorAll('.herr-tab').forEach(t => t.classList.toggle('active', t.dataset.tab === tab))
  document.querySelectorAll('.herr-panel').forEach(p => p.style.display = 'none')
  const panel = document.getElementById('herr-panel-' + tab)
  if (panel) panel.style.display = ''
  if (tab === 'tramites' && typeof renderDocHistory === 'function') renderDocHistory()
  if (tab === 'tramites' && typeof renderClausulaCatalog === 'function') renderClausulaCatalog()
  if (tab === 'otc') {
    // Auto-fetch Bitso price when opening OTC tab (onchange alone won't fire if coin already selected)
    // Reset _userEdited flag so Bitso price auto-fills, and clear cache to force fresh fetch
    setTimeout(() => {
      const tcInput = document.getElementById('otc-tc')
      if (tcInput && !tcInput.value) tcInput._userEdited = false
      _otcBitsoCache = {} // Force fresh fetch
      if (typeof otcFetchBitso === 'function') otcFetchBitso()
    }, 200)
    if (typeof renderOtcHistory === 'function') renderOtcHistory()
    if (typeof _otcCheckDraftOnOpen === 'function') _otcCheckDraftOnOpen()
  }
}
window.switchHerrSubtab = function(sub) {
  document.querySelectorAll('.herr-subtab').forEach(t => t.classList.toggle('active', t.dataset.subtab === sub))
  document.querySelectorAll('.herr-subpanel').forEach(p => p.style.display = 'none')
  const panel = document.getElementById('herr-sub-' + sub)
  if (panel) panel.style.display = ''
  if (sub === 'docs' && typeof renderDocHistory === 'function') renderDocHistory()
}

// ═══════════════════════════════════════════════════════════════════
// ORQUESTADOR OTC — BLOQUE A: MATH ENGINE
// ═══════════════════════════════════════════════════════════════════
let _otcData = { ventaBruta:0, comisionCliente:0, ventaReportada:0, comisionBitso:0, gananciaOp:0 }
let _otcRows = []
let _otcAdminVisible = false
let _otcBitsoCache = {}
const _floor2 = v => Math.floor(v * 100) / 100
const _fmt$ = v => v.toLocaleString('es-MX', {minimumFractionDigits:2, maximumFractionDigits:2})

// Bitso real-time price fetch
const BITSO_BOOKS = { USDT:'usdt_mxn', BTC:'btc_mxn', ETH:'eth_mxn', XRP:'xrp_mxn', SOL:'sol_mxn' }
window.otcFetchBitso = async function() {
  const coin = document.getElementById('otc-coin')?.value || 'USDT'
  const book = BITSO_BOOKS[coin]
  const tcInput = document.getElementById('otc-tc')
  const hint = document.getElementById('otc-bitso-hint')
  if (!book) {
    if (hint) hint.textContent = 'Sin precio Bitso para ' + coin + ' — ingresa T/C manual'
    return
  }
  if (hint) hint.textContent = 'Consultando Bitso...'
  try {
    if (_otcBitsoCache[book] && (Date.now() - _otcBitsoCache[book].ts < 30000)) {
      const price = _otcBitsoCache[book].ask
      if (tcInput && !tcInput._userEdited) tcInput.value = price
      if (hint) hint.innerHTML = 'Bitso ask: <strong>$' + _fmt$(price) + '</strong> — <span style="cursor:pointer;text-decoration:underline;" onclick="otcFetchBitso()">actualizar</span>'
      otcRecalc()
      return
    }
    const resp = await fetch('/api/financial?bitso=' + book)
    const json = await resp.json()
    if (json.success && json.payload) {
      const ask = parseFloat(json.payload.ask) || 0
      _otcBitsoCache[book] = { ask, ts: Date.now() }
      if (tcInput && !tcInput._userEdited) tcInput.value = ask.toFixed(2)
      if (hint) hint.innerHTML = 'Bitso ask: <strong>$' + _fmt$(ask) + '</strong> — <span style="cursor:pointer;text-decoration:underline;" onclick="otcFetchBitso()">actualizar</span>'
      otcRecalc()
    }
  } catch(e) {
    console.warn('Bitso fetch error', e)
    if (hint) hint.textContent = 'Error al consultar Bitso — ingresa T/C manual'
  }
}

window.otcRecalc = function() {
  const qty = parseFloat(document.getElementById('otc-qty')?.value) || 0
  const tc  = parseFloat(document.getElementById('otc-tc')?.value) || 0
  const feeReported = parseFloat(document.getElementById('otc-fee-reported')?.value) || 0
  const feeReal     = parseFloat(document.getElementById('otc-fee-real')?.value) || 0

  const ventaBruta = _floor2(qty * tc)
  const comisionCliente = _floor2(ventaBruta * (feeReported / 100))
  const ventaReportada  = _floor2(ventaBruta - comisionCliente)
  const comisionBitso   = _floor2(ventaBruta * (feeReal / 100))
  const gananciaOp      = _floor2(comisionCliente - comisionBitso)

  _otcData = { ventaBruta, comisionCliente, ventaReportada, comisionBitso, gananciaOp }

  document.getElementById('otc-kpi-bruta').textContent    = '$' + _fmt$(ventaBruta)
  document.getElementById('otc-kpi-comision').textContent  = '$' + _fmt$(comisionCliente)
  document.getElementById('otc-kpi-neto').textContent      = '$' + _fmt$(ventaReportada)
  document.getElementById('otc-kpi-ganancia').textContent  = _otcAdminVisible ? ('$' + _fmt$(gananciaOp)) : '****'

  otcUpdateSemaforo()
  otcUpdateWhatsApp()
  _otcSaveDraft()  // auto-persist draft to localStorage
}

window.toggleOtcAdmin = function() {
  _otcAdminVisible = !_otcAdminVisible
  document.getElementById('otc-kpi-ganancia').textContent = _otcAdminVisible ? ('$' + _fmt$(_otcData.gananciaOp)) : '****'
}

// ═══════════════════════════════════════════════════════════════════
// ORQUESTADOR OTC — BLOQUE B: DISPERSIÓN TABLE
// ═══════════════════════════════════════════════════════════════════
window.otcAddRow = function() {
  const id = 'odr_' + Date.now() + '_' + Math.random().toString(36).slice(2,6)
  _otcRows.push({ id, contactId:'', contactName:'', bank:'', clabe:'', assignType:'fixed', value:0, montoMXN:0, receipts:[], projectTag:'' })
  otcRenderTable()
  _otcSaveDraft()
}

window.otcRemoveRow = function(id) {
  _otcRows = _otcRows.filter(r => r.id !== id)
  otcRenderTable()
  otcUpdateSemaforo()
  otcUpdateWhatsApp()
  _otcSaveDraft()
}

function otcRenderTable() {
  const tbody = document.getElementById('otc-disp-body')
  const empty = document.getElementById('otc-disp-empty')
  const receiptsGrid = document.getElementById('otc-receipts-grid')
  const receiptsEmpty = document.getElementById('otc-receipts-empty')
  if (!tbody) return

  if (_otcRows.length === 0) {
    tbody.innerHTML = ''
    if (empty) empty.style.display = ''
    if (receiptsGrid) receiptsGrid.innerHTML = ''
    if (receiptsEmpty) receiptsEmpty.style.display = ''
    return
  }
  if (empty) empty.style.display = 'none'
  if (receiptsEmpty) receiptsEmpty.style.display = _otcRows.length ? 'none' : ''

  const contacts = (typeof getContacts === 'function') ? getContacts() : allNodes.filter(n => n.type === 'contact' || n.type === 'persona')
  const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;')

  let html = ''
  _otcRows.forEach((row, idx) => {
    const linkClass = row.projectTag ? ' otc-row-link' : ''
    html += '<tr class="' + linkClass + '" style="border-bottom:1px solid rgba(255,255,255,0.04);">'
    // Beneficiario — autocomplete
    html += '<td style="padding:6px;">'
    html += '<input type="text" class="modal-input" style="font-size:11px;padding:6px 8px;" placeholder="Nombre..." '
    html += 'value="' + esc(row.contactName) + '" '
    html += 'oninput="otcContactSearch(this,\'' + row.id + '\')" '
    html += 'onfocus="otcContactSearch(this,\'' + row.id + '\')" />'
    html += '<div id="otc-ac-' + row.id + '" style="position:relative;"></div>'
    html += '</td>'
    // Banco / CLABE
    html += '<td style="padding:6px;">'
    html += '<div style="font-size:10px;color:var(--text-muted);" id="otc-bank-' + row.id + '">' + (row.bank ? esc(row.bank) : '—') + '</div>'
    html += '<div style="font-size:10px;font-family:\'JetBrains Mono\',monospace;color:var(--text-dim);" id="otc-clabe-' + row.id + '">' + (row.clabe ? esc(row.clabe) : '') + '</div>'
    html += '</td>'
    // Tipo
    html += '<td style="padding:6px;text-align:center;">'
    html += '<select class="modal-input" style="font-size:10px;padding:4px 6px;width:70px;" onchange="otcChangeType(\'' + row.id + '\',this.value)">'
    html += '<option value="fixed"' + (row.assignType==='fixed'?' selected':'') + '>$ Fijo</option>'
    html += '<option value="pct"' + (row.assignType==='pct'?' selected':'') + '>% Porc.</option>'
    html += '</select>'
    html += '</td>'
    // Valor
    html += '<td style="padding:6px;">'
    html += '<input type="number" class="modal-input" style="font-size:11px;padding:6px 8px;text-align:right;width:100px;" '
    html += 'value="' + (row.value || '') + '" step="any" '
    html += 'oninput="otcChangeValue(\'' + row.id + '\',this.value)" />'
    html += '</td>'
    // Monto MXN calculado
    html += '<td style="padding:6px;text-align:right;">'
    html += '<span style="font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:700;color:#4ade80;" id="otc-monto-' + row.id + '">$' + _fmt$(row.montoMXN) + '</span>'
    html += '</td>'
    // Botones copiar
    html += '<td style="padding:6px;text-align:center;">'
    html += '<div style="display:flex;gap:3px;justify-content:center;">'
    html += '<button onclick="otcCopy(\'' + row.id + '\',\'clabe\')" style="background:none;border:1px solid var(--glass-border);border-radius:4px;padding:3px 5px;cursor:pointer;font-size:10px;color:var(--text-muted);" title="Copiar CLABE">📋C</button>'
    html += '<button onclick="otcCopy(\'' + row.id + '\',\'monto\')" style="background:none;border:1px solid var(--glass-border);border-radius:4px;padding:3px 5px;cursor:pointer;font-size:10px;color:var(--text-muted);" title="Copiar Monto">📋$</button>'
    html += '<button onclick="otcCopy(\'' + row.id + '\',\'concepto\')" style="background:none;border:1px solid var(--glass-border);border-radius:4px;padding:3px 5px;cursor:pointer;font-size:10px;color:var(--text-muted);" title="Copiar Concepto">📋T</button>'
    html += '</div>'
    html += '</td>'
    // Proyecto link
    html += '<td style="padding:6px;text-align:center;" id="otc-proj-' + row.id + '">'
    if (row.projectTag) {
      html += '<span style="font-size:10px;background:rgba(167,139,250,0.2);color:#c4b5fd;padding:2px 8px;border-radius:12px;cursor:pointer;" onclick="otcUnlinkProject(\'' + row.id + '\')" title="Desvincular">#' + esc(row.projectTag) + ' ✕</span>'
    }
    html += '</td>'
    // Delete
    html += '<td style="padding:6px;text-align:center;">'
    html += '<button onclick="otcRemoveRow(\'' + row.id + '\')" style="background:none;border:none;cursor:pointer;color:#f87171;font-size:14px;" title="Eliminar">✕</button>'
    html += '</td>'
    html += '</tr>'
  })
  tbody.innerHTML = html

  // Render receipts dropzones — multiple receipts per beneficiary
  if (receiptsGrid) {
    let rhtml = ''
    _otcRows.forEach(row => {
      const bName = row.contactName || 'Beneficiario ' + (_otcRows.indexOf(row)+1)
      rhtml += '<div style="border:1px dashed var(--glass-border);border-radius:10px;padding:12px;">'
      rhtml += '<div style="font-size:10px;color:var(--text-muted);font-weight:700;margin-bottom:8px;">' + esc(bName) + '</div>'
      // Show existing receipts as thumbnails/links
      if (row.receipts && row.receipts.length) {
        rhtml += '<div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:8px;">'
        row.receipts.forEach((rc, idx) => {
          rhtml += '<div style="position:relative;display:inline-block;">'
          if (rc.isUrl && !rc.data.match(/\.(png|jpg|jpeg|gif|webp|bmp)/i) && !rc.data.startsWith('data:')) {
            rhtml += '<a href="' + esc(rc.data) + '" target="_blank" style="color:#60a5fa;font-size:10px;text-decoration:underline;display:block;background:rgba(96,165,250,0.08);border:1px solid rgba(96,165,250,0.2);border-radius:6px;padding:4px 22px 4px 8px;">📄 Comp. ' + (idx+1) + '</a>'
          } else {
            rhtml += '<img src="' + esc(rc.data) + '" style="max-width:100px;max-height:80px;border-radius:6px;display:block;border:1px solid var(--glass-border);" onerror="this.style.display=\'none\'"/>'
          }
          rhtml += '<button onclick="event.stopPropagation();otcRemoveReceipt(\'' + row.id + '\',' + idx + ')" style="position:absolute;top:1px;right:2px;background:rgba(0,0,0,0.7);border:none;color:#f87171;border-radius:50%;width:18px;height:18px;cursor:pointer;font-size:10px;line-height:18px;text-align:center;padding:0;" title="Quitar">✕</button>'
          rhtml += '</div>'
        })
        rhtml += '</div>'
      }
      // Add controls: drag zone + URL input
      rhtml += '<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">'
      rhtml += '<div onclick="otcReceiptClick(\'' + row.id + '\')" style="cursor:pointer;color:var(--text-dim);font-size:10px;background:rgba(255,255,255,0.03);border:1px dashed rgba(255,255,255,0.15);border-radius:6px;padding:5px 10px;white-space:nowrap;" '
      rhtml += 'ondragover="event.preventDefault();this.style.borderColor=\'#00f6ff\'" '
      rhtml += 'ondragleave="this.style.borderColor=\'\'" '
      rhtml += 'ondrop="otcReceiptDrop(event,\'' + row.id + '\')">📎 + Agregar</div>'
      rhtml += '<input type="text" class="modal-input" style="font-size:10px;padding:4px 8px;flex:1;min-width:110px;" placeholder="🔗 URL de imagen/PDF..." '
      rhtml += 'id="otc-receipt-url-' + row.id + '" />'
      rhtml += '<button onclick="event.stopPropagation();otcReceiptUrl(\'' + row.id + '\')" style="background:rgba(96,165,250,0.15);border:1px solid rgba(96,165,250,0.3);border-radius:6px;padding:4px 8px;color:#60a5fa;font-size:10px;font-weight:700;cursor:pointer;">OK</button>'
      rhtml += '</div>'
      rhtml += '</div>'
    })
    receiptsGrid.innerHTML = rhtml
  }
}

// Contact autocomplete for OTC — uses fixed positioning to escape overflow containers
window.otcContactSearch = function(input, rowId) {
  const val = (input.value || '').toLowerCase().trim()
  const row = _otcRows.find(r => r.id === rowId)
  if (row) { row.contactName = input.value; row.contactId = '' }

  // Remove any existing dropdown
  const existing = document.getElementById('otc-ac-float')
  if (existing) existing.remove()

  if (val.length < 1) return

  const contacts = (typeof getContacts === 'function') ? getContacts() : allNodes.filter(n => n.type === 'contact' || n.type === 'persona')
  const matches = contacts.filter(c => {
    const name = (c.metadata?.name || c.content || '').toLowerCase().replace(/^#persona\s*/,'')
    const company = (c.metadata?.company || '').toLowerCase()
    return name.includes(val) || company.includes(val)
  }).slice(0, 6)

  if (matches.length === 0) return

  // Position dropdown using fixed positioning (escapes overflow-x:auto parent)
  const rect = input.getBoundingClientRect()
  const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;')
  const dd = document.createElement('div')
  dd.id = 'otc-ac-float'
  dd.setAttribute('data-row', rowId)
  dd.style.cssText = 'position:fixed;z-index:9999;background:var(--bg-panel,#0B132B);border:1px solid var(--glass-border);border-radius:8px;max-height:180px;overflow-y:auto;box-shadow:0 8px 30px rgba(0,0,0,0.6);'
  dd.style.top = (rect.bottom + 2) + 'px'
  dd.style.left = rect.left + 'px'
  dd.style.width = Math.max(rect.width, 220) + 'px'

  matches.forEach(c => {
    const name = c.metadata?.name || (c.content || '').replace(/^#persona\s*/,'')
    const accts = c.metadata?.contact_accounts || []
    const bankAcct = accts.find(a => a.type === 'bank') || accts[0]
    const desc = bankAcct ? (bankAcct.bank || bankAcct.label || '') : (c.metadata?.company || '')
    const item = document.createElement('div')
    item.style.cssText = 'padding:8px 10px;cursor:pointer;font-size:11px;border-bottom:1px solid rgba(255,255,255,0.04);display:flex;justify-content:space-between;align-items:center;'
    item.innerHTML = '<span style="color:#fff;font-weight:600;">' + esc(name) + '</span><span style="color:var(--text-dim);font-size:10px;">' + esc(desc) + '</span>'
    item.onmousedown = (e) => { e.preventDefault(); otcSelectContact(rowId, c.id) }
    item.onmouseenter = () => { item.style.background = 'rgba(0,246,255,0.08)' }
    item.onmouseleave = () => { item.style.background = '' }
    dd.appendChild(item)
  })

  document.body.appendChild(dd)

  // Close on blur (slight delay so click registers)
  const closeHandler = () => { setTimeout(() => { const el = document.getElementById('otc-ac-float'); if (el) el.remove() }, 150) }
  input.addEventListener('blur', closeHandler, { once: true })
}

window.otcSelectContact = function(rowId, contactId) {
  const row = _otcRows.find(r => r.id === rowId)
  if (!row) return
  const contact = allNodes.find(n => n.id === contactId)
  if (!contact) return

  const m = contact.metadata || {}
  row.contactId = contactId
  row.contactName = (m.name || contact.content || '').replace(/^#persona\s*/i, '')

  const accts = m.contact_accounts || []

  // Close autocomplete (both old div and new float)
  const acEl = document.getElementById('otc-ac-' + rowId)
  if (acEl) acEl.innerHTML = ''
  const floatAc = document.getElementById('otc-ac-float')
  if (floatAc) floatAc.remove()

  // If contact has multiple accounts, show account picker
  if (accts.length > 1) {
    _otcShowAccountPicker(rowId, row, accts)
  } else {
    // Single account or none — auto-select
    const bankAcct = accts.find(a => a.type === 'bank') || accts[0]
    if (bankAcct) {
      row.bank  = bankAcct.bank || bankAcct.label || ''
      row.clabe = bankAcct.clabe || bankAcct.wallet || ''
    } else {
      row.bank  = m.bank_name || ''
      row.clabe = m.clabe || ''
    }
    _otcDetectProjectLink(row)
    otcRenderTable()
    otcUpdateSemaforo()
    otcUpdateWhatsApp()
    _otcSaveDraft()
  }
}

// Account picker for contacts with multiple accounts
function _otcShowAccountPicker(rowId, row, accts) {
  const existingPicker = document.getElementById('otc-acct-picker')
  if (existingPicker) existingPicker.remove()

  // Find the row's name input to position the picker
  const tbody = document.getElementById('otc-disp-body')
  if (!tbody) return
  const inputs = tbody.querySelectorAll('input[type="text"]')
  let targetInput = null
  inputs.forEach(inp => { if (inp.value === row.contactName) targetInput = inp })
  if (!targetInput) targetInput = inputs[0]
  const rect = targetInput ? targetInput.getBoundingClientRect() : { bottom: 200, left: 100, width: 250 }

  const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;')
  const picker = document.createElement('div')
  picker.id = 'otc-acct-picker'
  picker.style.cssText = 'position:fixed;z-index:9999;background:var(--bg-panel,#0B132B);border:1px solid rgba(0,246,255,0.3);border-radius:12px;max-height:220px;overflow-y:auto;box-shadow:0 8px 30px rgba(0,0,0,0.6);padding:6px;'
  picker.style.top = (rect.bottom + 4) + 'px'
  picker.style.left = rect.left + 'px'
  picker.style.width = Math.max(rect.width + 80, 300) + 'px'

  const header = document.createElement('div')
  header.style.cssText = 'padding:6px 10px;font-size:10px;font-weight:800;color:var(--text-muted);letter-spacing:0.06em;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,0.06);margin-bottom:4px;'
  header.textContent = '🏦 Selecciona cuenta de ' + row.contactName
  picker.appendChild(header)

  const accIcon = { bank:'🏦', crypto:'₿', cash:'💵' }
  accts.forEach((acct, idx) => {
    const item = document.createElement('div')
    item.style.cssText = 'padding:10px 12px;cursor:pointer;font-size:11px;border-radius:8px;margin-bottom:2px;transition:background 0.15s;'
    const icon = accIcon[acct.type] || '💳'
    const label = acct.bank || acct.network || acct.label || acct.type || 'Cuenta ' + (idx+1)
    const detail = acct.clabe || acct.wallet || ''
    const last6 = detail.length > 6 ? '···' + detail.slice(-6) : detail
    item.innerHTML = '<div style="display:flex;align-items:center;gap:8px;">'
      + '<span style="font-size:16px;">' + icon + '</span>'
      + '<div style="flex:1;"><div style="font-weight:700;color:#fff;">' + esc(label) + '</div>'
      + '<div style="font-size:10px;color:var(--text-dim);font-family:\'JetBrains Mono\',monospace;">' + esc(detail) + '</div></div>'
      + '</div>'
    item.onmouseenter = () => { item.style.background = 'rgba(0,246,255,0.08)' }
    item.onmouseleave = () => { item.style.background = '' }
    item.onmousedown = (e) => {
      e.preventDefault()
      row.bank  = acct.bank || acct.network || acct.label || ''
      row.clabe = acct.clabe || acct.wallet || ''
      picker.remove()
      _otcDetectProjectLink(row)
      otcRenderTable()
      otcUpdateSemaforo()
      otcUpdateWhatsApp()
      _otcSaveDraft()
    }
    picker.appendChild(item)
  })

  document.body.appendChild(picker)

  // Auto-close on click outside
  setTimeout(() => {
    const closer = (e) => {
      if (!picker.contains(e.target)) { picker.remove(); document.removeEventListener('mousedown', closer) }
    }
    document.addEventListener('mousedown', closer)
  }, 100)
}

function _otcDetectProjectLink(row) {
  if (!row.contactId) return
  // Find cotizaciones or expenses linked to this contact in any project
  const projects = allNodes.filter(n => n.type === 'proyecto')
  const cots = allNodes.filter(n => n.type === 'cotizacion' && n.metadata?.provider_id === row.contactId)
  const pendingCot = cots.find(c => {
    const m = c.metadata || {}
    const total = +(m.total || m.amount || 0)
    const paid = (m.abonos || []).reduce((s,a) => s + (+(a.amount||0)), 0)
    return paid < total
  })
  if (pendingCot) {
    const projTag = pendingCot.metadata?.project_tag || ''
    if (projTag) {
      row.projectTag = projTag
      row._pendingCotId = pendingCot.id
    }
  }
}

window.otcUnlinkProject = function(rowId) {
  const row = _otcRows.find(r => r.id === rowId)
  if (row) { row.projectTag = ''; row._pendingCotId = '' }
  otcRenderTable()
}

window.otcChangeType = function(rowId, type) {
  const row = _otcRows.find(r => r.id === rowId)
  if (row) { row.assignType = type; row.value = 0; row.montoMXN = 0 }
  otcRenderTable()
  otcUpdateSemaforo()
  otcUpdateWhatsApp()
}

window.otcChangeValue = function(rowId, val) {
  const row = _otcRows.find(r => r.id === rowId)
  if (!row) return
  row.value = parseFloat(val) || 0
  if (row.assignType === 'pct') {
    row.montoMXN = _floor2(_otcData.ventaReportada * (row.value / 100))
  } else {
    row.montoMXN = _floor2(row.value)
  }
  const montoEl = document.getElementById('otc-monto-' + rowId)
  if (montoEl) montoEl.textContent = '$' + _fmt$(row.montoMXN)
  otcUpdateSemaforo()
  otcUpdateWhatsApp()
  _otcSaveDraft()
}

// Copy helpers
window.otcCopy = function(rowId, what) {
  const row = _otcRows.find(r => r.id === rowId)
  if (!row) return
  let text = ''
  const ref = document.getElementById('otc-ref')?.value.trim() || ('OTC-' + new Date().toISOString().slice(0,10).replace(/-/g,''))
  if (what === 'clabe') text = row.clabe || ''
  else if (what === 'monto') text = row.montoMXN.toFixed(2)
  else if (what === 'concepto') text = (row.projectTag ? row.projectTag.toUpperCase() + ' - ' : '') + ref
  if (text) {
    navigator.clipboard.writeText(text).then(() => showToast('Copiado: ' + text.slice(0,30)))
  }
}

// ═══════════════════════════════════════════════════════════════════
// ORQUESTADOR OTC — SEMÁFORO
// ═══════════════════════════════════════════════════════════════════
function otcUpdateSemaforo() {
  const total = _otcData.ventaReportada
  const assigned = _otcRows.reduce((s,r) => s + r.montoMXN, 0)
  const pct = total > 0 ? (assigned / total) * 100 : 0
  const remaining = _floor2(total - assigned)

  const bar   = document.getElementById('otc-sema-bar')
  const label = document.getElementById('otc-sema-label')
  const pctEl = document.getElementById('otc-sema-pct')
  const msg   = document.getElementById('otc-sema-msg')
  if (!bar) return

  bar.style.width = Math.min(pct, 100) + '%'

  if (pct < 100 - 0.001) {
    bar.className = 'otc-sema-yellow'
    if (label) { label.textContent = 'Saldo sin asignar'; label.style.color = '#fbbf24' }
    if (pctEl) { pctEl.textContent = pct.toFixed(1) + '%'; pctEl.style.color = '#fbbf24' }
    if (msg) { msg.textContent = 'Restante: $' + _fmt$(remaining) + ' MXN'; msg.style.color = '#fbbf24' }
  } else if (pct <= 100 + 0.001) {
    bar.className = 'otc-sema-green'
    if (label) { label.textContent = 'Fondos asignados a la perfección'; label.style.color = '#4ade80' }
    if (pctEl) { pctEl.textContent = '100%'; pctEl.style.color = '#4ade80' }
    if (msg) { msg.textContent = 'Listo para dispersar'; msg.style.color = '#4ade80' }
  } else {
    bar.className = 'otc-sema-red'
    if (label) { label.textContent = 'Error: Exceso de fondos'; label.style.color = '#f87171' }
    if (pctEl) { pctEl.textContent = pct.toFixed(1) + '%'; pctEl.style.color = '#f87171' }
    if (msg) { msg.textContent = 'Exceso: $' + _fmt$(Math.abs(remaining)) + ' MXN en negativo'; msg.style.color = '#f87171' }
  }

  // Update the prominent remaining strip below table
  const strip = document.getElementById('otc-remaining-strip')
  const stripVal = document.getElementById('otc-remaining-val')
  if (strip && stripVal) {
    if (_otcRows.length > 0 && total > 0) {
      strip.style.display = 'flex'
      stripVal.textContent = '$' + _fmt$(remaining)
      if (pct >= 100 - 0.001 && pct <= 100 + 0.001) {
        strip.style.borderColor = 'rgba(74,222,128,0.3)'
        strip.style.background = 'rgba(74,222,128,0.08)'
        stripVal.style.color = '#4ade80'
      } else if (pct > 100) {
        strip.style.borderColor = 'rgba(248,113,113,0.3)'
        strip.style.background = 'rgba(248,113,113,0.08)'
        stripVal.style.color = '#f87171'
      } else {
        strip.style.borderColor = 'rgba(251,191,36,0.25)'
        strip.style.background = 'rgba(251,191,36,0.08)'
        stripVal.style.color = '#fbbf24'
      }
    } else {
      strip.style.display = 'none'
    }
  }
}

// ═══════════════════════════════════════════════════════════════════
// ORQUESTADOR OTC — BLOQUE C: WHATSAPP MESSAGE
// ═══════════════════════════════════════════════════════════════════
function otcUpdateWhatsApp() {
  const el = document.getElementById('otc-wa-preview')
  if (!el) return
  if (_otcData.ventaReportada <= 0 || _otcRows.length === 0) {
    el.textContent = 'Completa la operación y la tabla de dispersión para generar el mensaje.'
    return
  }
  const coin = document.getElementById('otc-coin')?.value || 'USDT'
  const qty  = document.getElementById('otc-qty')?.value || '0'
  const tc   = document.getElementById('otc-tc')?.value || '0'
  const feeR = document.getElementById('otc-fee-reported')?.value || '0.90'

  let msg = ''
  msg += '📊 PRE-APROBACIÓN DE OPERACIÓN - OTC Nexus OS\n'
  msg += '---------------------------------------------\n'
  msg += '• Recibido: ' + qty + ' ' + coin + ' @ $' + tc + '\n'
  msg += '• Venta Total MXN: $' + _fmt$(_otcData.ventaBruta) + '\n'
  msg += '• Comisión Operación (' + feeR + '%): $' + _fmt$(_otcData.comisionCliente) + '\n'
  msg += '• TOTAL DISPONIBLE PARA REPARTO: $' + _fmt$(_otcData.ventaReportada) + '\n'
  msg += '\nPROPUESTA DE DISPERSIÓN BANCARIA:\n'
  _otcRows.forEach((row, i) => {
    msg += (i+1) + '. ' + (row.contactName || 'Beneficiario') + '\n'
    msg += '   💰 Monto: $' + _fmt$(row.montoMXN) + ' MXN\n'
    msg += '   🏦 Banco: ' + (row.bank||'—') + '\n'
    msg += '   🔢 CLABE: ' + (row.clabe||'—') + '\n'
    if (row.projectTag) msg += '   📂 Proyecto: #' + row.projectTag + '\n'
    msg += '\n'
  })
  const totalAssigned = _otcRows.reduce((s,r) => s + r.montoMXN, 0)
  msg += '📊 TOTAL A DISPERSAR: $' + _fmt$(totalAssigned) + ' MXN\n'
  msg += '💰 RESTANTE: $' + _fmt$(_otcData.ventaReportada - totalAssigned) + ' MXN\n'
  msg += '\n¿Confirmado el esquema y las cuentas para proceder con los SPEI?'

  el.textContent = msg
}

window.otcCopyWhatsApp = function() {
  const el = document.getElementById('otc-wa-preview')
  if (!el) return
  navigator.clipboard.writeText(el.textContent).then(() => showToast('Mensaje copiado al portapapeles'))
}

// ═══════════════════════════════════════════════════════════════════
// ORQUESTADOR OTC — BLOQUE D: RECEIPTS + PDF EXPORT
// ═══════════════════════════════════════════════════════════════════
window.otcReceiptDrop = function(ev, rowId) {
  ev.preventDefault()
  ev.currentTarget.style.borderColor = ''
  const file = ev.dataTransfer?.files?.[0]
  if (file && (file.type.startsWith('image/') || file.type === 'application/pdf')) {
    _otcReadReceiptFile(file, rowId)
  } else {
    const text = ev.dataTransfer?.getData('text/plain') || ''
    if (text.startsWith('http')) {
      const row = _otcRows.find(r => r.id === rowId)
      if (row) { if (!row.receipts) row.receipts = []; row.receipts.push({ data: text, isUrl: true }) }
      otcRenderTable(); _otcSaveDraft()
    } else {
      showToast('Arrastra una imagen, PDF o URL')
    }
  }
}

window.otcReceiptClick = function(rowId) {
  const inp = document.createElement('input')
  inp.type = 'file'; inp.accept = 'image/*,application/pdf'
  inp.onchange = () => { if (inp.files[0]) _otcReadReceiptFile(inp.files[0], rowId) }
  inp.click()
}

window.otcReceiptUrl = function(rowId) {
  const input = document.getElementById('otc-receipt-url-' + rowId)
  if (!input) return
  const url = input.value.trim()
  if (!url || !url.startsWith('http')) { showToast('Ingresa una URL válida (http/https)'); return }
  const row = _otcRows.find(r => r.id === rowId)
  if (row) { if (!row.receipts) row.receipts = []; row.receipts.push({ data: url, isUrl: true }) }
  input.value = ''
  otcRenderTable(); _otcSaveDraft()
  showToast('Comprobante vinculado')
}

function _otcReadReceiptFile(file, rowId) {
  const reader = new FileReader()
  reader.onload = () => {
    const row = _otcRows.find(r => r.id === rowId)
    if (row) { if (!row.receipts) row.receipts = []; row.receipts.push({ data: reader.result, isUrl: false }) }
    otcRenderTable(); _otcSaveDraft()
  }
  reader.readAsDataURL(file)
}

window.otcRemoveReceipt = function(rowId, idx) {
  const row = _otcRows.find(r => r.id === rowId)
  if (row && row.receipts) row.receipts.splice(idx, 1)
  otcRenderTable()
}

window.otcExportPDF = function() {
  if (_otcData.ventaReportada <= 0) { showToast('Calcula la operación primero'); return }
  const coin = document.getElementById('otc-coin')?.value || 'USDT'
  const qty  = parseFloat(document.getElementById('otc-qty')?.value  || '0')
  const tc   = parseFloat(document.getElementById('otc-tc')?.value   || '0')
  const feeR = parseFloat(document.getElementById('otc-fee-reported')?.value || '0')
  const ref  = document.getElementById('otc-ref')?.value.trim() || ('OTC-' + new Date().toISOString().slice(0,10).replace(/-/g,''))

  // Aplica comisión del 0.90 (o la que esté configurada) para mostrar
  // el USDT real entregado al beneficiario.
  // Si feeR = 0.90 (%), comisión = 0.009, factor = 1 - 0.009 = 0.991.
  // Si feeR = 10 (%), comisión = 0.10, factor = 0.90.
  const commissionFactor = 1 - (feeR / 100)

  const pdfData = {
    orqName: ref,
    coin,
    tc,
    rows: _otcRows.map(row => ({
      beneficiario: row.contactName || 'Sin nombre',
      banco:        row.bank   || '—',
      clabe:        row.clabe  || '',
      // USDT que el beneficiario recibió (post-comisión 0.90)
      cantidad:     tc > 0 ? _floor2((row.montoMXN / tc) * commissionFactor) : 0,
      moneda:       coin,
      neto:         row.montoMXN,
      // Pasa las URLs de comprobantes (string http o {data, isUrl})
      comprobantes: row.receipts || [],
      comprobante:  (row.receipts?.length || 0) > 0,
      fecha:        row.fecha || new Date().toISOString(),
    })),
    totals: {
      usdt: qty,
      neto: _otcData.ventaReportada,
    },
  }

  showToast('⏳ Generando PDF...')
  setTimeout(() => {
    try {
      pdfDispersionOTC(pdfData, new Date(), getEmisor())
      showToast('✅ PDF descargado')
    } catch (e) {
      console.error('pdfDispersionOTC:', e)
      showToast('❌ Error: ' + e.message)
    }
  }, 50)
  // (legacy HTML window removed — replaced by jsPDF pdfDispersionOTC above)
  return
}

// Save OTC operation to Nexus nodes
window.otcSaveToNodes = async function() {
  if (_otcData.ventaReportada <= 0) { showToast('Calcula la operación primero'); return }
  const coin = document.getElementById('otc-coin')?.value || 'USDT'
  const qty  = document.getElementById('otc-qty')?.value || '0'
  const tc   = document.getElementById('otc-tc')?.value || '0'
  const ref  = document.getElementById('otc-ref')?.value.trim() || ('OTC-' + new Date().toISOString().slice(0,10).replace(/-/g,''))

  // For each row linked to a project, inject as expense
  for (const row of _otcRows) {
    if (row.projectTag && row._pendingCotId && row.montoMXN > 0) {
      // Register as abono on the cotización
      const cotNode = allNodes.find(n => n.id === row._pendingCotId)
      if (cotNode) {
        const abonos = cotNode.metadata?.abonos || []
        abonos.push({
          date: new Date().toISOString().slice(0,10),
          amount: row.montoMXN,
          method: 'SPEI',
          note: 'OTC dispersión — ' + ref,
          receipt_url: row.receipts?.[0]?.data || ''
        })
        cotNode.metadata.abonos = abonos
        if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
          await supabase.from('nodes').update({ metadata: cotNode.metadata }).eq('id', cotNode.id)
        }
      }
    }
  }

  // ── Save operation history as a Nexus node ──
  const now = new Date()
  const autoName = now.toLocaleDateString('es-MX',{day:'2-digit',month:'short',year:'numeric'}) + ' '
                 + now.toLocaleTimeString('es-MX',{hour:'2-digit',minute:'2-digit'}) + ' — '
                 + qty + ' ' + coin + ' ($' + _fmt$(_otcData.ventaReportada) + ')'
  const histNode = {
    id: 'otc_' + Date.now() + '_' + Math.random().toString(36).slice(2,6),
    owner_id: (typeof currentUser !== 'undefined' && currentUser?.id) || '',
    content: autoName,
    type: 'note',
    metadata: {
      is_otc_history: true,
      otc_ref: ref,
      coin, qty: parseFloat(qty), tc: parseFloat(tc),
      feeReported: parseFloat(document.getElementById('otc-fee-reported')?.value || '0.90'),
      ventaBruta: _otcData.ventaBruta,
      comisionCliente: _otcData.comisionCliente,
      ventaReportada: _otcData.ventaReportada,
      gananciaOp: _otcData.gananciaOp,
      rows: _otcRows.map(r => ({ contactId:r.contactId, contactName:r.contactName, bank:r.bank, clabe:r.clabe, montoMXN:r.montoMXN, projectTag:r.projectTag, receipts:r.receipts||[] })),
      saved_at: now.toISOString()
    },
    created_at: now.toISOString()
  }

  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    const { data, error } = await supabase.from('nodes').insert([{
      owner_id: histNode.owner_id, content: histNode.content, type: 'note', metadata: histNode.metadata
    }]).select()
    if (data?.[0]) histNode.id = data[0].id
    if (error) console.warn('OTC history save error', error)
  }
  allNodes.push(histNode)

  _otcClearDraft()  // Clear draft after successful save
  showToast('Operación guardada — ' + _otcRows.filter(r=>r.projectTag).length + ' pagos vinculados a proyectos')
  renderOtcHistory()
  if (typeof renderAll === 'function') renderAll()
}

// ── OTC History Render ──────────────────────────────────────────
function renderOtcHistory() {
  const list  = document.getElementById('otc-history-list')
  const empty = document.getElementById('otc-history-empty')
  if (!list) return

  const ops = allNodes.filter(n => n.metadata?.is_otc_history === true)
    .sort((a,b) => new Date(b.metadata?.saved_at || b.created_at) - new Date(a.metadata?.saved_at || a.created_at))

  if (ops.length === 0) {
    list.innerHTML = ''
    if (empty) empty.style.display = ''
    return
  }
  if (empty) empty.style.display = 'none'

  const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;')
  // Update count badge on OTC tab
  const otcTabBadgeEl = document.getElementById('otc-hist-count')
  if (otcTabBadgeEl) {
    otcTabBadgeEl.textContent = ops.length
    otcTabBadgeEl.style.display = ops.length > 0 ? '' : 'none'
  }

  let h = ''
  ops.forEach(op => {
    const m = op.metadata || {}
    const rows = m.rows || []
    const benefCount = rows.length
    const totalDisp = rows.reduce((s,r) => s + (r.montoMXN||0), 0)
    const ventaBruta = m.ventaReportada || m.ventaBruta || 0
    const pct = ventaBruta > 0 ? Math.min((totalDisp / ventaBruta) * 100, 100) : 100
    // Status badge
    let statusColor = '#4ade80'; let statusLabel = 'Completada'
    if (pct < 99)       { statusColor = '#fbbf24'; statusLabel = `${pct.toFixed(0)}% dispersado` }
    if (benefCount === 0){ statusColor = '#94a3b8'; statusLabel = 'Sin beneficiarios' }
    const d = new Date(m.saved_at || op.created_at)
    const dateStr = d.toLocaleDateString('es-MX',{day:'2-digit',month:'short',year:'numeric'}) + ' ' + d.toLocaleTimeString('es-MX',{hour:'2-digit',minute:'2-digit'})
    h += `<div style="display:flex;align-items:center;gap:12px;padding:12px 14px;background:var(--bg-surface);border:1px solid rgba(255,255,255,0.06);border-radius:12px;margin-bottom:8px;transition:all 0.2s;cursor:pointer;"
      onmouseenter="this.style.borderColor='rgba(167,139,250,0.35)';this.style.background='rgba(255,255,255,0.03)'"
      onmouseleave="this.style.borderColor='rgba(255,255,255,0.06)';this.style.background='var(--bg-surface)'"
      onclick="otcViewHistory('${esc(op.id)}')">`
    h += `<div style="width:40px;height:40px;border-radius:10px;background:rgba(167,139,250,0.12);display:grid;place-items:center;font-size:18px;flex-shrink:0;">📊</div>`
    h += `<div style="flex:1;min-width:0;">`
    h += `<div style="display:flex;align-items:center;gap:6px;margin-bottom:2px;">`
    h += `<div style="font-size:13px;font-weight:700;color:var(--text-main);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${esc(m.otc_ref||'OTC')} — ${esc(m.coin||'')}</div>`
    h += `<span style="font-size:10px;font-weight:700;color:${statusColor};background:${statusColor}22;border:1px solid ${statusColor}44;border-radius:20px;padding:1px 8px;flex-shrink:0;">${statusLabel}</span>`
    h += `</div>`
    h += `<div style="font-size:11px;color:var(--text-muted);">${dateStr} · ${benefCount} beneficiario${benefCount!==1?'s':''}</div>`
    h += `</div>`
    h += `<div style="text-align:right;flex-shrink:0;">`
    h += `<div style="font-size:15px;font-weight:800;color:#4ade80;font-family:'JetBrains Mono',monospace;">$${_fmt$(totalDisp)}</div>`
    h += `<div style="font-size:10px;color:var(--text-dim);">dispersado</div>`
    h += `</div>`
    h += `<div style="display:flex;flex-direction:column;gap:4px;flex-shrink:0;" onclick="event.stopPropagation()">`
    h += `<button onclick="otcReopenHistory('${esc(op.id)}')" class="otc-btn-reopen" title="Reabrir para editar">↩ Reabrir</button>`
    h += `<button onclick="otcDeleteHistory('${esc(op.id)}')" style="background:none;border:1px solid rgba(248,113,113,0.2);color:#f87171;border-radius:6px;padding:3px 8px;cursor:pointer;font-size:10px;font-weight:600;">🗑</button>`
    h += `</div>`
    h += `</div>`
  })
  list.innerHTML = h
}

window.otcViewHistory = function(nodeId) {
  const op = allNodes.find(n => n.id === nodeId)
  if (!op || !op.metadata?.is_otc_history) return
  const m = op.metadata
  const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;')
  const rows = m.rows || []
  const d = new Date(m.saved_at || op.created_at)
  const dateStr = d.toLocaleDateString('es-MX',{weekday:'long',day:'numeric',month:'long',year:'numeric'})
  const timeStr = d.toLocaleTimeString('es-MX',{hour:'2-digit',minute:'2-digit',second:'2-digit'})
  const totalDisp = rows.reduce((s,r) => s + (r.montoMXN||0), 0)
  const pctDisp = (m.ventaReportada||0) > 0 ? Math.min((totalDisp / m.ventaReportada) * 100, 100) : 100
  const remaining = _floor2((m.ventaReportada||0) - totalDisp)
  const statusColor = remaining <= 0.01 && remaining >= -0.01 ? '#16a34a' : remaining > 0 ? '#d97706' : '#dc2626'
  const statusText  = remaining <= 0.01 && remaining >= -0.01 ? '✅ COMPLETO' : remaining > 0 ? '⏳ PENDIENTE' : '🔴 EXCESO'
  const linkedProjects = [...new Set(rows.filter(r=>r.projectTag).map(r=>r.projectTag))]
  const feeR = m.feeReported ?? 0.90

  let rowsHtml = ''
  rows.forEach((r, i) => {
    const projBadge = r.projectTag ? '<span style="background:#ede9fe;color:#7c3aed;padding:1px 6px;border-radius:4px;font-size:9px;font-weight:700;">#' + esc(r.projectTag) + '</span>' : '<span style="color:#ccc;">—</span>'
    const recCount = r.receipts?.length || 0
    const receiptBadge = recCount > 0 ? '<span style="color:#16a34a;font-size:10px;font-weight:700;">✅ ' + recCount + '</span>' : '<span style="color:#ccc;font-size:10px;">—</span>'
    rowsHtml += '<tr style="border-bottom:1px solid #f1f5f9;">'
    rowsHtml += '<td style="padding:8px;font-weight:700;color:#64748b;">' + (i+1) + '</td>'
    rowsHtml += '<td style="padding:8px;font-weight:700;">' + esc(r.contactName||'Sin nombre') + '</td>'
    rowsHtml += '<td style="padding:8px;">' + esc(r.bank||'—') + '</td>'
    rowsHtml += '<td style="padding:8px;font-family:\'Courier New\',monospace;font-size:11px;letter-spacing:0.03em;">' + esc(r.clabe||'—') + '</td>'
    rowsHtml += '<td style="padding:8px;text-align:right;font-weight:800;font-size:13px;">$' + _fmt$(r.montoMXN||0) + '</td>'
    rowsHtml += '<td style="padding:8px;text-align:center;">' + projBadge + '</td>'
    rowsHtml += '<td style="padding:8px;text-align:center;">' + receiptBadge + '</td>'
    rowsHtml += '</tr>'
  })

  let h = '<!DOCTYPE html><html><head><meta charset="utf-8"/>'
  h += '<title>OTC — ' + esc(m.otc_ref||'') + '</title>'
  h += '<style>'
  h += '*{box-sizing:border-box;margin:0;padding:0}'
  h += 'body{font-family:"Segoe UI",system-ui,sans-serif;max-width:900px;margin:0 auto;padding:30px;color:#1e293b;font-size:13px;}'
  h += 'table{width:100%;border-collapse:collapse;} th{text-align:left;padding:8px;background:#f8fafc;font-size:10px;color:#64748b;font-weight:700;text-transform:uppercase;letter-spacing:.05em;border-bottom:2px solid #e2e8f0;}'
  h += '.kpi-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:20px;}'
  h += '.kpi{background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;padding:14px;text-align:center;}'
  h += '.kpi-l{font-size:9px;font-weight:800;color:#94a3b8;letter-spacing:.5px;text-transform:uppercase;} .kpi-v{font-size:20px;font-weight:800;margin-top:6px;} .kpi-s{font-size:9px;color:#94a3b8;margin-top:2px;}'
  h += '.bar-bg{height:10px;background:#e2e8f0;border-radius:5px;overflow:hidden;margin-top:6px;} .bar-fill{height:100%;border-radius:5px;}'
  h += '.badge{display:inline-block;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:700;}'
  h += '@media print{body{padding:12px;}}'
  h += '</style></head><body>'

  // Header
  h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #0f172a;padding-bottom:16px;margin-bottom:24px;">'
  h += '<div>'
  h += '<h1 style="font-size:22px;font-weight:900;color:#0f172a;margin-bottom:4px;">📊 Estado de Cuenta — Operación OTC</h1>'
  h += '<div style="font-size:12px;color:#64748b;margin-bottom:2px;">📝 Referencia: <b style="color:#0f172a;">' + esc(m.otc_ref||'') + '</b></div>'
  h += '<div style="font-size:12px;color:#64748b;">📅 ' + dateStr + ' · ⏰ ' + timeStr + '</div>'
  if (linkedProjects.length) h += '<div style="margin-top:6px;">' + linkedProjects.map(p => '<span class="badge" style="background:#ede9fe;color:#7c3aed;">📂 #' + esc(p) + '</span>').join(' ') + '</div>'
  h += '</div>'
  h += '<div style="text-align:right;"><div style="font-size:18px;font-weight:900;color:#0f172a;">NEXUS OS</div><div style="font-size:10px;color:#94a3b8;">Histórico OTC</div>'
  h += '<div class="badge" style="margin-top:6px;background:' + (statusColor==='#16a34a'?'#dcfce7':'#fef3c7') + ';color:' + statusColor + ';">' + statusText + '</div>'
  h += '</div></div>'

  // KPIs
  h += '<div class="kpi-grid">'
  h += '<div class="kpi"><div class="kpi-l">💱 Recibido</div><div class="kpi-v">' + esc(m.qty||0) + '</div><div class="kpi-s">' + esc(m.coin||'') + '</div></div>'
  h += '<div class="kpi"><div class="kpi-l">📈 Tipo de Cambio</div><div class="kpi-v">$' + (m.tc||0).toFixed(2) + '</div><div class="kpi-s">MXN</div></div>'
  h += '<div class="kpi"><div class="kpi-l">💰 Venta Bruta</div><div class="kpi-v">$' + _fmt$(m.ventaBruta||0) + '</div></div>'
  h += '<div class="kpi"><div class="kpi-l">📊 Comisión (' + feeR + '%)</div><div class="kpi-v" style="color:#d97706;">$' + _fmt$(m.comisionCliente||0) + '</div></div>'
  h += '<div class="kpi" style="border-color:#16a34a;"><div class="kpi-l">✅ Neto Dispersado</div><div class="kpi-v" style="color:#16a34a;">$' + _fmt$(m.ventaReportada||0) + '</div></div>'
  h += '</div>'

  // Progress bar
  h += '<div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;padding:14px 18px;margin-bottom:20px;">'
  h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">'
  h += '<span style="font-size:11px;font-weight:700;color:#64748b;">Dispersión Total</span>'
  h += '<span style="font-size:13px;font-weight:800;color:' + statusColor + ';">' + pctDisp.toFixed(1) + '% — $' + _fmt$(totalDisp) + '</span>'
  h += '</div>'
  h += '<div class="bar-bg"><div class="bar-fill" style="width:' + pctDisp.toFixed(1) + '%;background:' + statusColor + ';"></div></div>'
  h += '</div>'

  // Table
  h += '<div style="margin-bottom:20px;">'
  h += '<div style="font-size:12px;font-weight:800;color:#0f172a;margin-bottom:8px;">💸 Detalle — ' + rows.length + ' beneficiario' + (rows.length!==1?'s':'') + '</div>'
  h += '<table><thead><tr><th>#</th><th>Beneficiario</th><th>Banco</th><th>CLABE / Cuenta</th><th style="text-align:right;">Monto MXN</th><th style="text-align:center;">Proyecto</th><th style="text-align:center;">SPEI</th></tr></thead>'
  h += '<tbody>' + rowsHtml + '</tbody>'
  h += '<tfoot><tr style="border-top:3px solid #0f172a;background:#f8fafc;"><td colspan="4" style="padding:10px 8px;text-align:right;font-weight:800;font-size:12px;">TOTAL DISPERSADO:</td>'
  h += '<td style="padding:10px 8px;text-align:right;font-size:16px;font-weight:900;">$' + _fmt$(totalDisp) + '</td><td colspan="2"></td></tr></tfoot>'
  h += '</table></div>'

  // Per-beneficiary bars
  if (rows.length > 1) {
    h += '<div style="margin-bottom:20px;"><div style="font-size:12px;font-weight:800;color:#0f172a;margin-bottom:10px;">📊 Distribución por Beneficiario</div>'
    rows.forEach(r => {
      const pct = totalDisp > 0 ? (r.montoMXN / totalDisp * 100) : 0
      h += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">'
      h += '<div style="font-size:11px;font-weight:600;min-width:120px;text-align:right;color:#475569;">' + esc(r.contactName||'—') + '</div>'
      h += '<div style="flex:1;height:18px;background:#f1f5f9;border-radius:4px;overflow:hidden;position:relative;">'
      h += '<div style="height:100%;width:' + pct.toFixed(1) + '%;background:linear-gradient(90deg,#3b82f6,#60a5fa);border-radius:4px;"></div>'
      h += '<span style="position:absolute;right:6px;top:1px;font-size:10px;font-weight:700;color:#475569;">' + pct.toFixed(1) + '%</span>'
      h += '</div>'
      h += '<div style="font-size:11px;font-weight:700;min-width:80px;text-align:right;">$' + _fmt$(r.montoMXN||0) + '</div>'
      h += '</div>'
    })
    h += '</div>'
  }

  // Receipts
  const rowsWithRec = rows.filter(r => r.receipts?.length)
  if (rowsWithRec.length) {
    h += '<div style="margin-bottom:20px;"><div style="font-size:12px;font-weight:800;color:#0f172a;margin-bottom:10px;">🧾 Comprobantes SPEI</div>'
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;">'
    rowsWithRec.forEach(r => {
      ;(r.receipts||[]).forEach((rc, idx) => {
        h += '<div style="border:1px solid #e2e8f0;border-radius:10px;padding:12px;text-align:center;">'
        h += '<div style="font-size:11px;font-weight:700;margin-bottom:6px;">' + esc(r.contactName) + ' · $' + _fmt$(r.montoMXN||0) + (r.receipts.length>1?' · #'+(idx+1):'') + '</div>'
        if (rc.isUrl && !rc.data.match(/\.(png|jpg|jpeg|gif|webp)/i) && !rc.data.startsWith('data:')) {
          h += '<a href="' + esc(rc.data) + '" target="_blank" style="color:#3b82f6;font-size:11px;">🔗 Ver comprobante</a>'
        } else {
          h += '<img src="' + rc.data + '" style="max-width:100%;max-height:250px;border-radius:6px;"/>'
        }
        h += '</div>'
      })
    })
    h += '</div></div>'
  }

  // Footer
  h += '<div style="text-align:center;margin-top:30px;padding-top:14px;border-top:2px solid #e2e8f0;color:#94a3b8;font-size:10px;">'
  h += 'Nexus OS — Histórico OTC · ' + dateStr + ' · ' + timeStr
  h += '</div></body></html>'

  const win = window.open('', '_blank')
  if (win) { win.document.write(h); win.document.close(); setTimeout(() => win.print(), 400) }
}

window.otcDeleteHistory = async function(nodeId) {
  const idx = allNodes.findIndex(n => n.id === nodeId)
  if (idx === -1) return
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').delete().eq('id', nodeId)
  }
  allNodes.splice(idx, 1)
  renderOtcHistory()
  showToast('Operación eliminada del histórico')
}

// ═══════════════════════════════════════════════════════════════════
// ORQUESTADOR OTC — DRAFT PERSISTENCE (localStorage)
// ═══════════════════════════════════════════════════════════════════
const OTC_DRAFT_KEY = 'nexus_otc_draft'

function _otcSaveDraft() {
  // Only save when there's meaningful data
  const coin = document.getElementById('otc-coin')?.value || 'USDT'
  const qty  = document.getElementById('otc-qty')?.value || ''
  const tc   = document.getElementById('otc-tc')?.value || ''
  const feeR = document.getElementById('otc-fee-reported')?.value || '0.90'
  const feeB = document.getElementById('otc-fee-real')?.value || '0.75'
  const ref  = document.getElementById('otc-ref')?.value || ''
  if (!qty && _otcRows.length === 0) return // nothing to save
  const draft = {
    coin, qty, tc, feeReported: feeR, feeReal: feeB, ref,
    data: { ..._otcData },
    rows: _otcRows.map(r => ({
      id: r.id, contactId: r.contactId, contactName: r.contactName,
      bank: r.bank, clabe: r.clabe, assignType: r.assignType,
      value: r.value, montoMXN: r.montoMXN, projectTag: r.projectTag,
      receipts: r.receipts || [],
      _pendingCotId: r._pendingCotId || ''
    })),
    savedAt: new Date().toISOString()
  }
  try { localStorage.setItem(OTC_DRAFT_KEY, JSON.stringify(draft)) } catch(e) { /* quota */ }
}

function _otcHasDraft() {
  try {
    const raw = localStorage.getItem(OTC_DRAFT_KEY)
    if (!raw) return null
    return JSON.parse(raw)
  } catch(e) { return null }
}

function _otcClearDraft() {
  localStorage.removeItem(OTC_DRAFT_KEY)
  const banner = document.getElementById('otc-draft-banner')
  if (banner) banner.style.display = 'none'
}

window.otcRestoreDraft = function() {
  const draft = _otcHasDraft()
  if (!draft) return
  _otcLoadState(draft)
  _otcClearDraft()
  showToast('Operación restaurada')
}

window.otcDiscardDraft = function() {
  _otcClearDraft()
  showToast('Borrador descartado')
}

function _otcLoadState(draft) {
  // Populate form fields
  const coinEl = document.getElementById('otc-coin')
  const qtyEl  = document.getElementById('otc-qty')
  const tcEl   = document.getElementById('otc-tc')
  const feeREl = document.getElementById('otc-fee-reported')
  const feeBEl = document.getElementById('otc-fee-real')
  const refEl  = document.getElementById('otc-ref')
  if (coinEl) coinEl.value = draft.coin || 'USDT'
  if (qtyEl)  qtyEl.value  = draft.qty || ''
  if (tcEl)   { tcEl.value = draft.tc || ''; tcEl._userEdited = true }
  if (feeREl) feeREl.value = draft.feeReported || '0.90'
  if (feeBEl) feeBEl.value = draft.feeReal || '0.75'
  if (refEl)  refEl.value  = draft.ref || ''

  // Restore rows
  _otcRows = (draft.rows || []).map(r => ({ ...r }))

  // Recalc to update KPIs, semáforo, and WhatsApp
  otcRecalc()
  // Re-render dispersion table
  if (typeof otcRenderTable === 'function') otcRenderTable()
}

function _otcCheckDraftOnOpen() {
  const draft = _otcHasDraft()
  const banner = document.getElementById('otc-draft-banner')
  const info = document.getElementById('otc-draft-info')
  if (!draft || !banner) return
  // Show banner with info
  const d = new Date(draft.savedAt)
  const timeStr = d.toLocaleTimeString('es-MX', { hour:'2-digit', minute:'2-digit' })
  const dateStr = d.toLocaleDateString('es-MX', { day:'2-digit', month:'short' })
  const amt = draft.qty ? (draft.qty + ' ' + (draft.coin||'USDT')) : ''
  banner.style.display = 'flex'
  if (info) info.textContent = dateStr + ' ' + timeStr + (amt ? ' — ' + amt : '') + ' · ' + (draft.rows?.length||0) + ' beneficiario(s)'
}

// ── Reopen saved operation from history ──
window.otcReopenHistory = function(nodeId) {
  const op = allNodes.find(n => n.id === nodeId)
  if (!op || !op.metadata?.is_otc_history) return
  const m = op.metadata
  const draft = {
    coin: m.coin || 'USDT',
    qty: String(m.qty || ''),
    tc: String(m.tc || ''),
    feeReported: '0.90',
    feeReal: '0.75',
    ref: m.otc_ref || '',
    rows: (m.rows || []).map((r, i) => ({
      id: 'reopen_' + Date.now() + '_' + i,
      contactId: r.contactId || '',
      contactName: r.contactName || '',
      bank: r.bank || '',
      clabe: r.clabe || '',
      assignType: 'fixed',
      value: r.montoMXN || 0,
      montoMXN: r.montoMXN || 0,
      projectTag: r.projectTag || '',
      receipts: r.receipts || [],
      _pendingCotId: r._pendingCotId || ''
    })),
    savedAt: new Date().toISOString()
  }
  _otcLoadState(draft)
  _otcClearDraft()
  // Scroll to top of OTC panel
  document.getElementById('herr-panel-otc')?.scrollIntoView({ behavior:'smooth', block:'start' })
  showToast('Operación cargada — puedes editar y volver a guardar')
}

