// ── Importar CSV masivo de movimientos ───────────────────────────────────────
window.mvImportCSV = async (input) => {
  if (!_mvActiveOrqId) { showToast('⚠ Selecciona un orquestador primero'); return }
  const file = input.files?.[0]; if (!file) return
  input.value = ''
  const text = await file.text()
  const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean)
  if (lines.length < 2) { showToast('⚠ Archivo vacío o sin filas de datos'); return }

  // Detectar BOM y encabezado
  const header = lines[0].replace(/^﻿/,'').toLowerCase()
  const cols   = header.split(',').map(c => c.trim().replace(/^"|"$/g,''))
  const idx    = (k) => cols.indexOf(k)

  const iF = idx('fecha'), iT = idx('tipo'), iOr = idx('ordenante'), iBe = idx('beneficiario')
  const iBa = idx('banco'), iCl = idx('clabe'), iCa = idx('cantidad'), iMo = idx('moneda')
  const iTc = idx('tc'), iCom = idx('comision'), iNo = idx('notas'), iEs = idx('estado')
  const iCat = idx('categoria'), iProy = idx('proyecto')

  if (iF < 0 || iT < 0 || iCa < 0) {
    showToast('⚠ El CSV debe tener columnas: fecha, tipo, cantidad'); return
  }

  const parseRow = (line) => {
    // Soporta CSV con comillas
    const vals = []; let cur = '', inQ = false
    for (const ch of line) {
      if (ch === '"') { inQ = !inQ }
      else if (ch === ',' && !inQ) { vals.push(cur); cur = '' }
      else cur += ch
    }
    vals.push(cur)
    return vals.map(v => v.trim())
  }

  const toInsert = []
  const errors   = []
  for (let i = 1; i < lines.length; i++) {
    const v   = parseRow(lines[i])
    const tipo = (v[iT]||'').toLowerCase()
    if (!['entrada','salida'].includes(tipo)) { errors.push(`Fila ${i+1}: tipo inválido "${v[iT]}"`); continue }
    const cant = parseFloat(v[iCa])
    if (isNaN(cant) || cant < 0) { errors.push(`Fila ${i+1}: cantidad inválida`); continue }
    const tc   = parseFloat(v[iTc]) || 1
    const com  = iCom >= 0 && v[iCom] ? parseFloat(v[iCom]) : null
    const moneda = (v[iMo]||'MXN').toUpperCase()
    const estado = ['hecho','pendiente','cancelado'].includes((v[iEs]||'').toLowerCase()) ? (v[iEs]||'hecho').toLowerCase() : 'hecho'
    toInsert.push({
      owner_id: currentUser.id, orquestador_id: _mvActiveOrqId,
      tipo, fecha: v[iF] || new Date().toISOString().slice(0,10),
      ordenante: v[iOr]||null, beneficiario: v[iBe]||null,
      banco: v[iBa]||null, clabe: v[iCl]||null,
      cantidad: cant, moneda, tc, comision: com,
      monto_mxn: Math.round(cant * tc * 100) / 100,
      notas: v[iNo]||null, estado,
      categoria: iCat >= 0 && v[iCat] ? v[iCat].trim() : null,
      proyecto:  iProy >= 0 && v[iProy] ? v[iProy].trim() : null,
    })
  }

  if (!toInsert.length) { showToast('⚠ Sin filas válidas. ' + (errors[0]||'')); return }

  // Confirmar
  const ok = confirm(`¿Importar ${toInsert.length} movimiento${toInsert.length>1?'s':''} al orquestador "${_mvOrqs.find(o=>o.id===_mvActiveOrqId)?.nombre}"?\n${errors.length?'\n⚠ '+errors.slice(0,3).join('\n'+(errors.length>3?'...':'')):''}`)
  if (!ok) return

  showToast('⏳ Importando...')
  const BATCH = 50
  let imported = 0
  for (let i = 0; i < toInsert.length; i += BATCH) {
    const { error } = await supabase.from('movimientos').insert(toInsert.slice(i, i + BATCH))
    if (error) { showToast(`❌ Error lote ${Math.floor(i/BATCH)+1}: ${error.message}`); break }
    imported += Math.min(BATCH, toInsert.length - i)
  }
  showToast(`✅ ${imported} movimientos importados`)
  await _mvLoadMovs(); renderMovimientos()
}

// ── Autocomplete contactos en modal ─────────────────────────────────────────
window.mvSearchContact = (field, query) => {
  const drop = document.getElementById(`mv-${field}-drop`)
  if (!drop) return
  if (!query || query.length < 1) { drop.style.display = 'none'; return }
  const q        = query.toLowerCase()
  const contacts = allNodes.filter(n => n.type === 'persona' || n.type === 'contact')
  const matches  = contacts.filter(c => {
    const name = (c.metadata?.name || c.content || '').toLowerCase()
    const phone = (c.metadata?.phones?.[0]?.number || c.metadata?.phone || '').toLowerCase()
    return name.includes(q) || phone.includes(q)
  }).slice(0, 7)
  if (!matches.length) { drop.style.display = 'none'; return }
  drop.style.cssText = 'display:block;position:absolute;top:100%;left:0;right:0;z-index:9999;background:#1a2035;border:1px solid rgba(0,246,255,0.3);border-radius:10px;margin-top:4px;overflow:hidden;box-shadow:0 8px 30px rgba(0,0,0,0.5);'
  drop.innerHTML = matches.map(c => {
    const name     = c.metadata?.name || c.content || ''
    const accounts = c.metadata?.contact_accounts || []
    const phone    = c.metadata?.phones?.[0]?.number || c.metadata?.phone || ''
    return `<div onclick="mvPickContact('${field}','${c.id}')" style="padding:9px 14px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid rgba(255,255,255,0.06);" onmouseover="this.style.background='rgba(0,246,255,0.07)'" onmouseout="this.style.background=''">
      <div>
        <div style="font-size:13px;font-weight:700;color:#fff;">${esc(name)}</div>
        ${phone ? `<div style="font-size:10px;color:#64748b;">${esc(phone)}</div>` : ''}
      </div>
      ${accounts.length ? `<span style="font-size:10px;color:#00f0ff;background:rgba(0,246,255,0.1);padding:2px 8px;border-radius:5px;">🏦 ${accounts.length}</span>` : ''}
    </div>`
  }).join('')
}

window.mvPickContact = (field, contactId) => {
  const c = allNodes.find(n => n.id === contactId)
  if (!c) return
  const name     = c.metadata?.name || c.content || ''
  const accounts = c.metadata?.contact_accounts || []
  const inp      = document.getElementById(`mv-${field}`)
  if (inp) inp.value = name
  const drop = document.getElementById(`mv-${field}-drop`)
  if (drop) drop.style.display = 'none'

  if (accounts.length === 1) {
    _mvFillBankFields(field, accounts[0])
  } else if (accounts.length > 1) {
    _mvShowAccountPicker(field, accounts)
  }
}

/** Fills banco_origen/clabe_origen or banco_destino/clabe_destino depending on field */
function _mvFillBankFields(field, acc) {
  const bankVal  = acc.bank || acc.bank_name || acc.network || ''
  const clabeVal = acc.clabe || acc.wallet   || ''
  const side     = field === 'ordenante' ? 'origen' : 'destino'
  const b  = document.getElementById(`mv-banco-${side}`)
  const cl = document.getElementById(`mv-clabe-${side}`)
  if (b)  b.value  = bankVal
  if (cl) cl.value = clabeVal
}

function _mvShowAccountPicker(field, accounts) {
  document.getElementById('mv-acct-picker')?.remove()
  // anchor below the relevant bank row
  const rowId = field === 'ordenante' ? 'mv-banco-orig-row' : 'mv-banco-dest-row'
  const anchor = document.getElementById(rowId)
  if (!anchor) return
  const wrap = document.createElement('div')
  wrap.id = 'mv-acct-picker'
  wrap.dataset.field = field
  wrap.style.cssText = 'margin-bottom:10px;padding:12px;background:rgba(0,246,255,0.05);border:1px solid rgba(0,246,255,0.2);border-radius:12px;'
  const label = field === 'ordenante' ? 'cuenta de origen (quien envía)' : 'cuenta de destino (quien recibe)'
  wrap.innerHTML = `<div style="font-size:11px;font-weight:700;color:#00f0ff;margin-bottom:8px;display:flex;align-items:center;gap:6px;">${lx('Building2',12)} Selecciona ${label}</div>
    ${accounts.map((acc, i) => {
      const bankLabel = acc.label || acc.bank || acc.bank_name || acc.network || ('Cuenta ' + (i+1))
      const clabeHint = (acc.clabe || acc.wallet || '')
      const clabeDisp = clabeHint.length > 6 ? '···' + clabeHint.slice(-4) : clabeHint
      return `<button onclick="window._mvSelectAccount(${i})" data-acct='${JSON.stringify(acc).replace(/'/g,'&apos;')}' style="display:flex;justify-content:space-between;width:100%;padding:8px 12px;margin-bottom:4px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.09);border-radius:8px;cursor:pointer;font-size:12px;color:var(--text-primary);transition:all 0.15s;" onmouseover="this.style.borderColor='rgba(0,246,255,0.4)'" onmouseout="this.style.borderColor='rgba(255,255,255,0.09)'">
        <span style="font-weight:600;">${esc(bankLabel)}</span>
        <span style="color:var(--text-dim);font-family:'JetBrains Mono',monospace;font-size:11px;">${esc(clabeDisp)}</span>
      </button>`
    }).join('')}
  `
  anchor.insertAdjacentElement('afterend', wrap)
}

window._mvSelectAccount = (idx) => {
  const picker = document.getElementById('mv-acct-picker')
  if (!picker) return
  const field = picker.dataset.field || 'ordenante'
  const btns  = picker.querySelectorAll('button')
  const btn   = btns[idx]; if (!btn) return
  const acc   = JSON.parse(btn.getAttribute('data-acct').replace(/&apos;/g,"'"))
  _mvFillBankFields(field, acc)
  picker.remove()
}

// ═══════════════════════════════════════════════════════════════════════════════
// MÓDULO COTIZACIONES Y VENTAS — Presupuestos + Notas de Venta + Catálogo
// ═══════════════════════════════════════════════════════════════════════════════

const _COT_STATUS = {
  borrador:  { label: 'Borrador',  color: '#94a3b8', bg: 'rgba(148,163,184,0.10)', border: 'rgba(148,163,184,0.28)' },
  enviado:   { label: 'Enviado',   color: '#60a5fa', bg: 'rgba(96,165,250,0.10)',  border: 'rgba(96,165,250,0.28)'  },
  aprobado:  { label: 'Aprobado',  color: '#4ade80', bg: 'rgba(74,222,128,0.10)',  border: 'rgba(74,222,128,0.28)'  },
  cancelado: { label: 'Cancelado', color: '#f87171', bg: 'rgba(248,113,113,0.10)', border: 'rgba(248,113,113,0.28)' },
  pagado:    { label: 'Pagado',    color: '#34d399', bg: 'rgba(52,211,153,0.10)',  border: 'rgba(52,211,153,0.28)'  },
}

function _cotFmt(n, moneda = 'MXN') {
  const sym = moneda === 'USD' ? 'US$' : moneda === 'USDT' ? 'USDT ' : moneda === 'BTC' ? '₿' : '$'
  return sym + Math.abs(n || 0).toLocaleString('es-MX', { minimumFractionDigits: 2, maximumFractionDigits: moneda === 'BTC' ? 8 : 2 })
}

function _cotFolio(prefix) {
  const d  = new Date()
  const ds = d.toISOString().slice(0, 10).replace(/-/g, '')
  return `${prefix}-${ds}-${Math.floor(Math.random() * 9000 + 1000)}`
}

// ── Render vista principal ─────────────────────────────────────────────────────
function renderCotizaciones() {
  const root = document.getElementById('view-cotizaciones')
  if (!root) return

  const presupuestos = allNodes.filter(n => n.type === 'cot_presupuesto')
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
  const notas = allNodes.filter(n => n.type === 'cot_nota')
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
  const catalogo = allNodes.filter(n => n.type === 'cot_catalogo')
    .sort((a, b) => (a.metadata?.nombre || '').localeCompare(b.metadata?.nombre || ''))

  if (_cotTab === 'catalogo') {
    _renderCatalogo(root, catalogo)
    return
  }

  const tabDocs = _cotTab === 'presupuestos' ? presupuestos : notas
  const filtered = _cotStatusFilter === 'all'
    ? tabDocs
    : tabDocs.filter(d => (d.metadata?.estado || 'borrador') === _cotStatusFilter)

  const totalP   = presupuestos.reduce((s, d) => s + (d.metadata?.total || 0), 0)
  const totalN   = notas.reduce((s, d) => s + (d.metadata?.total || 0), 0)
  const aprobP   = presupuestos.filter(d => d.metadata?.estado === 'aprobado').length
  const convRate = presupuestos.length ? Math.round(aprobP / presupuestos.length * 100) : 0
  const isPresupTab = _cotTab === 'presupuestos'

  root.innerHTML = `
    <div style="padding:0 24px 32px;">

      <!-- Header -->
      <div class="view-header" style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px;margin-bottom:20px;">
        <h1 class="view-title">📊 Cotizaciones y Ventas</h1>
        <button onclick="openCotModal('${isPresupTab ? 'cot_presupuesto' : 'cot_nota'}')"
          style="display:flex;align-items:center;gap:7px;background:rgba(34,211,238,0.1);border:1px solid rgba(34,211,238,0.3);color:#22d3ee;border-radius:10px;padding:9px 16px;cursor:pointer;font-size:13px;font-weight:700;">
          + Nuevo ${isPresupTab ? 'Presupuesto' : 'Nota de Venta'}
        </button>
      </div>

      <!-- KPIs -->
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:24px;">
        <div style="background:rgba(96,165,250,0.06);border:1px solid rgba(96,165,250,0.18);border-radius:12px;padding:14px 16px;">
          <div style="font-size:10px;font-weight:700;color:#60a5fa;letter-spacing:.07em;margin-bottom:5px;">PRESUPUESTOS</div>
          <div style="font-size:24px;font-weight:900;color:#fff;font-family:monospace;">${presupuestos.length}</div>
          <div style="font-size:11px;color:#94a3b8;margin-top:2px;">${_cotFmt(totalP)}</div>
        </div>
        <div style="background:rgba(74,222,128,0.06);border:1px solid rgba(74,222,128,0.18);border-radius:12px;padding:14px 16px;">
          <div style="font-size:10px;font-weight:700;color:#4ade80;letter-spacing:.07em;margin-bottom:5px;">APROBADOS</div>
          <div style="font-size:24px;font-weight:900;color:#fff;font-family:monospace;">${aprobP}</div>
          <div style="font-size:11px;color:#94a3b8;margin-top:2px;">${convRate}% conversión</div>
        </div>
        <div style="background:rgba(167,139,250,0.06);border:1px solid rgba(167,139,250,0.18);border-radius:12px;padding:14px 16px;">
          <div style="font-size:10px;font-weight:700;color:#a78bfa;letter-spacing:.07em;margin-bottom:5px;">NOTAS VENTA</div>
          <div style="font-size:24px;font-weight:900;color:#fff;font-family:monospace;">${notas.length}</div>
          <div style="font-size:11px;color:#94a3b8;margin-top:2px;">${_cotFmt(totalN)}</div>
        </div>
        <div style="background:rgba(251,191,36,0.06);border:1px solid rgba(251,191,36,0.18);border-radius:12px;padding:14px 16px;">
          <div style="font-size:10px;font-weight:700;color:#fbbf24;letter-spacing:.07em;margin-bottom:5px;">CATÁLOGO</div>
          <div style="font-size:24px;font-weight:900;color:#fff;font-family:monospace;">${catalogo.length}</div>
          <div style="font-size:11px;color:#94a3b8;margin-top:2px;">productos / servicios</div>
        </div>
      </div>

      <!-- Tabs -->
      <div style="display:flex;gap:4px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:12px;padding:4px;margin-bottom:16px;width:fit-content;">
        <button onclick="switchCotTab('presupuestos')"
          style="padding:7px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;transition:all .15s;${_cotTab==='presupuestos'?'background:rgba(34,211,238,0.12);color:#22d3ee;border:1px solid rgba(34,211,238,0.25);':'background:transparent;color:#6b7280;border:1px solid transparent;'}">
          📋 Presupuestos
        </button>
        <button onclick="switchCotTab('notas')"
          style="padding:7px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;transition:all .15s;${_cotTab==='notas'?'background:rgba(34,211,238,0.12);color:#22d3ee;border:1px solid rgba(34,211,238,0.25);':'background:transparent;color:#6b7280;border:1px solid transparent;'}">
          🧾 Notas de Venta
        </button>
        <button onclick="switchCotTab('catalogo')"
          style="padding:7px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;transition:all .15s;${_cotTab==='catalogo'?'background:rgba(251,191,36,0.12);color:#fbbf24;border:1px solid rgba(251,191,36,0.25);':'background:transparent;color:#6b7280;border:1px solid transparent;'}">
          📦 Catálogo
        </button>
      </div>

      <!-- Status filters (solo presupuestos) -->
      ${isPresupTab ? `
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px;">
        ${[['all','Todos','#94a3b8'],...Object.entries(_COT_STATUS).map(([k,v])=>[k,v.label,v.color])].map(([s, lbl, col]) => {
          const active = _cotStatusFilter === s
          return `<button onclick="setCotStatusFilter('${s}')" style="padding:5px 14px;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;transition:all .15s;border:1px solid ${active ? col : 'rgba(255,255,255,0.1)'};background:${active ? col + '18' : 'transparent'};color:${active ? col : '#6b7280'};">${lbl}</button>`
        }).join('')}
      </div>` : ''}

      <!-- Lista de documentos -->
      ${filtered.length === 0 ? `
        <div style="text-align:center;padding:56px 24px;color:#6b7280;">
          <div style="font-size:44px;margin-bottom:14px;">${isPresupTab ? '📋' : '🧾'}</div>
          <div style="font-size:15px;font-weight:700;color:#94a3b8;margin-bottom:6px;">Sin ${isPresupTab ? 'presupuestos' : 'notas de venta'}${_cotStatusFilter !== 'all' ? ' en este estado' : ''}</div>
          <div style="font-size:12px;">Crea tu primer documento con el botón de arriba.</div>
        </div>
      ` : `<div style="display:flex;flex-direction:column;gap:10px;">${filtered.map(d => _renderCotCard(d)).join('')}</div>`}

    </div>`
}

// ── Render del catálogo ────────────────────────────────────────────────────────
function _renderCatalogo(root, catalogo) {
  const searchQ = (_catSearch || '').toLowerCase()
  const filtered = searchQ
    ? catalogo.filter(n => {
        const m = n.metadata || {}
        return (m.nombre || '').toLowerCase().includes(searchQ)
          || (m.categoria || '').toLowerCase().includes(searchQ)
          || (m.tags || '').toLowerCase().includes(searchQ)
          || (m.descripcion || '').toLowerCase().includes(searchQ)
      })
    : catalogo

  root.innerHTML = `
    <div style="padding:0 24px 32px;">
      <!-- Header -->
      <div class="view-header" style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px;margin-bottom:20px;">
        <h1 class="view-title">📊 Cotizaciones y Ventas</h1>
        <button onclick="openCatModal()"
          style="display:flex;align-items:center;gap:7px;background:rgba(251,191,36,0.1);border:1px solid rgba(251,191,36,0.3);color:#fbbf24;border-radius:10px;padding:9px 16px;cursor:pointer;font-size:13px;font-weight:700;">
          + Nuevo ítem
        </button>
      </div>

      <!-- Tabs -->
      <div style="display:flex;gap:4px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:12px;padding:4px;margin-bottom:16px;width:fit-content;">
        <button onclick="switchCotTab('presupuestos')"
          style="padding:7px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;transition:all .15s;background:transparent;color:#6b7280;border:1px solid transparent;">
          📋 Presupuestos
        </button>
        <button onclick="switchCotTab('notas')"
          style="padding:7px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;transition:all .15s;background:transparent;color:#6b7280;border:1px solid transparent;">
          🧾 Notas de Venta
        </button>
        <button onclick="switchCotTab('catalogo')"
          style="padding:7px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;transition:all .15s;background:rgba(251,191,36,0.12);color:#fbbf24;border:1px solid rgba(251,191,36,0.25);">
          📦 Catálogo
        </button>
      </div>

      <!-- Búsqueda -->
      <div style="margin-bottom:20px;">
        <input type="text" id="cat-search-input" class="modal-input" style="max-width:340px;"
          placeholder="Buscar por nombre, categoría, tags…"
          value="${esc(_catSearch)}"
          oninput="_catSearch=this.value;_renderCatalogo(document.getElementById('view-cotizaciones'), allNodes.filter(n=>n.type==='cot_catalogo').sort((a,b)=>(a.metadata?.nombre||'').localeCompare(b.metadata?.nombre||'')))"/>
      </div>

      <!-- Grid de productos -->
      ${filtered.length === 0 ? `
        <div style="text-align:center;padding:56px 24px;color:#6b7280;">
          <div style="font-size:44px;margin-bottom:14px;">📦</div>
          <div style="font-size:15px;font-weight:700;color:#94a3b8;margin-bottom:6px;">Sin ítems en el catálogo</div>
          <div style="font-size:12px;">Agrega productos o servicios con el botón de arriba.</div>
        </div>
      ` : `
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:14px;">
          ${filtered.map(n => _renderCatCard(n)).join('')}
        </div>
      `}
    </div>`
}

function _renderCatCard(n) {
  const m = n.metadata || {}
  return `
  <div style="background:rgba(255,255,255,0.025);border:1px solid rgba(255,255,255,0.08);border-radius:14px;overflow:hidden;transition:border-color .2s;" onmouseover="this.style.borderColor='rgba(251,191,36,0.3)'" onmouseout="this.style.borderColor='rgba(255,255,255,0.08)'">
    ${m.foto_url
      ? `<img src="${esc(m.foto_url)}" style="width:100%;height:140px;object-fit:cover;display:block;" onerror="this.style.display='none'"/>`
      : `<div style="width:100%;height:100px;background:rgba(251,191,36,0.06);display:flex;align-items:center;justify-content:center;font-size:36px;">📦</div>`
    }
    <div style="padding:12px 14px;">
      <div style="font-size:13px;font-weight:700;color:#fff;margin-bottom:3px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(m.nombre || 'Sin nombre')}</div>
      ${m.categoria ? `<div style="font-size:10px;color:#fbbf24;font-weight:600;margin-bottom:4px;">${esc(m.categoria)}</div>` : ''}
      ${m.descripcion ? `<div style="font-size:11px;color:#94a3b8;margin-bottom:6px;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;">${esc(m.descripcion)}</div>` : ''}
      <div style="font-size:16px;font-weight:900;color:#22d3ee;margin-bottom:8px;">${_cotFmt(m.precio || 0, m.moneda || 'MXN')}</div>
      <div style="display:flex;gap:6px;">
        <button onclick="openCatModal('${n.id}')" style="flex:1;padding:6px;border-radius:8px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.03);color:#94a3b8;cursor:pointer;font-size:12px;">✏️ Editar</button>
        <button onclick="deleteCatItem('${n.id}')" style="width:32px;height:32px;border-radius:8px;border:1px solid rgba(248,113,113,0.22);background:rgba(248,113,113,0.04);color:#f87171;cursor:pointer;font-size:14px;">🗑</button>
      </div>
    </div>
  </div>`
}

function _renderCotCard(d) {
  const m        = d.metadata || {}
  const estado   = m.estado || 'borrador'
  const scfg     = _COT_STATUS[estado] || _COT_STATUS.borrador
  const isP      = d.type === 'cot_presupuesto'
  const mon      = m.moneda || 'MXN'
  const fechaStr = m.fecha
    ? new Date(m.fecha + 'T12:00:00').toLocaleDateString('es-MX', { day:'2-digit', month:'short', year:'numeric' })
    : '—'
  const itemCount = (m.items || []).length

  // ── Pagos para Notas de Venta ──────────────────────────────────────────────
  const pagos    = m.pagos || []
  const pagado   = pagos.reduce((s, p) => s + (p.monto || 0), 0)
  const total    = m.total || 0
  const saldo    = Math.max(0, total - pagado)
  const pct      = total > 0 ? Math.min(100, Math.round(pagado / total * 100)) : 0
  const barColor = pct >= 100 ? '#4ade80' : pct >= 50 ? '#fbbf24' : '#f87171'

  const pagosList = !isP && pagos.length > 0 ? `
    <div style="margin-top:10px;display:flex;flex-direction:column;gap:4px;">
      ${pagos.map(p => `
        <div style="display:flex;justify-content:space-between;align-items:center;font-size:10px;color:#94a3b8;padding:3px 6px;background:rgba(255,255,255,0.03);border-radius:6px;">
          <span>${p.fecha || '—'} · ${p.metodo || 'Transferencia'}${p.referencia ? ` · <span style="font-family:monospace;">${esc(p.referencia)}</span>` : ''}</span>
          <span style="font-weight:700;color:#4ade80;">${_cotFmt(p.monto || 0, p.moneda || mon)}</span>
        </div>`).join('')}
    </div>` : ''

  const paymentsBlock = !isP ? `
    <div style="width:100%;padding:10px 18px 0;border-top:1px solid rgba(255,255,255,0.05);margin-top:12px;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;">
        <span style="font-size:10px;color:#6b7280;">Cobrado: <strong style="color:#4ade80;">${_cotFmt(pagado, mon)}</strong></span>
        <span style="font-size:10px;color:#6b7280;">Saldo: <strong style="color:${saldo > 0 ? '#f87171' : '#4ade80'};">${_cotFmt(saldo, mon)}</strong></span>
        <span style="font-size:10px;font-weight:700;color:${barColor};">${pct}%</span>
      </div>
      <div style="height:5px;border-radius:99px;background:rgba(255,255,255,0.07);overflow:hidden;margin-bottom:${pagos.length ? '0' : '10px'};">
        <div style="height:100%;width:${pct}%;background:${barColor};border-radius:99px;transition:width .4s;"></div>
      </div>
      ${pagosList}
      ${saldo > 0.009 ? `
      <button onclick="registrarPagoCot('${d.id}')"
        style="width:100%;margin-top:8px;padding:7px;border-radius:9px;border:1px solid rgba(74,222,128,0.35);background:rgba(74,222,128,0.08);color:#4ade80;cursor:pointer;font-size:11px;font-weight:700;">
        + Registrar Pago
      </button>` : ''}
      <div id="pago-panel-${d.id.slice(0,8)}" style="display:none;"></div>
    </div>` : ''

  return `
  <div style="background:rgba(255,255,255,0.025);border:1px solid rgba(255,255,255,0.08);border-radius:14px;overflow:hidden;transition:border-color .2s;" onmouseover="this.style.borderColor='rgba(34,211,238,0.22)'" onmouseout="this.style.borderColor='rgba(255,255,255,0.08)'">
    <div style="padding:16px 18px;display:flex;align-items:center;gap:14px;flex-wrap:wrap;">
      <div style="font-size:26px;flex-shrink:0;">${isP ? '📋' : '🧾'}</div>
      <div style="flex:1;min-width:0;">
        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:3px;">
          <span style="font-size:12px;font-weight:800;color:#fff;font-family:monospace;">${esc(m.folio || '—')}</span>
          <span style="font-size:10px;font-weight:700;padding:2px 9px;border-radius:10px;background:${scfg.bg};border:1px solid ${scfg.border};color:${scfg.color};">${scfg.label}</span>
          ${mon !== 'MXN' ? `<span style="font-size:10px;color:#fbbf24;font-weight:600;">${mon}</span>` : ''}
        </div>
        ${m.titulo ? `<div style="font-size:12px;color:#a78bfa;margin-bottom:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(m.titulo)}</div>` : ''}
        <div style="font-size:13px;color:#e2e8f0;font-weight:600;margin-bottom:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${esc(m.clienteName || 'Sin cliente')}</div>
        ${m.proyectoNombre ? `<div style="font-size:10px;color:#60a5fa;">Proyecto: ${esc(m.proyectoNombre)}</div>` : ''}
        <div style="font-size:10px;color:#6b7280;margin-top:3px;">${fechaStr}${isP && m.validezDias ? ` · Válido ${m.validezDias} días` : ''} · ${itemCount} concepto${itemCount !== 1 ? 's' : ''}</div>
      </div>
      <div style="text-align:right;flex-shrink:0;margin-right:6px;">
        <div style="font-size:18px;font-weight:900;color:#22d3ee;font-family:monospace;">${_cotFmt(total || 0, mon)}</div>
        ${m.conIva ? '<div style="font-size:10px;color:#94a3b8;">incl. IVA 16%</div>' : ''}
      </div>
      <div style="display:flex;flex-direction:column;gap:5px;flex-shrink:0;">
        <button onclick="exportCotPDF('${d.id}')" title="Exportar PDF" style="width:32px;height:32px;border-radius:8px;border:1px solid rgba(34,211,238,0.22);background:rgba(34,211,238,0.07);color:#22d3ee;cursor:pointer;font-size:15px;">📥</button>
        <button onclick="openCotModal('${d.type}','${d.id}')" title="Editar" style="width:32px;height:32px;border-radius:8px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.03);color:#94a3b8;cursor:pointer;font-size:14px;">✏️</button>
        ${isP && estado === 'aprobado'
          ? `<button onclick="convertirPresupuestoNota('${d.id}')" title="Convertir a Nota de Venta"
              style="height:32px;padding:0 10px;border-radius:8px;border:1px solid rgba(167,139,250,0.5);background:rgba(167,139,250,0.15);color:#a78bfa;cursor:pointer;font-size:11px;font-weight:700;white-space:nowrap;">🧾 → Nota</button>`
          : isP
            ? `<button onclick="convertirPresupuestoNota('${d.id}')" title="Convertir a Nota de Venta"
                style="width:32px;height:32px;border-radius:8px;border:1px solid rgba(167,139,250,0.22);background:rgba(167,139,250,0.04);color:#a78bfa;cursor:pointer;font-size:13px;">🧾</button>`
            : ''}
        <button onclick="deleteCot('${d.id}')" title="Eliminar" style="width:32px;height:32px;border-radius:8px;border:1px solid rgba(248,113,113,0.22);background:rgba(248,113,113,0.04);color:#f87171;cursor:pointer;font-size:14px;">🗑</button>
      </div>
      ${isP ? `
      <div style="flex-shrink:0;">
        <select onchange="changeCotStatus('${d.id}',this.value)"
          style="font-size:11px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.1);border-radius:8px;padding:5px 8px;color:#94a3b8;cursor:pointer;outline:none;">
          ${Object.entries(_COT_STATUS).map(([k,v]) => `<option value="${k}" ${estado===k?'selected':''}>${v.label}</option>`).join('')}
        </select>
      </div>` : ''}
    </div>
    ${paymentsBlock}
  </div>`
}

// ── Controles de vista ─────────────────────────────────────────────────────────
window.switchCotTab = function(tab) {
  _cotTab = tab
  _cotStatusFilter = 'all'
  renderCotizaciones()
}

window.setCotStatusFilter = function(s) {
  _cotStatusFilter = s
  renderCotizaciones()
}

// ── Modal Cotización — abrir ───────────────────────────────────────────────────
window.openCotModal = function(type, id = null) {
  _cotEditId   = id
  _cotEditType = type
  const isP    = type === 'cot_presupuesto'
  const modal  = document.getElementById('cot-modal')
  if (!modal) return

  const existing = id ? (allNodes.find(n => n.id === id)?.metadata || {}) : {}

  // Cuentas del emisor (para el selector de pago)
  const emisorNode     = existing.emisorId ? allNodes.find(n => n.id === existing.emisorId) : null
  const emisorAccounts = emisorNode?.metadata?.contact_accounts || emisorNode?.metadata?.cuentas || []

  // Contactos — incluye tanto type:'contact' como type:'persona'
  const _allContacts = getContacts()
    .sort((a, b) => (a.metadata?.name || a.content || '').localeCompare(b.metadata?.name || b.content || ''))

  const contactOpts = _allContacts.map(c => {
    const name = esc(c.metadata?.name || c.content || c.id)
    const badge = c.metadata?.empresa ? ` — ${esc(c.metadata.empresa)}` : ''
    return `<option value="${c.id}" ${existing.clienteId === c.id ? 'selected' : ''}>${name}${badge}</option>`
  }).join('')

  const emisorContactOpts = _allContacts.map(c => {
    const name = esc(c.metadata?.name || c.content || c.id)
    const badge = c.metadata?.empresa ? ` — ${esc(c.metadata.empresa)}` : ''
    return `<option value="${c.id}" ${existing.emisorId === c.id ? 'selected' : ''}>${name}${badge}</option>`
  }).join('')

  // Proyectos
  const proyOpts = allNodes
    .filter(n => n.type === 'proyecto')
    .sort((a, b) => (a.metadata?.nombre || a.content || '').localeCompare(b.metadata?.nombre || b.content || ''))
    .map(p => {
      const name = esc(p.metadata?.nombre || p.content || p.id)
      return `<option value="${p.id}" ${existing.proyectoId === p.id ? 'selected' : ''}>${name}</option>`
    }).join('')

  // Items
  const items = existing.items || []

  document.getElementById('cot-modal-icon').textContent  = isP ? '📋' : '🧾'
  document.getElementById('cot-modal-title').textContent = id
    ? (isP ? 'Editar Presupuesto' : 'Editar Nota de Venta')
    : (isP ? 'Nuevo Presupuesto'  : 'Nueva Nota de Venta')

  const today = new Date().toISOString().slice(0, 10)
  const _lbl = (t) => `<label style="font-size:11px;font-weight:700;color:var(--text-muted);display:block;margin-bottom:4px;letter-spacing:.04em;">${t}</label>`

  document.getElementById('cot-modal-body').innerHTML = `
    <!-- ── Sección: Cabecera ────────────────────────────────────────────────── -->
    <div style="font-size:11px;font-weight:700;color:#22d3ee;margin-bottom:10px;letter-spacing:.08em;">📝 CABECERA</div>
    <div style="display:grid;grid-template-columns:2fr 1fr${isP?' 1fr':''}; gap:14px;margin-bottom:16px;">
      <div>
        ${_lbl('Título del documento')}
        <input type="text" id="cot-titulo" class="modal-input"
          placeholder="Ej. Propuesta Desarrollo Web — Casa Chamela"
          value="${esc(existing.titulo || '')}"/>
      </div>
      <div>
        ${_lbl('Fecha')}
        <input type="date" id="cot-fecha" class="modal-input" value="${existing.fecha || today}"/>
      </div>
      ${isP ? `
      <div>
        ${_lbl('Validez (días)')}
        <input type="number" id="cot-validez" class="modal-input" min="1" max="365" placeholder="30" value="${existing.validezDias || 30}"/>
      </div>` : ''}
    </div>

    <!-- ── Sección: Partes ─────────────────────────────────────────────────── -->
    <div style="font-size:11px;font-weight:700;color:#22d3ee;margin-bottom:10px;letter-spacing:.08em;">🏢 PARTES</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:16px;">
      <div>
        ${_lbl('Emisor (quién emite)')}
        <select id="cot-emisor-sel" class="modal-input" style="margin-bottom:6px;" onchange="cotModalFillEmisor()">
          <option value="">— Seleccionar contacto —</option>${emisorContactOpts}
        </select>
        <input type="text" id="cot-emisor-nombre" class="modal-input" style="margin-bottom:4px;"
          placeholder="Nombre o razón social" value="${esc(existing.emisorNombre || '')}"/>
        <input type="text" id="cot-emisor-rfc" class="modal-input" style="margin-bottom:4px;"
          placeholder="RFC" value="${esc(existing.emisorRfc || '')}"/>
        <input type="text" id="cot-emisor-dir" class="modal-input" style="margin-bottom:4px;"
          placeholder="Dirección fiscal" value="${esc(existing.emisorDireccion || '')}"/>
        <input type="text" id="cot-emisor-tel" class="modal-input"
          placeholder="Teléfono del emisor" value="${esc(existing.emisorTel || '')}"/>
      </div>
      <div>
        ${_lbl('Cliente (destinatario)')}
        <select id="cot-cliente-sel" class="modal-input" style="margin-bottom:6px;" onchange="cotModalFillCliente()">
          <option value="">— Seleccionar contacto —</option>${contactOpts}
        </select>
        <input type="text" id="cot-cliente-name" class="modal-input" style="margin-bottom:4px;"
          placeholder="Nombre del cliente" value="${esc(existing.clienteName || '')}"/>
        <input type="text" id="cot-cliente-rfc" class="modal-input" style="margin-bottom:4px;"
          placeholder="RFC" value="${esc(existing.clienteRfc || '')}"/>
        <input type="text" id="cot-cliente-dir" class="modal-input" style="margin-bottom:4px;"
          placeholder="Dirección" value="${esc(existing.clienteDireccion || '')}"/>
        <input type="text" id="cot-cliente-tel" class="modal-input" style="margin-bottom:4px;"
          placeholder="Teléfono" value="${esc(existing.clienteTel || '')}"/>
        <input type="email" id="cot-cliente-email" class="modal-input"
          placeholder="Email (opcional)" value="${esc(existing.clienteEmail || '')}"/>
      </div>
    </div>

    <!-- ── Sección: Proyecto ───────────────────────────────────────────────── -->
    <div style="font-size:11px;font-weight:700;color:#22d3ee;margin-bottom:10px;letter-spacing:.08em;">🗂 PROYECTO VINCULADO <span style="font-weight:400;color:#6b7280;">(opcional)</span></div>
    <div style="margin-bottom:16px;">
      <select id="cot-proyecto-sel" class="modal-input" style="max-width:400px;" onchange="cotModalFillProject()">
        <option value="">— Sin proyecto vinculado —</option>${proyOpts}
      </select>
      <div id="cot-proyecto-info" style="font-size:11px;color:#60a5fa;margin-top:5px;">${existing.proyectoNombre ? `Proyecto: ${esc(existing.proyectoNombre)}` : ''}</div>
    </div>

    <!-- ── Sección: Financiera ─────────────────────────────────────────────── -->
    <div style="font-size:11px;font-weight:700;color:#22d3ee;margin-bottom:10px;letter-spacing:.08em;">💱 FINANCIERO</div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:14px;margin-bottom:14px;">
      <div>
        ${_lbl('Moneda')}
        <select id="cot-moneda" class="modal-input" onchange="cotCalcTotales()">
          <option value="MXN" ${(existing.moneda||'MXN')==='MXN'?'selected':''}>MXN — Peso Mexicano</option>
          <option value="USD" ${existing.moneda==='USD'?'selected':''}>USD — Dólar</option>
          <option value="USDT" ${existing.moneda==='USDT'?'selected':''}>USDT — Tether</option>
          <option value="BTC" ${existing.moneda==='BTC'?'selected':''}>BTC — Bitcoin</option>
        </select>
      </div>
      <div>
        ${_lbl('Tipo de cambio')}
        <input type="number" id="cot-tc" class="modal-input" min="0" step="0.01"
          placeholder="Solo si moneda ≠ MXN" value="${existing.tipoCambio || ''}"/>
      </div>
      <div>
        ${_lbl('Método de pago')}
        <select id="cot-metodo-pago" class="modal-input">
          <option value="">— Seleccionar —</option>
          ${['Transferencia','SPEI','Efectivo','Cripto','Otro'].map(m =>
            `<option value="${m}" ${existing.metodoPago===m?'selected':''}>${m}</option>`
          ).join('')}
        </select>
      </div>
    </div>
    <!-- Selector de cuenta del emisor — se puebla automáticamente al seleccionar contacto -->
    <div style="margin-bottom:10px;">
      ${_lbl('💳 Cuenta del emisor para cobro (auto-llenado)')}
      <select id="cot-pago-cta" class="modal-input" onchange="cotSelectPagoCta()"
        style="${emisorAccounts.length ? '' : 'display:none;'}">
        <option value="">— Seleccionar cuenta —</option>
        ${emisorAccounts.map((a, i) => {
          const aBanco  = a.banco || a.bank || a.bank_name || ''
          const matched = existing.bancoPago === aBanco && existing.clabePago === (a.clabe||a.wallet||'')
          const lbl     = a.label || aBanco || 'Cuenta '+(i+1)
          return `<option value="${i}" ${matched?'selected':''}>${esc(lbl)}${aBanco && lbl !== aBanco ? ' · '+esc(aBanco) : ''} ${esc(a.clabe||a.wallet||'').slice(0,10)}${(a.clabe||a.wallet||'').length>10?'…':''}</option>`
        }).join('')}
      </select>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:16px;">
      <div>
        ${_lbl('Banco')}
        <input type="text" id="cot-banco" class="modal-input" placeholder="Nombre del banco"
          value="${esc(existing.bancoPago || '')}"/>
      </div>
      <div>
        ${_lbl('CLABE / Wallet')}
        <input type="text" id="cot-clabe" class="modal-input" placeholder="CLABE 18 dígitos o dirección de wallet"
          value="${esc(existing.clabePago || '')}"/>
      </div>
    </div>

    <!-- ── Sección: Ítems ──────────────────────────────────────────────────── -->
    <div style="font-size:11px;font-weight:700;color:#22d3ee;margin-bottom:10px;letter-spacing:.08em;">📦 CONCEPTOS / PRODUCTOS</div>

    <!-- Búsqueda en catálogo -->
    <div style="margin-bottom:12px;position:relative;">
      <input type="text" id="cot-cat-search" class="modal-input" style="max-width:360px;"
        placeholder="Buscar en catálogo para agregar ítems…"
        oninput="cotSearchCatalog()"/>
      <div id="cot-cat-results" style="position:absolute;top:100%;left:0;z-index:100;max-width:360px;background:#0e1422;border:1px solid rgba(34,211,238,0.2);border-radius:10px;max-height:160px;overflow-y:auto;display:none;"></div>
    </div>

    <!-- Tabla de ítems — descripción como textarea para detalles completos -->
    <div style="display:grid;grid-template-columns:3fr 70px 100px 70px 90px;gap:5px;padding:0 2px;margin-bottom:5px;">
      <span style="font-size:10px;color:#6b7280;">Descripción completa</span>
      <span style="font-size:10px;color:#6b7280;text-align:center;">Cant.</span>
      <span style="font-size:10px;color:#6b7280;text-align:right;">Precio unit.</span>
      <span style="font-size:10px;color:#6b7280;text-align:center;">Desc.%</span>
      <span style="font-size:10px;color:#6b7280;text-align:right;">Subtotal</span>
    </div>
    <div id="cot-items-wrap">
      ${Array.from({length: 10}, (_, i) => {
        const it = items[i] || {}
        return `<div style="display:grid;grid-template-columns:3fr 70px 100px 70px 90px;gap:5px;margin-bottom:6px;align-items:start;">
          <textarea id="cot-desc-${i+1}" class="modal-input" rows="2" style="font-size:12px;resize:none;line-height:1.4;"
            placeholder="Concepto ${i+1} — incluye detalles, especificaciones y alcance…">${esc(it.descripcion || '')}</textarea>
          <input type="number" id="cot-cant-${i+1}" class="modal-input" style="font-size:12px;text-align:center;"
            placeholder="1" min="0" step="0.01" value="${it.cantidad || ''}" oninput="cotCalcTotales()"/>
          <input type="number" id="cot-precio-${i+1}" class="modal-input" style="font-size:12px;text-align:right;"
            placeholder="0.00" min="0" step="0.01" value="${it.precio || ''}" oninput="cotCalcTotales()"/>
          <input type="number" id="cot-desc-p-${i+1}" class="modal-input" style="font-size:12px;text-align:center;"
            placeholder="0" min="0" max="100" step="0.1" value="${it.descuento || ''}" oninput="cotCalcTotales()"/>
          <input type="text" id="cot-sub-${i+1}" class="modal-input" style="font-size:12px;text-align:right;background:rgba(34,211,238,0.04);color:#22d3ee;"
            placeholder="0.00" readonly value="${it.subtotal ? it.subtotal.toFixed(2) : ''}"/>
        </div>`
      }).join('')}
    </div>

    <!-- IVA + notas con plantillas rápidas -->
    <div style="display:grid;grid-template-columns:auto 1fr;gap:20px;align-items:start;margin-bottom:16px;margin-top:14px;">
      <label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:13px;color:var(--text-main);white-space:nowrap;padding-top:2px;">
        <input type="checkbox" id="cot-con-iva" style="width:16px;height:16px;accent-color:#22d3ee;"
          ${existing.conIva ? 'checked' : ''} onchange="cotCalcTotales()"/>
        Incluir IVA (16%)
      </label>
      <div>
        ${_lbl('Observaciones / Plan de trabajo')}
        <div style="display:flex;gap:5px;flex-wrap:wrap;margin-bottom:6px;">
          ${[
            ['📋 Condiciones','condiciones'],
            ['🚀 Entrega','entrega'],
            ['🛡 Garantía','garantia'],
            ['💳 Anticipo 50%','anticipo'],
            ['📞 Seguimiento','seguimiento'],
          ].map(([label, key]) =>
            `<button type="button" onclick="cotInsertTemplate('${key}')"
              style="font-size:10px;padding:3px 8px;border-radius:6px;border:1px solid rgba(34,211,238,0.2);background:rgba(34,211,238,0.05);color:#22d3ee;cursor:pointer;">${label}</button>`
          ).join('')}
        </div>
        <textarea id="cot-notas" class="modal-input" rows="3" style="resize:vertical;"
          placeholder="Condiciones de pago, plan de trabajo, garantías, plazo de entrega, alcance del proyecto…">${esc(existing.notas || '')}</textarea>
      </div>
    </div>

    <!-- Totales preview -->
    <div id="cot-totales-preview" style="display:flex;justify-content:flex-end;margin-top:8px;">
      <div style="background:rgba(34,211,238,0.05);border:1px solid rgba(34,211,238,0.15);border-radius:12px;padding:14px 20px;min-width:220px;">
        <div style="display:flex;justify-content:space-between;font-size:12px;color:#94a3b8;margin-bottom:5px;">
          <span>Subtotal</span><span id="cot-prev-sub">$0.00</span>
        </div>
        <div id="cot-prev-desc-row" style="display:none;justify-content:space-between;font-size:12px;color:#f87171;margin-bottom:5px;">
          <span>Descuento</span><span id="cot-prev-desc">$0.00</span>
        </div>
        <div id="cot-prev-iva-row" style="display:none;justify-content:space-between;font-size:12px;color:#94a3b8;margin-bottom:5px;">
          <span>IVA 16%</span><span id="cot-prev-iva">$0.00</span>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:16px;font-weight:900;color:#22d3ee;">
          <span>TOTAL</span><span id="cot-prev-total">$0.00</span>
        </div>
        <div id="cot-prev-moneda" style="font-size:10px;color:#6b7280;text-align:right;margin-top:2px;"></div>
      </div>
    </div>
  `

  modal.classList.remove('hidden')
  cotCalcTotales()

  // Attach live preview delegation — captura input/change en todo el panel izquierdo
  const formPanel = document.getElementById('cot-modal-body')
  if (formPanel) {
    formPanel.removeEventListener('input',  _scheduleCotPreview)
    formPanel.removeEventListener('change', _scheduleCotPreview)
    formPanel.addEventListener('input',     _scheduleCotPreview)
    formPanel.addEventListener('change',    _scheduleCotPreview)
  }

  // Render preview inmediata (sin debounce)
  _updateCotPreview()
}

window.closeCotModal = function() {
  document.getElementById('cot-modal')?.classList.add('hidden')
  _cotEditId = null
}

// Auto-fill emisor desde contacto + puebla selector de cuentas
window.cotModalFillEmisor = function() {
  const sel = document.getElementById('cot-emisor-sel')
  if (!sel?.value) return
  const c = allNodes.find(n => n.id === sel.value)
  if (!c) return
  const m = c.metadata || {}
  const nombreEl = document.getElementById('cot-emisor-nombre')
  const rfcEl    = document.getElementById('cot-emisor-rfc')
  const dirEl    = document.getElementById('cot-emisor-dir')
  const telEl    = document.getElementById('cot-emisor-tel')
  nombreEl.value = m.name || c.content || ''
  rfcEl.value    = m.rfc  || ''
  dirEl.value    = m.domicilioLegal || m.address_street || m.address || ''
  if (telEl) telEl.value = m.phone || m.tel || ''

  // Poblar selector de cuentas del emisor (para datos de cobro)
  const accounts = m.contact_accounts || m.cuentas || []
  const ctaSel   = document.getElementById('cot-pago-cta')
  if (ctaSel) {
    if (accounts.length) {
      ctaSel.innerHTML = '<option value="">— Seleccionar cuenta de cobro —</option>' +
        accounts.map((a, i) => {
          const aBanco  = a.banco || a.bank || a.bank_name || ''
          const lbl     = a.label || aBanco || 'Cuenta ' + (i+1)
          const preview = (a.clabe || a.wallet || '').slice(0, 12) + ((a.clabe || a.wallet || '').length > 12 ? '…' : '')
          return `<option value="${i}">${esc(lbl)}${aBanco && lbl !== aBanco ? ' · '+esc(aBanco) : ''} · ${esc(a.tipo || '')} ${preview}</option>`
        }).join('')
      // Store for cotSelectPagoCta
      ctaSel.dataset.accounts = JSON.stringify(accounts)
      ctaSel.style.display    = 'block'
      // Auto-seleccionar si solo hay una cuenta
      if (accounts.length === 1) { ctaSel.value = '0'; cotSelectPagoCta() }
    } else {
      ctaSel.style.display = 'none'
    }
  }
}

// Auto-fill cliente desde contacto — carga todos los campos disponibles
window.cotModalFillCliente = function() {
  const sel = document.getElementById('cot-cliente-sel')
  if (!sel?.value) return
  const c = allNodes.find(n => n.id === sel.value)
  if (!c) return
  const m = c.metadata || {}
  const nameEl  = document.getElementById('cot-cliente-name')
  const rfcEl   = document.getElementById('cot-cliente-rfc')
  const dirEl   = document.getElementById('cot-cliente-dir')
  const telEl   = document.getElementById('cot-cliente-tel')
  const emailEl = document.getElementById('cot-cliente-email')
  const curpEl  = document.getElementById('cot-cliente-curp')
  if (nameEl)  nameEl.value  = m.name  || c.content || ''
  if (rfcEl)   rfcEl.value   = m.rfc   || ''
  if (dirEl)   dirEl.value   = m.domicilioLegal || m.address_street || m.address || ''
  if (telEl)   telEl.value   = m.phone || m.tel  || ''
  if (emailEl) emailEl.value = m.email || ''
  if (curpEl)  curpEl.value  = m.curp  || ''
}

// Auto-fill emisor también carga email
window.cotModalFillEmisorExtra = function() {
  const sel = document.getElementById('cot-emisor-sel')
  if (!sel?.value) return
  const c = allNodes.find(n => n.id === sel.value)
  if (!c) return
  const m = c.metadata || {}
  const telEl = document.getElementById('cot-emisor-tel')
  if (telEl) telEl.value = m.phone || m.tel || ''
}

// Seleccionar cuenta del emisor → auto-llenar banco + CLABE + método
window.cotSelectPagoCta = function() {
  const ctaSel  = document.getElementById('cot-pago-cta')
  if (!ctaSel || ctaSel.value === '') return
  const accounts = JSON.parse(ctaSel.dataset.accounts || '[]')
  const acct     = accounts[parseInt(ctaSel.value)]
  if (!acct) return
  const bancoEl = document.getElementById('cot-banco')
  const clabeEl = document.getElementById('cot-clabe')
  const metodEl = document.getElementById('cot-metodo-pago')
  const aBanco = acct.banco || acct.bank || acct.bank_name || ''
  if (bancoEl) bancoEl.value = aBanco
  if (clabeEl) clabeEl.value = acct.clabe || acct.wallet || ''
  // Detectar método de pago por tipo de cuenta
  if (metodEl) {
    const tipo = (acct.tipo || acct.type || '').toLowerCase()
    if (tipo.includes('cripto') || tipo.includes('wallet') || tipo.includes('crypto') || tipo.includes('usdt') || tipo.includes('btc')) {
      metodEl.value = 'Cripto'
    } else if ((acct.clabe || '').length === 18) {
      metodEl.value = 'SPEI'
    } else if (tipo.includes('transfer')) {
      metodEl.value = 'Transferencia'
    }
  }
}

// Insertar plantilla rápida en campo de notas/observaciones
window.cotInsertTemplate = function(key) {
  const el = document.getElementById('cot-notas')
  if (!el) return
  const templates = {
    condiciones: 'Condiciones de pago: 50% de anticipo para iniciar el proyecto y 50% contra entrega. Precios sujetos a cambio sin previo aviso. El presente documento tiene vigencia de 30 días a partir de su fecha de emisión.',
    entrega: 'Tiempo estimado de entrega: 15 días hábiles a partir de la confirmación del proyecto y pago del anticipo. Cualquier cambio en el alcance podrá afectar los tiempos de entrega.',
    garantia: 'Garantía: 30 días por defectos de fabricación o errores en el trabajo entregado. No incluye modificaciones al alcance original ni daños por mal uso.',
    anticipo: 'Se requiere anticipo del 50% para iniciar trabajos. El saldo restante (50%) se cubrirá contra entrega. No se inicia el proyecto sin anticipo confirmado.',
    seguimiento: 'Se realizará una reunión de seguimiento semanal para revisar avances. El cliente deberá proporcionar retroalimentación en un plazo máximo de 3 días hábiles por cada entregable.',
  }
  const text = templates[key] || ''
  if (!text) return
  const sep  = el.value.trim() ? '\n\n' : ''
  el.value   = el.value + sep + text
  el.focus()
}

// Auto-fill info de proyecto
window.cotModalFillProject = function() {
  const sel  = document.getElementById('cot-proyecto-sel')
  const info = document.getElementById('cot-proyecto-info')
  if (!sel || !info) return
  if (!sel.value) { info.textContent = ''; return }
  const p = allNodes.find(n => n.id === sel.value)
  if (!p) return
  const nombre = p.metadata?.nombre || p.content || sel.value
  info.innerHTML = `<span style="color:#60a5fa;">Proyecto: ${esc(nombre)}</span> <span style="color:#6b7280;font-size:10px;">— la portada del proyecto se incluirá en el PDF</span>`
}

// Búsqueda en catálogo para agregar ítems
window.cotSearchCatalog = function() {
  const q = (document.getElementById('cot-cat-search')?.value || '').toLowerCase()
  const res = document.getElementById('cot-cat-results')
  if (!res) return
  if (!q) { res.style.display = 'none'; return }

  const matches = allNodes
    .filter(n => n.type === 'cot_catalogo' && (
      (n.metadata?.nombre || '').toLowerCase().includes(q) ||
      (n.metadata?.categoria || '').toLowerCase().includes(q) ||
      (n.metadata?.tags || '').toLowerCase().includes(q)
    ))
    .slice(0, 8)

  if (!matches.length) {
    res.style.display = 'none'
    return
  }

  res.style.display = 'block'
  res.innerHTML = matches.map(n => {
    const m = n.metadata || {}
    return `<div onclick="cotAddCatalogItem('${n.id}')"
      style="padding:8px 12px;cursor:pointer;border-bottom:1px solid rgba(255,255,255,0.05);transition:background .1s;"
      onmouseover="this.style.background='rgba(34,211,238,0.07)'" onmouseout="this.style.background='transparent'">
      <div style="font-size:12px;color:#fff;font-weight:600;">${esc(m.nombre || '—')}</div>
      <div style="font-size:10px;color:#94a3b8;">${esc(m.categoria || '')} · ${_cotFmt(m.precio || 0, m.moneda || 'MXN')}</div>
    </div>`
  }).join('')
}

// Agrega ítem del catálogo a la tabla del modal
window.cotAddCatalogItem = function(id) {
  const n = allNodes.find(x => x.id === id)
  if (!n) return
  const m = n.metadata || {}
  // Texto: primero notasInternas (plantilla), luego descripcion larga, luego nombre
  const descText = m.notasInternas || m.descripcion || m.nombre || ''
  // Buscar primera fila vacía
  for (let i = 1; i <= 10; i++) {
    const descEl = document.getElementById(`cot-desc-${i}`)
    if (descEl && !descEl.value.trim()) {
      descEl.value = descText
      const cantEl   = document.getElementById(`cot-cant-${i}`)
      const precioEl = document.getElementById(`cot-precio-${i}`)
      if (cantEl)   cantEl.value   = 1
      if (precioEl) precioEl.value = m.precio || 0
      cotCalcTotales()
      break
    }
  }
  // Ocultar resultados
  const res = document.getElementById('cot-cat-results')
  if (res) res.style.display = 'none'
  const searchEl = document.getElementById('cot-cat-search')
  if (searchEl) searchEl.value = ''
}

// Calcular subtotales + totales en tiempo real
window.cotCalcTotales = function() {
  const mon    = document.getElementById('cot-moneda')?.value || 'MXN'
  let subtotal = 0
  let descTotal = 0

  for (let i = 1; i <= 10; i++) {
    const cant   = parseFloat(document.getElementById(`cot-cant-${i}`)?.value    || '0') || 0
    const precio = parseFloat(document.getElementById(`cot-precio-${i}`)?.value  || '0') || 0
    const desc   = parseFloat(document.getElementById(`cot-desc-p-${i}`)?.value  || '0') || 0
    const rawSub = cant * precio
    const deduccion = rawSub * (desc / 100)
    const sub    = rawSub - deduccion
    const subEl  = document.getElementById(`cot-sub-${i}`)
    if (subEl) subEl.value = rawSub > 0 ? sub.toFixed(2) : ''
    subtotal  += rawSub
    descTotal += deduccion
  }

  const conIva  = document.getElementById('cot-con-iva')?.checked
  const iva     = conIva ? (subtotal - descTotal) * 0.16 : 0
  const total   = subtotal - descTotal + iva
  const fmtM    = (n) => _cotFmt(n, mon)

  const subEl = document.getElementById('cot-prev-sub');   if (subEl) subEl.textContent = fmtM(subtotal)
  const descEl = document.getElementById('cot-prev-desc'); if (descEl) descEl.textContent = fmtM(descTotal)
  const ivaEl  = document.getElementById('cot-prev-iva');  if (ivaEl)  ivaEl.textContent = fmtM(iva)
  const totEl  = document.getElementById('cot-prev-total'); if (totEl) totEl.textContent = fmtM(total)
  const ivaRow  = document.getElementById('cot-prev-iva-row')
  const descRow = document.getElementById('cot-prev-desc-row')
  const monEl   = document.getElementById('cot-prev-moneda')
  if (ivaRow)  ivaRow.style.display  = conIva ? 'flex' : 'none'
  if (descRow) descRow.style.display = descTotal > 0 ? 'flex' : 'none'
  if (monEl)   monEl.textContent     = mon !== 'MXN' ? `en ${mon}` : ''

  _scheduleCotPreview()
}

// ── Vista previa en vivo — debounce 400 ms ─────────────────────────────────
let _cotPreviewTimer = null
function _scheduleCotPreview() {
  if (_cotPreviewTimer) clearTimeout(_cotPreviewTimer)
  _cotPreviewTimer = setTimeout(_updateCotPreview, 400)
}

function _updateCotPreview() {
  const panel = document.getElementById('cot-preview-panel')
  if (!panel || document.getElementById('cot-modal')?.classList.contains('hidden')) return

  const isP       = _cotEditType === 'cot_presupuesto'
  const titulo    = document.getElementById('cot-titulo')?.value?.trim()    || ''
  const fecha     = document.getElementById('cot-fecha')?.value             || new Date().toISOString().slice(0,10)
  const validez   = document.getElementById('cot-validez')?.value           || ''
  const mon       = document.getElementById('cot-moneda')?.value            || 'MXN'
  const tc        = parseFloat(document.getElementById('cot-tc')?.value     || '0') || 0
  const emisorNom = document.getElementById('cot-emisor-nombre')?.value?.trim() || ''
  const emisorRfc = document.getElementById('cot-emisor-rfc')?.value?.trim()    || ''
  const emisorDir = document.getElementById('cot-emisor-dir')?.value?.trim()    || ''
  const emisorTel = document.getElementById('cot-emisor-tel')?.value?.trim()    || ''
  const clienteNom = document.getElementById('cot-cliente-name')?.value?.trim() || ''
  const clienteRfc = document.getElementById('cot-cliente-rfc')?.value?.trim()  || ''
  const clienteDir = document.getElementById('cot-cliente-dir')?.value?.trim()  || ''
  const clienteTel = document.getElementById('cot-cliente-tel')?.value?.trim()  || ''
  const banco     = document.getElementById('cot-banco')?.value?.trim()         || ''
  const clabe     = document.getElementById('cot-clabe')?.value?.trim()         || ''
  const metodo    = document.getElementById('cot-metodo-pago')?.value           || ''
  const notas     = document.getElementById('cot-notas')?.value?.trim()         || ''
  const conIva    = document.getElementById('cot-con-iva')?.checked             || false
  const proyNom   = document.getElementById('cot-proyecto-info')?.textContent?.replace('Proyecto: ','')?.trim() || ''
  const folioLbl  = _cotEditId
    ? (allNodes.find(n => n.id === _cotEditId)?.metadata?.folio || '—')
    : (isP ? 'PRS-BORRADOR' : 'NV-BORRADOR')

  // Collect items
  const items = []
  for (let i = 1; i <= 10; i++) {
    const desc  = document.getElementById(`cot-desc-${i}`)?.value?.trim()    || ''
    const cant  = parseFloat(document.getElementById(`cot-cant-${i}`)?.value  || '0') || 0
    const prec  = parseFloat(document.getElementById(`cot-precio-${i}`)?.value|| '0') || 0
    const dsc   = parseFloat(document.getElementById(`cot-desc-p-${i}`)?.value|| '0') || 0
    if (!desc && !prec) continue
    const sub   = cant * prec * (1 - dsc / 100)
    items.push({ desc, cant, prec, dsc, sub })
  }

  const subtotal   = items.reduce((s, it) => s + it.cant * it.prec, 0)
  const descTotal  = items.reduce((s, it) => s + it.cant * it.prec * (it.dsc / 100), 0)
  const ivaAmt     = conIva ? (subtotal - descTotal) * 0.16 : 0
  const total      = subtotal - descTotal + ivaAmt
  const mxnTotal   = mon !== 'MXN' && tc > 0 ? total * tc : null

  const _fmt = (n) => n.toLocaleString('es-MX', { style:'currency', currency:'MXN', maximumFractionDigits: 2 })
    .replace('MXN', mon === 'MXN' ? '$' : mon + ' ')
  const _fmtMXN = (n) => n.toLocaleString('es-MX', { style:'currency', currency:'MXN', maximumFractionDigits: 2 })

  const fechaFmt = fecha
    ? new Date(fecha + 'T12:00:00').toLocaleDateString('es-MX', { year:'numeric', month:'long', day:'numeric' })
    : ''

  const E = (s) => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')

  panel.innerHTML = `
  <div style="background:#fff;width:100%;max-width:640px;min-height:860px;padding:30px 34px 48px;box-shadow:0 12px 48px rgba(0,0,0,0.4);font-family:'Helvetica Neue',Helvetica,Arial,sans-serif;font-size:9px;color:#1a1a2e;position:relative;border-radius:3px;">

    <!-- Banda de proyecto (si hay nombre de proyecto) -->
    ${proyNom ? `<div style="background:#0a0f1e;color:rgba(255,255,255,0.85);padding:6px 12px;margin:-30px -34px 18px;font-size:8px;font-weight:700;letter-spacing:.05em;">📁 ${E(proyNom)}</div>` : ''}

    <!-- Header: Tipo + Folio + Título -->
    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:16px;">
      <div>
        <div style="font-size:22px;font-weight:900;color:#0a0f1e;letter-spacing:.02em;line-height:1;">${isP ? 'PRESUPUESTO' : 'NOTA DE VENTA'}</div>
        ${titulo ? `<div style="font-size:11px;color:#374151;margin-top:5px;max-width:320px;line-height:1.4;">${E(titulo)}</div>` : ''}
        ${proyNom && !titulo ? `<div style="font-size:10px;color:#6b7280;margin-top:3px;font-style:italic;">Proyecto: ${E(proyNom)}</div>` : ''}
      </div>
      <div style="text-align:right;flex-shrink:0;margin-left:16px;">
        <div style="font-size:11px;font-weight:800;background:#0a0f1e;color:white;padding:6px 14px;border-radius:5px;letter-spacing:.05em;">${E(folioLbl)}</div>
        <div style="font-size:8px;color:#6b7280;margin-top:5px;">${fechaFmt}</div>
        ${validez ? `<div style="font-size:7.5px;color:#9ca3af;margin-top:2px;">Válido ${validez} días</div>` : ''}
      </div>
    </div>

    <!-- Línea divisora -->
    <div style="height:1px;background:linear-gradient(90deg,#0a0f1e,#e5e7eb);margin-bottom:14px;"></div>

    <!-- Emisor + Cliente -->
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;">
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:5px;padding:9px 11px;">
        <div style="font-size:6.5px;font-weight:800;color:#6b7280;text-transform:uppercase;letter-spacing:.08em;margin-bottom:5px;">Emisor</div>
        <div style="font-size:10px;font-weight:700;color:#0a0f1e;">${E(emisorNom || '—')}</div>
        ${emisorRfc ? `<div style="font-size:7.5px;color:#4b5563;margin-top:2px;">RFC: ${E(emisorRfc)}</div>` : ''}
        ${emisorDir ? `<div style="font-size:7.5px;color:#4b5563;margin-top:1px;">${E(emisorDir)}</div>` : ''}
        ${emisorTel ? `<div style="font-size:7.5px;color:#4b5563;">Tel: ${E(emisorTel)}</div>` : ''}
      </div>
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:5px;padding:9px 11px;">
        <div style="font-size:6.5px;font-weight:800;color:#6b7280;text-transform:uppercase;letter-spacing:.08em;margin-bottom:5px;">Cliente</div>
        <div style="font-size:10px;font-weight:700;color:#0a0f1e;">${E(clienteNom || '—')}</div>
        ${clienteRfc ? `<div style="font-size:7.5px;color:#4b5563;margin-top:2px;">RFC: ${E(clienteRfc)}</div>` : ''}
        ${clienteDir ? `<div style="font-size:7.5px;color:#4b5563;margin-top:1px;">${E(clienteDir)}</div>` : ''}
        ${clienteTel ? `<div style="font-size:7.5px;color:#4b5563;">Tel: ${E(clienteTel)}</div>` : ''}
      </div>
    </div>

    <!-- Moneda indicator -->
    ${mon !== 'MXN' ? `<div style="font-size:7.5px;color:#6b7280;margin-bottom:8px;font-style:italic;">Moneda: ${E(mon)}${tc > 0 ? ` · Tipo de cambio: ${tc}` : ''}</div>` : ''}

    <!-- Tabla de conceptos -->
    ${items.length === 0 ? `<div style="padding:20px 0;text-align:center;color:#9ca3af;font-size:9px;font-style:italic;">Sin conceptos aún — agrega productos o servicios</div>` : `
    <table style="width:100%;border-collapse:collapse;margin-bottom:10px;font-size:8.5px;">
      <thead>
        <tr style="background:#0a0f1e;color:white;">
          <th style="padding:5px 7px;text-align:center;width:22px;font-weight:700;">#</th>
          <th style="padding:5px 7px;text-align:left;font-weight:700;">Descripción</th>
          <th style="padding:5px 7px;text-align:center;width:36px;font-weight:700;">Cant.</th>
          <th style="padding:5px 7px;text-align:right;width:76px;font-weight:700;">Precio</th>
          ${items.some(it => it.dsc > 0) ? `<th style="padding:5px 7px;text-align:center;width:38px;font-weight:700;">Desc.%</th>` : ''}
          <th style="padding:5px 7px;text-align:right;width:82px;font-weight:700;">Subtotal</th>
        </tr>
      </thead>
      <tbody>
        ${items.map((it, idx) => `
        <tr style="background:${idx%2===0?'#f8fafc':'#fff'};border-bottom:1px solid #e5e7eb;">
          <td style="padding:5px 7px;text-align:center;color:#6b7280;">${idx+1}</td>
          <td style="padding:5px 7px;color:#1a1a2e;white-space:pre-wrap;line-height:1.35;">${E(it.desc)}</td>
          <td style="padding:5px 7px;text-align:center;color:#4b5563;">${it.cant.toLocaleString('es-MX',{maximumFractionDigits:2})}</td>
          <td style="padding:5px 7px;text-align:right;color:#4b5563;">${_fmt(it.prec)}</td>
          ${items.some(x => x.dsc > 0) ? `<td style="padding:5px 7px;text-align:center;color:#f87171;">${it.dsc > 0 ? it.dsc+'%' : '—'}</td>` : ''}
          <td style="padding:5px 7px;text-align:right;font-weight:700;color:#0a0f1e;">${_fmt(it.sub)}</td>
        </tr>`).join('')}
      </tbody>
    </table>`}

    <!-- Totales -->
    <div style="display:flex;justify-content:flex-end;margin-bottom:14px;">
      <div style="min-width:188px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:5px;padding:9px 13px;">
        <div style="display:flex;justify-content:space-between;font-size:8.5px;color:#4b5563;margin-bottom:4px;"><span>Subtotal</span><span>${_fmt(subtotal)}</span></div>
        ${descTotal > 0 ? `<div style="display:flex;justify-content:space-between;font-size:8.5px;color:#ef4444;margin-bottom:4px;"><span>Descuento</span><span>-${_fmt(descTotal)}</span></div>` : ''}
        ${conIva ? `<div style="display:flex;justify-content:space-between;font-size:8.5px;color:#4b5563;margin-bottom:4px;"><span>IVA (16%)</span><span>${_fmt(ivaAmt)}</span></div>` : ''}
        <div style="height:1px;background:#e2e8f0;margin:5px 0;"></div>
        <div style="display:flex;justify-content:space-between;font-size:12px;font-weight:900;color:#0a0f1e;">
          <span>TOTAL ${mon}</span><span>${_fmt(total)}</span>
        </div>
        ${mxnTotal !== null ? `<div style="display:flex;justify-content:flex-end;font-size:8px;color:#6b7280;margin-top:3px;font-style:italic;">≈ MXN ${_fmtMXN(mxnTotal)}</div>` : ''}
      </div>
    </div>

    <!-- Observaciones -->
    ${notas ? `
    <div style="background:#f8fafc;border:1px solid #e2e8f0;border-left:3px solid #0a0f1e;border-radius:0 5px 5px 0;padding:10px 12px;margin-bottom:12px;">
      <div style="font-size:7px;font-weight:800;color:#0a0f1e;text-transform:uppercase;letter-spacing:.07em;margin-bottom:5px;">Observaciones / Plan de trabajo</div>
      <div style="font-size:8px;color:#374151;line-height:1.6;white-space:pre-wrap;">${E(notas)}</div>
    </div>` : ''}

    <!-- Datos de pago -->
    ${(metodo || banco || clabe) ? `
    <div style="border:1.5px solid #0a0f1e;border-radius:5px;padding:10px 12px;margin-bottom:12px;">
      <div style="font-size:7px;font-weight:800;color:#0a0f1e;text-transform:uppercase;letter-spacing:.07em;margin-bottom:7px;">💳 Datos de Pago</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:6px;">
        ${metodo ? `<div style="font-size:8px;"><span style="color:#6b7280;font-weight:600;">Método: </span><span style="color:#1a1a2e;">${E(metodo)}</span></div>` : ''}
        ${banco  ? `<div style="font-size:8px;"><span style="color:#6b7280;font-weight:600;">Banco: </span><span style="color:#1a1a2e;">${E(banco)}</span></div>` : ''}
        ${clabe  ? `<div style="font-size:8px;font-weight:700;grid-column:1/-1;"><span style="color:#6b7280;font-weight:600;">CLABE / Cuenta: </span><span style="color:#1a1a2e;letter-spacing:.04em;">${E(clabe)}</span></div>` : ''}
      </div>
    </div>` : ''}

    <!-- Footer -->
    <div style="position:absolute;bottom:12px;left:34px;right:34px;border-top:1px solid #e5e7eb;padding-top:6px;display:flex;justify-content:space-between;">
      <span style="font-size:7px;color:#9ca3af;">Documento generado con Nexus OS</span>
      <span style="font-size:7px;color:#9ca3af;">${E(folioLbl)}</span>
    </div>

  </div>`
}

// Cerrar modal con Escape
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape' && !document.getElementById('cot-modal')?.classList.contains('hidden')) {
    window.closeCotModal()
  }
})

// ── Recopilar datos del modal ──────────────────────────────────────────────────
function _collectCotData() {
  const isP         = _cotEditType === 'cot_presupuesto'
  const fechaRaw    = document.getElementById('cot-fecha')?.value || ''
  const fechaFmt    = fechaRaw
    ? new Date(fechaRaw + 'T12:00:00').toLocaleDateString('es-MX', { year:'numeric', month:'long', day:'numeric' })
    : new Date().toLocaleDateString('es-MX', { year:'numeric', month:'long', day:'numeric' })

  // Emisor
  const emisorSelVal    = document.getElementById('cot-emisor-sel')?.value || ''
  const emisorNombre    = document.getElementById('cot-emisor-nombre')?.value?.trim() || ''
  const emisorRfc       = document.getElementById('cot-emisor-rfc')?.value?.trim() || ''
  const emisorDireccion = document.getElementById('cot-emisor-dir')?.value?.trim() || ''
  const emisorTel       = document.getElementById('cot-emisor-tel')?.value?.trim() || ''

  // Cliente
  const clienteSelVal   = document.getElementById('cot-cliente-sel')?.value || ''
  const clienteNode     = clienteSelVal ? allNodes.find(n => n.id === clienteSelVal) : null
  const clienteName     = document.getElementById('cot-cliente-name')?.value?.trim()
    || (clienteNode ? (clienteNode.metadata?.name || clienteNode.content) : '') || ''
  const clienteRfc      = document.getElementById('cot-cliente-rfc')?.value?.trim() || ''
  const clienteDireccion = document.getElementById('cot-cliente-dir')?.value?.trim() || ''
  const clienteTel      = document.getElementById('cot-cliente-tel')?.value?.trim() || ''
  const clienteEmail    = document.getElementById('cot-cliente-email')?.value?.trim() || ''

  // Proyecto
  const proyectoSelVal  = document.getElementById('cot-proyecto-sel')?.value || ''
  const proyectoNode    = proyectoSelVal ? allNodes.find(n => n.id === proyectoSelVal) : null
  const proyectoNombre  = proyectoNode ? (proyectoNode.metadata?.nombre || proyectoNode.content || '') : ''

  // Financiero
  const moneda      = document.getElementById('cot-moneda')?.value || 'MXN'
  const tipoCambio  = parseFloat(document.getElementById('cot-tc')?.value || '0') || null
  const metodoPago  = document.getElementById('cot-metodo-pago')?.value || ''
  const bancoPago   = document.getElementById('cot-banco')?.value?.trim() || ''
  const clabePago   = document.getElementById('cot-clabe')?.value?.trim() || ''
  const titulo      = document.getElementById('cot-titulo')?.value?.trim() || ''
  const validezDias = isP ? parseInt(document.getElementById('cot-validez')?.value || '30') : 0
  const conIva      = document.getElementById('cot-con-iva')?.checked || false
  const notas       = document.getElementById('cot-notas')?.value?.trim() || ''

  // Items
  const items = []
  let subtotal = 0; let descuentoTotal = 0
  for (let i = 1; i <= 10; i++) {
    const desc    = document.getElementById(`cot-desc-${i}`)?.value?.trim() || ''
    const cant    = parseFloat(document.getElementById(`cot-cant-${i}`)?.value    || '0') || 0
    const precio  = parseFloat(document.getElementById(`cot-precio-${i}`)?.value  || '0') || 0
    const descPct = parseFloat(document.getElementById(`cot-desc-p-${i}`)?.value  || '0') || 0
    if (desc) {
      const rawSub = (cant || 1) * precio
      const deduccion = rawSub * (descPct / 100)
      const sub = rawSub - deduccion
      items.push({ descripcion: desc, cantidad: cant || 1, precio, descuento: descPct, subtotal: sub })
      subtotal     += rawSub
      descuentoTotal += deduccion
    }
  }
  const iva   = conIva ? (subtotal - descuentoTotal) * 0.16 : 0
  const total = subtotal - descuentoTotal + iva

  // Folio
  const folio = _cotEditId
    ? (allNodes.find(n => n.id === _cotEditId)?.metadata?.folio || _cotFolio(isP ? 'PRS' : 'NV'))
    : _cotFolio(isP ? 'PRS' : 'NV')

  return {
    folio, titulo, fecha: fechaRaw, fechaFmt, validezDias,
    emisorId: emisorSelVal, emisorNombre, emisorRfc, emisorDireccion, emisorTel,
    clienteId: clienteSelVal, clienteName, clienteRfc, clienteDireccion, clienteTel, clienteEmail,
    proyectoId: proyectoSelVal, proyectoNombre,
    moneda, tipoCambio, metodoPago, bancoPago, clabePago,
    items, conIva, subtotal, descuentoTotal, iva, total, notas,
  }
}

// ── Guardar ────────────────────────────────────────────────────────────────────
window.saveCot = function() { _persistCot(false) }
window.saveCotAndExport = function() { _persistCot(true) }

async function _persistCot(exportPdf = false) {
  const data   = _collectCotData()
  if (!data.items.length) { showToast('⚠️ Agrega al menos un concepto'); return }

  const isP    = _cotEditType === 'cot_presupuesto'
  const emisor = getEmisor()
  const estado = _cotEditId
    ? (allNodes.find(n => n.id === _cotEditId)?.metadata?.estado || 'borrador')
    : 'borrador'

  const meta = {
    folio: data.folio, titulo: data.titulo,
    fecha: data.fecha, fechaFmt: data.fechaFmt, validezDias: data.validezDias,
    emisorId: data.emisorId, emisorNombre: data.emisorNombre, emisorRfc: data.emisorRfc,
    emisorDireccion: data.emisorDireccion, emisorTel: data.emisorTel,
    clienteId: data.clienteId, clienteName: data.clienteName,
    clienteRfc: data.clienteRfc, clienteDireccion: data.clienteDireccion,
    clienteTel: data.clienteTel, clienteEmail: data.clienteEmail,
    proyectoId: data.proyectoId, proyectoNombre: data.proyectoNombre,
    moneda: data.moneda, tipoCambio: data.tipoCambio,
    metodoPago: data.metodoPago, bancoPago: data.bancoPago, clabePago: data.clabePago,
    items: data.items, conIva: data.conIva,
    subtotal: data.subtotal, descuentoTotal: data.descuentoTotal, iva: data.iva, total: data.total,
    notas: data.notas, estado,
  }
  const label   = data.titulo || data.clienteName || 'Sin cliente'
  const content = `${isP ? 'Presupuesto' : 'Nota de Venta'} ${data.folio} — ${label} — ${_cotFmt(data.total, data.moneda)}`

  if (_cotEditId) {
    const node = allNodes.find(n => n.id === _cotEditId)
    if (node) {
      node.content  = content
      node.metadata = { ...node.metadata, ...meta }
      if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
        await supabase.from('nodes').update({ content, metadata: node.metadata }).eq('id', _cotEditId)
      }
    }
    showToast('✅ Documento actualizado')
  } else {
    const node = {
      id: crypto.randomUUID(),
      content, type: _cotEditType, metadata: meta,
      created_at: new Date().toISOString(),
    }
    allNodes.push(node)
    _cotEditId = node.id
    if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
      await supabase.from('nodes').insert([{ id: node.id, owner_id: currentUser?.id, content, type: node.type, metadata: meta }])
    }
    showToast('✅ Documento guardado')
  }

  if (exportPdf) {
    const pdfData = { ...data, folio: meta.folio, emisor }
    // Preload project cover for PDF
    const _pdfCoverUrl = proyectoNode?.metadata?.cover_url || ''
    if (_pdfCoverUrl) {
      preloadCover(_pdfCoverUrl).then(dataUrl => {
        pdfData.cover_data_url = dataUrl
        if (isP) pdfPresupuestoPro(pdfData, emisor)
        else     pdfNotaVentaPro(pdfData, emisor)
      }).catch(() => {
        if (isP) pdfPresupuestoPro(pdfData, emisor)
        else     pdfNotaVentaPro(pdfData, emisor)
      })
    } else {
      if (isP) pdfPresupuestoPro(pdfData, emisor)
      else     pdfNotaVentaPro(pdfData, emisor)
    }
  }

  closeCotModal()
  renderCotizaciones()
}

// ── Exportar PDF desde la lista ────────────────────────────────────────────────
window.exportCotPDF = async function(id) {
  const node = allNodes.find(n => n.id === id)
  if (!node) { showToast('Documento no encontrado'); return }
  const m      = node.metadata || {}
  const emisor = getEmisor()
  const data   = { ...m }
  // Inyectar portada del proyecto vinculado
  if (data.proyectoId && !data.cover_data_url) {
    const pNode = allNodes.find(n => n.id === data.proyectoId)
    const coverUrl = pNode?.metadata?.cover_url || ''
    if (coverUrl) { try { data.cover_data_url = await preloadCover(coverUrl) } catch {} }
    if (!data.proyectoNombre && pNode) data.proyectoNombre = pNode.metadata?.nombre || pNode.content || ''
  }
  if (node.type === 'cot_presupuesto') pdfPresupuestoPro(data, emisor)
  else                                  pdfNotaVentaPro(data, emisor)
  showToast('📥 PDF generado')
}

// ── Cambiar estado ─────────────────────────────────────────────────────────────
window.changeCotStatus = async function(id, estado) {
  const node = allNodes.find(n => n.id === id)
  if (!node) return
  node.metadata = { ...node.metadata, estado }
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: node.metadata }).eq('id', id)
  }
  renderCotizaciones()
  showToast(`Estado → ${_COT_STATUS[estado]?.label || estado}`)
}

// ── Eliminar cotización ────────────────────────────────────────────────────────
window.deleteCot = async function(id) {
  if (!confirm('¿Eliminar este documento? Esta acción no se puede deshacer.')) return
  const idx = allNodes.findIndex(n => n.id === id)
  if (idx !== -1) allNodes.splice(idx, 1)
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').delete().eq('id', id)
  }
  renderCotizaciones()
  showToast('🗑 Documento eliminado')
}

// ── Convertir Presupuesto → Nota de Venta (+ Movimiento de ingreso automático) ──
window.convertirPresupuestoNota = async function(id) {
  const src = allNodes.find(n => n.id === id)
  if (!src) return
  const m      = src.metadata || {}
  const label  = m.titulo || m.folio || 'Sin título'
  const cliente = m.clienteName || 'Sin cliente'

  // Confirmar conversión
  if (!confirm(`¿Convertir "${label}" en Nota de Venta?\n\nSe creará una Nota de Venta con todos los datos del presupuesto.\nPodrás registrar pagos parciales y la nota comenzará como "Pendiente".`)) return

  const folio    = _cotFolio('NV')
  const notaMeta = {
    ...m,
    folio,
    estado: 'pendiente',  // comienza pendiente, no pagado
    validezDias: 0,
    pagos: [],            // historial de pagos parciales
    createdFromPresupuesto: id,
    createdAt: new Date().toISOString(),
  }
  const notaContent = `Nota de Venta ${folio} — ${cliente} — ${_cotFmt(m.total || 0, m.moneda)}`
  const notaNode = {
    id: crypto.randomUUID(),
    content: notaContent, type: 'cot_nota', metadata: notaMeta,
    created_at: new Date().toISOString(),
  }
  allNodes.push(notaNode)
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').insert([{ id: notaNode.id, owner_id: currentUser?.id, content: notaContent, type: 'cot_nota', metadata: notaMeta }])
  }

  // Marcar presupuesto como convertido/cerrado
  src.metadata = { ...src.metadata, estado: 'cerrado', notaVentaId: notaNode.id }
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: src.metadata }).eq('id', id)
  }

  showToast(`🧾 Nota de Venta ${folio} creada — Registra los pagos en la pestaña Notas de Venta`)
  _cotTab = 'notas'
  renderCotizaciones()
}

// ── Registrar pago parcial en Nota de Venta ────────────────────────────────────
window.registrarPagoCot = function(notaId) {
  const nota = allNodes.find(n => n.id === notaId)
  if (!nota) return
  const m         = nota.metadata || {}
  const pagados   = (m.pagos || []).reduce((s, p) => s + (p.monto || 0), 0)
  const saldo     = Math.max(0, (m.total || 0) - pagados)
  const panelId   = `pago-panel-${notaId.slice(0, 8)}`
  const panel     = document.getElementById(panelId)
  if (!panel) return

  // Toggle
  if (panel.style.display !== 'none') { panel.style.display = 'none'; return }
  panel.style.display = ''

  const mon = m.moneda || 'MXN'
  panel.innerHTML = `
    <div style="padding:14px;border-top:1px solid rgba(255,255,255,0.07);">
      <div style="font-size:11px;font-weight:700;color:#4ade80;margin-bottom:10px;">💰 Registrar Pago</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:8px;">
        <div>
          <label style="font-size:10px;color:#6b7280;display:block;margin-bottom:3px;">Monto *</label>
          <input type="number" id="pago-monto-${notaId.slice(0,8)}" class="modal-input" style="font-size:12px;"
            placeholder="${saldo.toFixed(2)}" min="0.01" step="0.01" max="${saldo}"/>
        </div>
        <div>
          <label style="font-size:10px;color:#6b7280;display:block;margin-bottom:3px;">Moneda</label>
          <select id="pago-mon-${notaId.slice(0,8)}" class="modal-input" style="font-size:12px;">
            <option value="MXN" ${mon==='MXN'?'selected':''}>MXN</option>
            <option value="USD" ${mon==='USD'?'selected':''}>USD</option>
            <option value="USDT" ${mon==='USDT'?'selected':''}>USDT</option>
          </select>
        </div>
        <div>
          <label style="font-size:10px;color:#6b7280;display:block;margin-bottom:3px;">Fecha</label>
          <input type="date" id="pago-fecha-${notaId.slice(0,8)}" class="modal-input" style="font-size:12px;"
            value="${new Date().toISOString().slice(0,10)}"/>
        </div>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px;">
        <div>
          <label style="font-size:10px;color:#6b7280;display:block;margin-bottom:3px;">Método</label>
          <select id="pago-met-${notaId.slice(0,8)}" class="modal-input" style="font-size:12px;">
            ${['SPEI','Transferencia','Efectivo','Cripto','Otro'].map(x => `<option value="${x}">${x}</option>`).join('')}
          </select>
        </div>
        <div>
          <label style="font-size:10px;color:#6b7280;display:block;margin-bottom:3px;">Referencia / Folio</label>
          <input type="text" id="pago-ref-${notaId.slice(0,8)}" class="modal-input" style="font-size:12px;" placeholder="Opcional"/>
        </div>
      </div>
      <div style="display:flex;gap:8px;">
        <button onclick="saveRegistroPago('${notaId}')"
          style="flex:1;padding:9px;border-radius:9px;border:1px solid rgba(74,222,128,0.4);background:rgba(74,222,128,0.12);color:#4ade80;cursor:pointer;font-size:12px;font-weight:700;">
          ✅ Confirmar pago
        </button>
        <button onclick="document.getElementById('${panelId}').style.display='none'"
          style="padding:9px 16px;border-radius:9px;border:1px solid rgba(255,255,255,0.1);background:transparent;color:#6b7280;cursor:pointer;font-size:12px;">
          Cancelar
        </button>
      </div>
    </div>`
}

window.saveRegistroPago = async function(notaId) {
  const nota = allNodes.find(n => n.id === notaId)
  if (!nota) return
  const m    = nota.metadata || {}
  const sfx  = notaId.slice(0, 8)
  const monto  = parseFloat(document.getElementById(`pago-monto-${sfx}`)?.value || '0')
  const moneda = document.getElementById(`pago-mon-${sfx}`)?.value   || 'MXN'
  const fecha  = document.getElementById(`pago-fecha-${sfx}`)?.value || new Date().toISOString().slice(0,10)
  const metodo = document.getElementById(`pago-met-${sfx}`)?.value   || 'Transferencia'
  const ref    = document.getElementById(`pago-ref-${sfx}`)?.value?.trim() || ''

  if (!monto || monto <= 0) { showToast('⚠️ Ingresa un monto válido'); return }

  // Crear income movimiento
  const movContent = `${m.titulo || m.folio} — ${m.clienteName || 'Sin cliente'} — Pago ${ref || fecha}`
  const movMeta    = {
    amount: monto, moneda, type: 'income', date: fecha,
    description: movContent,
    cotizacion_ref: notaId, folio_ref: m.folio,
    cliente: m.clienteName || '', metodo, referencia: ref,
    source: 'nota_venta', autoGenerado: true,
  }
  const movId = 'mv_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6)
  const movNode = { id: movId, content: movContent, type: 'income', metadata: movMeta, created_at: new Date().toISOString() }
  allNodes.push(movNode)
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').insert([{ id: movId, owner_id: currentUser?.id, content: movContent, type: 'income', metadata: movMeta }])
  }

  // Actualizar nota con el nuevo pago
  const pagos   = [...(m.pagos || []), { id: movId, monto, moneda, fecha, metodo, referencia: ref }]
  const pagado  = pagos.reduce((s, p) => s + (p.monto || 0), 0)
  const nuevoEstado = pagado >= (m.total || 0) - 0.01 ? 'pagado' : 'pendiente'
  nota.metadata = { ...m, pagos, estado: nuevoEstado }
  if (typeof supabase !== 'undefined' && localStorage.getItem('nexus_admin_bypass') !== 'true') {
    await supabase.from('nodes').update({ metadata: nota.metadata }).eq('id', notaId)
  }

  showToast(`✅ Pago de ${_cotFmt(monto, moneda)} registrado · Movimiento de ingreso creado`)
  renderCotizaciones()
}

// ── Generar Movimiento desde Nota de Venta (legado — para notas sin pagos) ────
window.generarMovimientoCot = async function(id) {
  const src = allNodes.find(n => n.id === id)
  if (!src) { showToast('Nota no encontrada'); return }
  const m = src.metadata || {}
  if (!m.total) { showToast('⚠️ La nota no tiene total'); return }
  // Redirigir al flujo de pagos parciales
  window.registrarPagoCot(id)
}

